-- Poems batch 412
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-922','渔家傲','周紫芝','宋','宋词','song-ci','渔家傲','[]','月黑波翻江浩渺。',72,'宋词/ci.song.5000.json','["月黑波翻江浩渺。", "扁舟系缆垂杨杪。", "渔网横江灯火闹。", "红影照。", "分明赤壁回惊棹。", "风静云收天似扫。", "梦疑身在三山岛。", "浮世功名何日了。", "从醉倒。", "柁楼红日千岩晓。"]'),
('song-ci-923','渔家傲','周紫芝','宋','宋词','song-ci','渔家傲','[]','休惜骑鲸人已远。',72,'宋词/ci.song.5000.json','["休惜骑鲸人已远。", "风流都被仍云占。", "腰下锦绦缠宝剑。", "光闪焰。", "人间莫作牛刀看。", "见说河阳花满县。", "相邀更约疏狂伴。", "幸有小蛮开小燕。", "须少款。", "玉堂此去知非晚。"]'),
('song-ci-924','渔家傲','周紫芝','宋','宋词','song-ci','渔家傲','[]','路入云岩山窈窕。',72,'宋词/ci.song.5000.json','["路入云岩山窈窕。", "岩花滴露花头小。", "香共西风吹得到。", "秋欲杪。", "天还未放秋容老。", "谁道水南花不好。", "犹胜金蕊浑如扫。", "留取光阴重一笑。", "须是早。", "黄花更惜重阳帽。"]'),
('song-ci-925','渔家傲','周紫芝','宋','宋词','song-ci','渔家傲','[]','月黑天寒花欲睡。',72,'宋词/ci.song.5000.json','["月黑天寒花欲睡。", "移灯影落清尊里。", "唤醒妖红明晚翠。", "如有意。", "嫣然一笑知谁会。", "露湿柔柯红压地。", "羞容似替人垂泪。", "著意西风吹不起。", "空绕砌。", "明年花共谁同醉。"]'),
('song-ci-926','南柯子・南歌子','周紫芝','宋','宋词','song-ci','南柯子・南歌子','["\u897f\u6e56"]','蝉薄轻梳鬓，螺香浅画眉。',62,'宋词/ci.song.5000.json','["蝉薄轻梳鬓，螺香浅画眉。", "西湖人道似西施。", "人似西施浓淡、更相宜。", "画烛催歌板，飞花上舞衣。", "殷勤犹劝玉东西。", "不道使君肠断、已多时。"]'),
('song-ci-927','南柯子・南歌子','周紫芝','宋','宋词','song-ci','南柯子・南歌子','[]','雾帐兰衾暖，薰炉宝篆浓。',62,'宋词/ci.song.5000.json','["雾帐兰衾暖，薰炉宝篆浓。", "眼波犹带睡朦胧。", "卧听晓来双燕、语春风。", "螺浅欢馀黛，霞销枕处红。", "断云飞雨怕匆匆。", "欲去且留情绪、两冲冲。"]'),
('song-ci-928','南柯子・南歌子','周紫芝','宋','宋词','song-ci','南柯子・南歌子','[]','白羽传觞急，金鞍跃马迟。',62,'宋词/ci.song.5000.json','["白羽传觞急，金鞍跃马迟。", "云间彩凤看双飞。", "飞上碧梧枝上、稳双栖。", "林下风流女，堂东坦腹儿。", "此郎标韵世间稀。", "好为伯鸾举案、又齐眉。"]'),
('song-ci-929','朝中措','周紫芝','宋','宋词','song-ci','朝中措','["\u897f\u6e56"]','西湖烟尽水溶溶。',57,'宋词/ci.song.5000.json','["西湖烟尽水溶溶。", "一笑与谁同。", "多谢湖边霜菊，伴人三见秋风。", "两高南北，天教看尽，吴越西东。", "趁取老来犹健，登临莫放杯空。"]'),
('song-ci-930','朝中措','周紫芝','宋','宋词','song-ci','朝中措','[]','大江流处是庐峰。',57,'宋词/ci.song.5000.json','["大江流处是庐峰。", "苍玉照晴空。", "何事浅鬟浓黛，却成烟雨溟濛。", "如今纵有，云涛万顷，翠巘千重。", "传语云间五老，一尊须要君同。"]'),
('song-ci-931','朝中措','周紫芝','宋','宋词','song-ci','朝中措','[]','雨馀庭院冷萧萧。',57,'宋词/ci.song.5000.json','["雨馀庭院冷萧萧。", "帘幕度微飙。", "鸟语唤回残梦，春寒勒住花梢。", "无憀睡起，新愁黯黯，归路迢迢。", "又是夕阳时候，一炉沈水烟销。"]'),
('song-ci-932','朝中措','周紫芝','宋','宋词','song-ci','朝中措','[]','小桃花动著枝浓。',57,'宋词/ci.song.5000.json','["小桃花动著枝浓。", "移得伴衰翁。", "多谢天公怜我，一时染就轻红。", "春光犹在，花枝未老，莫放尊空。", "休倚半岩烟树，能消几度东风。"]'),
('song-ci-933','朝中措','周紫芝','宋','宋词','song-ci','朝中措','[]','黄昏楼阁乱栖鸦。',57,'宋词/ci.song.5000.json','["黄昏楼阁乱栖鸦。", "天末淡微霞。", "风里一池杨柳，月边满树梨花。", "阳台路远，鱼沈尺素，人在天涯。", "想得小窗遥夜，哀弦拨断琵琶。"]'),
('song-ci-934','虞美人','周紫芝','宋','宋词','song-ci','虞美人','[]','短墙梅粉香初透。',66,'宋词/ci.song.5000.json','["短墙梅粉香初透。", "削约寒枝瘦。", "恼人知为阿谁开。", "还伴冷烟疏雨、做愁媒。", "飘零苦恨春情薄。", "不管花开落。", "小池疏影弄寒沙。", "何似玉台鸾镜、对横斜。"]'),
('song-ci-935','虞美人','周紫芝','宋','宋词','song-ci','虞美人','[]','西园摘处香和露。',66,'宋词/ci.song.5000.json','["西园摘处香和露。", "洗尽南轩暑。", "莫嫌坐上适来蝇。", "只恐怕寒、难近玉壶冰。", "井花浮翠金盆小。", "午梦初回后。", "诗翁自是不归来。", "不是青门、无地可移栽。"]'),
('song-ci-936','虞美人','周紫芝','宋','宋词','song-ci','虞美人','[]','痴云压地风尘卷。',66,'宋词/ci.song.5000.json','["痴云压地风尘卷。", "雪共春寒浅。", "山城寒夜不烧灯。", "时见竹篱茅舍、两三星。", "九衢风里香尘拥。", "十载鳌山梦。", "如今独自倚冰檐。", "落尽短檠红灺、不成眠。"]'),
('song-ci-937','江城子','周紫芝','宋','宋词','song-ci','江城子','[]','夕阳低尽柳如烟。',86,'宋词/ci.song.5000.json','["夕阳低尽柳如烟。", "淡平川。", "断肠天。", "今夜十分，霜月更娟娟。", "怎得人如天上月，虽暂缺，有时圆。", "断云飞雨又经年。", "思凄然。", "泪涓涓。", "且做如今，要见也无缘。", "因甚江头来处雁，飞不到，小楼边。"]'),
('song-ci-938','江城子','周紫芝','宋','宋词','song-ci','江城子','[]','碧梧和露滴清秋。',86,'宋词/ci.song.5000.json','["碧梧和露滴清秋。", "小庭幽。", "翠烟流。", "羞带一襟，明月上危楼。", "苦恨秋江风与月，偏管断，这些愁。", "此情空道两绸缪。", "信悠悠。", "几时休。", "到得如今，剗地见无由。", "拟待不能思想得，无限事，在心头。"]'),
('song-ci-939','潇湘夜雨・满庭芳','周紫芝','宋','宋词','song-ci','潇湘夜雨・满庭芳','[]','楼上寒深，江边雪满，楚台烟霭空濛。',118,'宋词/ci.song.5000.json','["楼上寒深，江边雪满，楚台烟霭空濛。", "一天飞絮，零乱点孤篷。", "似我华颠雪领，浑无定、漂泊孤踪。", "空凄黯，江天又晚，风袖倚蒙茸。", "吾庐，犹记得，波横素练，玉做寒峰。", "更短坡烟竹，声碎玲珑。", "拟问山阴旧路，家何在、水远山重。", "渔蓑冷，扁舟梦断，灯暗小窗中。"]'),
('song-ci-940','潇湘夜雨・满庭芳','周紫芝','宋','宋词','song-ci','潇湘夜雨・满庭芳','[]','晓色凝暾，霜痕犹浅，九天春意将回。',118,'宋词/ci.song.5000.json','["晓色凝暾，霜痕犹浅，九天春意将回。", "隔年花信，先已到江梅。", "沈水烟浓如雾，金波满、红袖双垂。", "仙翁醉，问春何处，春在玉东西。", "瑶台。", "人不老，还从东壁，来步天墀。", "且细看八砖，花影迟迟。", "会见朱颜绿鬓，家长近、咫尺天威。", "君知否，天教雨露，常满岁寒枝。"]'),
('song-ci-941','潇湘夜雨・满庭芳','周紫芝','宋','宋词','song-ci','潇湘夜雨・满庭芳','[]','江绕淮城，云昏楚观，一枝烟笛谁横。',118,'宋词/ci.song.5000.json','["江绕淮城，云昏楚观，一枝烟笛谁横。", "晓风吹帽，霜日照人明。", "暗恼潘郎旧恨，应追念、菊老残英。", "秋空晚，茱萸细拈，醽醁为谁倾。", "人间，真梦境，新愁未了，绿鬓星星。", "问明年此会，谁寄幽情。", "倚尽一楼残照，何妨更、月到帘旌。", "凭阑久，歌君妙曲，谁是米嘉荣。"]'),
('song-ci-942','潇湘夜雨・满庭芳','周紫芝','宋','宋词','song-ci','潇湘夜雨・满庭芳','[]','楚尾江横，斗南山秀，辋川谁画新图。',118,'宋词/ci.song.5000.json','["楚尾江横，斗南山秀，辋川谁画新图。", "几时天际，平地出方壶。", "应念江南倦客，家何在、飘泊江湖。", "天教共，银涛翠壁，相伴老人娱。", "长淮，看不尽，风帆落处，天在平芜。", "算人间此地，岂是穷途。", "好与婆娑尽日，应须待、月到金枢。", "山中饮，从教笑我，白首醉模糊。"]'),
('song-ci-943','宴桃源・如梦令','周紫芝','宋','宋词','song-ci','宴桃源・如梦令','[]','帘幕疏疏风透。',40,'宋词/ci.song.5000.json','["帘幕疏疏风透。", "庭下月寒花瘦。", "宽尽沈郎衣，方寸不禁僝僽。", "难受。", "难受。", "灯暗月斜时候。"]'),
('song-ci-944','宴桃源・如梦令','周紫芝','宋','宋词','song-ci','宴桃源・如梦令','[]','林外野塘烟腻。',40,'宋词/ci.song.5000.json','["林外野塘烟腻。", "衣上落梅香细。", "瘦马步凌兢，人在乱山丛里。", "憔悴。", "憔悴。", "回望小楼千里。"]'),
('song-ci-945','宴桃源・如梦令','周紫芝','宋','宋词','song-ci','宴桃源・如梦令','[]','绿尽小池芳草。',40,'宋词/ci.song.5000.json','["绿尽小池芳草。", "门外柳垂春昼。", "花上雨廉纤，帘幕燕来时候。", "消瘦。", "消瘦。", "依约粉香襟袖。"]'),
('song-ci-946','宴桃源・如梦令','周紫芝','宋','宋词','song-ci','宴桃源・如梦令','[]','旧日荼䕷时候。',40,'宋词/ci.song.5000.json','["旧日荼䕷时候。", "酒涴粉香襟袖。", "老去惜春心，试问孙郎知否。", "花瘦。", "花瘦。", "剪取一枝重嗅。"]'),
('song-ci-947','满江红','周紫芝','宋','宋词','song-ci','满江红','[]','寂寂江天，雪又满、晚来风急。',115,'宋词/ci.song.5000.json','["寂寂江天，雪又满、晚来风急。", "空懊恨、散盐飞絮，未成轻集。", "万里长空飞不到，珠帘卷尽还羞入。", "问向晚、谁欲画渔莎，寒江立。", "天黯淡，催残日。", "波浩渺，添寒力。", "又何如聊遣，舞衣红湿。", "好与月娥临晚砌，莫教先放梅花拆。", "便准拟、一醉广寒宫，千山白。"]'),
('song-ci-948','定风波令・定风波','周紫芝','宋','宋词','song-ci','定风波令・定风波','[]','梅粉梢头雨未乾。',54,'宋词/ci.song.5000.json','["梅粉梢头雨未乾。", "淡烟疏日带春寒。", "暝鸦啼处，人在小楼边。", "芳草只随春恨长，塞鸿空傍碧云还。", "断霞销尽，新月又婵娟。"]'),
('song-ci-949','蝶恋花','周紫芝','宋','宋词','song-ci','蝶恋花','[]','天意才晴风又雨。',70,'宋词/ci.song.5000.json','["天意才晴风又雨。", "催得风前，日日吹轻絮。", "燕子不飞莺不语。", "满庭芳草空无数。", "春去可堪人去也。", "枝上残红，不忍抬头觑。", "假使留春春肯住。", "唤谁相伴春同处。"]'),
('song-ci-950','永遇乐','周紫芝','宋','宋词','song-ci','永遇乐','[]','槐幄如云，燕泥犹湿，雨馀清暑。',128,'宋词/ci.song.5000.json','["槐幄如云，燕泥犹湿，雨馀清暑。", "细草摇风，小荷擎雨，时节还端午。", "碧罗窗底，依稀记得，闲系翠丝烟缕。", "到如今、前欢如梦，还对彩绦无语。", "榴花半吐，金刀犹在，往事更堪重数。", "艾虎钗头，菖蒲酒里，旧约浑无据。", "轻衫如雾，玉肌似削，人在画楼深处。", "想灵符、无人共带，翠眉暗聚。"]'),
('song-ci-951','蓦山溪','周紫芝','宋','宋词','song-ci','蓦山溪','[]','月眉星眼，阆苑真仙侣。',102,'宋词/ci.song.5000.json','["月眉星眼，阆苑真仙侣。", "娇小正笄年，每当筵、愁歌怕舞。", "水亭烟树，春去已无踪，桃源路。", "知何处。", "往事如风絮。", "如今闻道，误剪香云缕，闲系小乌纱，更无心、浅匀深注。", "三山路杳，终不是人间，知谁与。", "吹箫女。", "共驾青鸾去。"]'),
('song-ci-952','品令','周紫芝','宋','宋词','song-ci','品令','[]','西风持酒。',80,'宋词/ci.song.5000.json','["西风持酒。", "诮不做、愁时候。", "机云兄弟，坐中玉树，琼枝高秀。", "且莫劝人归去，坐来未久。", "甘泉书奏。", "报幽障、沈烽后。", "明朝重九，茱萸休恼，泪沾襟袖。", "怕衰黄花，也解笑人白首。"]'),
('song-ci-953','品令','周紫芝','宋','宋词','song-ci','品令','[]','霜蓬零乱。',80,'宋词/ci.song.5000.json','["霜蓬零乱。", "笑绿鬓、光阴晚。", "紫茱时节，小楼长醉，一川平远。", "休说龙山佳会，此情不浅。", "黄花香满。", "记白苎、吴歌软。", "如今却向，乱山丛里，一枝重看。", "对著西风搔首，为谁肠断。"]'),
('song-ci-954','清平乐','周紫芝','宋','宋词','song-ci','清平乐','[]','芦州晚净。',54,'宋词/ci.song.5000.json','["芦州晚净。", "雨罢江如镜。", "属玉双飞栖不定。", "数点晚来烟艇。", "梦回满眼凄凉。", "一成无奈思量。", "舟在绿杨堤下，蝉嘶欲尽斜阳。"]'),
('song-ci-955','清平乐','周紫芝','宋','宋词','song-ci','清平乐','[]','烟鬟敛翠。',54,'宋词/ci.song.5000.json','["烟鬟敛翠。", "柳下门初闭。", "门外一川风细细。", "沙上暝禽飞起。", "今宵水畔楼边。", "风光宛似当年。", "月到旧时明处，共谁同倚阑干。"]'),
('song-ci-956','清平乐','周紫芝','宋','宋词','song-ci','清平乐','[]','青春欲暮。',54,'宋词/ci.song.5000.json','["青春欲暮。", "柳下将飞絮。", "月到阶前梅子树。", "啼得杜鹃飞去。", "人归不掩朱门。", "一成过了黄昏。", "只有琐窗红蜡，照人犹自销魂。"]'),
('song-ci-957','清平乐','周紫芝','宋','宋词','song-ci','清平乐','[]','团栾小树。',54,'宋词/ci.song.5000.json','["团栾小树。", "天与香无数。", "薄艳不尽风日苦。", "剩著红油遮护。", "移栽未到江南。", "香山鼻观先参。", "勾引老情偏醉，锦薰笼暖春酣。"]'),
('song-ci-958','清平乐','周紫芝','宋','宋词','song-ci','清平乐','[]','浅妆匀靓。',54,'宋词/ci.song.5000.json','["浅妆匀靓。", "一点闲心性。", "脸上羞红凝不定。", "恼乱酒愁花病。", "晚来泪搵残霞。", "坠鬟小玉钗斜。", "细雨一帘春恨，东风满地桃花。"]'),
('song-ci-959','清平乐','周紫芝','宋','宋词','song-ci','清平乐','[]','东风庭户。',54,'宋词/ci.song.5000.json','["东风庭户。", "红满桃花树。", "准拟踏青南陌路。", "双凤绣鞋新做。", "秋千月挂黄昏。", "画堂深掩朱门。", "立尽花阴归去，此时别是销魂。"]'),
('song-ci-960','浪淘沙','周紫芝','宋','宋词','song-ci','浪淘沙','[]','江上送年归。',64,'宋词/ci.song.5000.json','["江上送年归。", "还似年时。", "屠苏休恨到君迟。", "觅得醉乡无事处，莫放愁知。", "红灺一灯垂。", "应笑人衰。", "鹤长凫短怨他谁。", "明日江楼春到也，且醉南枝。"]'),
('song-ci-961','浪淘沙','周紫芝','宋','宋词','song-ci','浪淘沙','[]','落日在阑干。',64,'宋词/ci.song.5000.json','["落日在阑干。", "风满晴川。", "坐来高浪拥银山。", "白鹭欲栖飞不下，却入苍烟。", "千里水云寒。", "正绕烟鬟。", "拍浮须要酒杯宽。", "天与吾曹供一醉，不是人间。"]'),
('song-ci-962','踏莎行','周紫芝','宋','宋词','song-ci','踏莎行','[]','风翠轻翻，雾红深注。',68,'宋词/ci.song.5000.json','["风翠轻翻，雾红深注。", "鸳鸯池畔双鱼树。", "合欢凤子也多情，飞来连理枝头住。", "欲付浓愁，深凭尺素。", "戏鱼波上无寻处。", "教谁试与问花看，如何寄得香笺去。"]'),
('song-ci-963','踏莎行','周紫芝','宋','宋词','song-ci','踏莎行','[]','燕子归来，梅花又落。',68,'宋词/ci.song.5000.json','["燕子归来，梅花又落。", "缃桃雨后燕支薄。", "眼前先自许多愁，斜阳更在春池阁。", "梦里新欢，年时旧约。", "日长院静空帘幕。", "几回猛待不思量，抬头又是思量著。"]'),
('song-ci-964','踏莎行','周紫芝','宋','宋词','song-ci','踏莎行','[]','鹊报寒枝，鱼传尺素。',68,'宋词/ci.song.5000.json','["鹊报寒枝，鱼传尺素。", "晴香暗与风微度。", "故人还寄陇头梅，凭谁为作梅花赋。", "柳外朱桥，竹边深坞。", "何时却向君家去。", "便须倩月与徘徊，无人留得花常住。"]'),
('song-ci-965','踏莎行','周紫芝','宋','宋词','song-ci','踏莎行','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','情似游丝，人如飞絮。',68,'宋词/ci.song.5000.json','["情似游丝，人如飞絮。", "泪珠阁定空相觑。", "一溪烟柳万丝垂，无因系得兰舟住。", "雁过斜阳，草迷烟渚。", "如今已是愁无数。", "明朝且做莫思量，如何过得今宵去。"]'),
('song-ci-966','雨中花令','周紫芝','宋','宋词','song-ci','雨中花令','[]','山雨细、泉生幽谷，水满平田。',86,'宋词/ci.song.5000.json','["山雨细、泉生幽谷，水满平田。", "雪茧红蚕熟后，黄云陇麦秋间。", "武陵烟暖，数声鸡犬，别是山川。", "嗟老去、倦游踪迹，长恨华颠。", "行尽吴头楚尾，空惭万壑千岩。", "不如休也，一庵归去，依旧云山。"]'),
('song-ci-967','点绛唇','周紫芝','宋','宋词','song-ci','点绛唇','[]','燕子风高，小桃枝上花无数。',50,'宋词/ci.song.5000.json','["燕子风高，小桃枝上花无数。", "乱溪深处。", "满地飞红雨。", "唤得春来，又送春归去。", "浑无绪。", "刘郎前度。", "空记来时路。"]'),
('song-ci-968','点绛唇','周紫芝','宋','宋词','song-ci','点绛唇','[]','人道长生，算来世上何曾有。',50,'宋词/ci.song.5000.json','["人道长生，算来世上何曾有。", "玉尊长倒。", "早是人间少。", "四十年来，历尽闲烦恼。", "如今老。", "大家开口。", "赢得花前笑。"]'),
('song-ci-969','临江仙','周紫芝','宋','宋词','song-ci','临江仙','[]','水远山长何处去，欲行人似孤云。',70,'宋词/ci.song.5000.json','["水远山长何处去，欲行人似孤云。", "十分瘦损沈休文。", "忍将秋水镜，容易与君分。", "试问梨花枝上雨，为谁弹满清尊。", "一江风月黯离魂。", "平波催短棹，小立送黄昏。"]'),
('song-ci-970','临江仙','周紫芝','宋','宋词','song-ci','临江仙','[]','记得武陵相见日，六年往事堪惊。',70,'宋词/ci.song.5000.json','["记得武陵相见日，六年往事堪惊。", "回头双鬓已星星。", "谁知江上酒，还与故人倾。", "铁马红旗寒日暮，使君犹寄边城。", "只愁飞诏下青冥。", "不应霜塞晚，横槊看诗成。"]'),
('song-ci-971','好事近','周紫芝','宋','宋词','song-ci','好事近','[]','江路绕青山，山翠扑衣轻湿。',53,'宋词/ci.song.5000.json','["江路绕青山，山翠扑衣轻湿。", "谁酿晚来云意，做一天愁色。", "竹溪斜度尽篮舆，疏梅暗香入。", "何处最关心事，恨落梅风急。"]'),
('song-ci-972','好事近','周紫芝','宋','宋词','song-ci','好事近','[]','香蜡染宫黄，不属世间风月。',53,'宋词/ci.song.5000.json','["香蜡染宫黄，不属世间风月。", "分我照寒金蕊，伴小窗愁绝。", "高标独步本无双，一枝为谁折。", "压尽半春桃李，任满山如雪。"]'),
('song-ci-973','好事近','周紫芝','宋','宋词','song-ci','好事近','[]','帘外一声歌，倾尽满城风月。',53,'宋词/ci.song.5000.json','["帘外一声歌，倾尽满城风月。", "看到酒阑羞处，想多情难说。", "周郎元是个中人，如今鬓如雪。", "自恨老来肠肚，诮不堪摧折。"]'),
('song-ci-974','好事近','周紫芝','宋','宋词','song-ci','好事近','[]','雨后欲斜阳，红满井梧风叶。',53,'宋词/ci.song.5000.json','["雨后欲斜阳，红满井梧风叶。", "还是夜来时候，共小轩明月。", "不关纤手与调冰，消除这些热。", "自是月娥肌骨，似玉壶香雪。"]'),
('song-ci-975','好事近','周紫芝','宋','宋词','song-ci','好事近','[]','春似酒杯浓，醉得海棠无力。',53,'宋词/ci.song.5000.json','["春似酒杯浓，醉得海棠无力。", "谁染玉肌丰脸，做燕支颜色。", "送春风雨最无情，吹残也堪惜。", "何似且留花住，唤小鬟催拍。"]'),
('song-ci-976','好事近','周紫芝','宋','宋词','song-ci','好事近','[]','秋意总关愁，那更与君轻别。',53,'宋词/ci.song.5000.json','["秋意总关愁，那更与君轻别。", "从此共谁同醉，恨老来风月。", "遥知手板笑看云，江边醉时节，应为老人回首，记白头如雪。"]'),
('song-ci-977','酹江月・念奴娇','周紫芝','宋','宋词','song-ci','酹江月・念奴娇','[]','冰轮飞上，正金波翻动，玉壶新绿。',120,'宋词/ci.song.5000.json','["冰轮飞上，正金波翻动，玉壶新绿。", "风帽还猗清露滴，凛凛微生寒粟。", "白玉楼高，水精帘卷，十里堆琼屋。", "千山人静，怒龙声喷蕲竹。", "夜久斗落天高，银河还对泻，冷悬双瀑。", "此地人间何处有，难买明珠千斛。", "弄影人归，锦袍何在，更谁知鸿鹄。", "素光如练，满天空挂寒玉。"]'),
('song-ci-978','酹江月・念奴娇','周紫芝','宋','宋词','song-ci','酹江月・念奴娇','[]','楚山无尽，看西来新拥，石城双旆。',120,'宋词/ci.song.5000.json','["楚山无尽，看西来新拥，石城双旆。", "立马花边金镫暖，遥想元戎小队。", "白雪歌成，莫愁去后，往事空千载。", "一时吟啸，风流不减前辈。", "闻道梦泽南州，日高初睡足，雅宜高会。", "老去愁多谁念我，空对云山苍翠。", "南雁归时，白头应记得，尊前倾盖。", "送君南浦，无情空恨江水。"]'),
('song-ci-979','感皇恩','周紫芝','宋','宋词','song-ci','感皇恩','[]','残月挂征鞍，路长山绕。',81,'宋词/ci.song.5000.json','["残月挂征鞍，路长山绕。", "独拥寒貂犯霜晓。", "水边林下，孤负此生多少。", "星星空满鬓，因谁有。", "不如办个，短蓑长钓。", "唤取轻鸥伴人老。", "思量也胜，看人眉头眼脑。", "世间浑是梦，何时了。"]'),
('song-ci-980','感皇恩','周紫芝','宋','宋词','song-ci','感皇恩','[]','玉箸点椒花，年华又杪。',81,'宋词/ci.song.5000.json','["玉箸点椒花，年华又杪。", "绛蜡烧残暗催晓。", "小窗醒处，梦断月斜江悄。", "故山春欲动，归程杳。", "天意不放，人生长少。", "富贵应须致身早。", "此宵长愿，赢取一尊娱老。", "假饶真百岁，能多少。"]'),
('song-ci-981','感皇恩','周紫芝','宋','宋词','song-ci','感皇恩','[]','无事小神仙，世人谁会。',82,'宋词/ci.song.5000.json','["无事小神仙，世人谁会。", "著甚来由自萦系。", "人生须是，做些闲中活计。", "百年能几许，无多子。", "近日谢天，与片闲田地。", "作个茅堂待打睡。", "酒儿熟也，赢取山中一醉。", "人间如意事，只此是。"]'),
('song-ci-982','感皇恩','周紫芝','宋','宋词','song-ci','感皇恩','[]','江上一山横，偶来同住。',81,'宋词/ci.song.5000.json','["江上一山横，偶来同住。", "山北山南共来去。", "今朝何事，目送征鸿轻举。", "可堪吹不断，梨花雨。", "千里莫厌，重霄云路。", "飞下彤庭伴鹓鹭。", "紫骝乌帽，看尽章台风絮。", "故人应问我，今何处。"]'),
('song-ci-983','感皇恩','周紫芝','宋','宋词','song-ci','感皇恩','[]','何处是云庵，本来无住。',81,'宋词/ci.song.5000.json','["何处是云庵，本来无住。", "云共谁来共谁去。", "菊篱杯酒，聊为渊明频举。", "幅巾应屡湿，斜川雨。", "此去常恨，相从无路。", "记取孤飞水边鹭。", "重来一笑，又是柳飞残絮。", "梦魂飞不到，君闲处。"]'),
('song-ci-984','洞仙歌','周紫芝','宋','宋词','song-ci','洞仙歌','[]','江梅吹尽，更幽兰香度。',103,'宋词/ci.song.5000.json','["江梅吹尽，更幽兰香度。", "可惜浓春为谁住。", "最嫌他、无数轻薄桃花，推不去，偏守定、东风一处。", "病来应怕酒，□眼常醒，老去羞春似无语。", "准拟强追随，管领风光，人生只、欢期难预。", "纵留得、梨花做寒食，怎吃他朝来，这般风雨。"]'),
('song-ci-985','贺新郎','周紫芝','宋','宋词','song-ci','贺新郎','["\u5e90\u5c71"]','白首归何晚。',141,'宋词/ci.song.5000.json','["白首归何晚。", "笑一椽、天教负与，楚江南岸。", "门外春山晚无数，只有匡庐似染。", "但想像、红妆不见。", "谁念香山当日事，漫青衫、泪湿人谁管。", "歌旧曲，空凄怨。", "将军未老身归汉。", "算功名、过了唯有，古词尘满。", "谁似渊明拚得老，饱看云山万点。", "况此老、斜川不远。", "终待我他年自，剪黄花、一酹重阳盏。", "君为我，休辞劝。"]'),
('song-ci-986','苏幕遮','周紫芝','宋','宋词','song-ci','苏幕遮','[]','水傍边，山尽处。',76,'宋词/ci.song.5000.json','["水傍边，山尽处。", "唤取云来，共我山头住。", "分得一江风共雨。", "满院芙蓉，更听红妆舞。", "趁霜晴，闲独步。", "那里烟村，有个梅花树。", "小径斜穿来又去。", "醉后知他，有甚青云路。"]'),
('song-ci-987','苏幕遮','周紫芝','宋','宋词','song-ci','苏幕遮','["\u5e90\u5c71"]','老相邀，山作伴。',76,'宋词/ci.song.5000.json','["老相邀，山作伴。", "千里西来，始识庐山面。", "爱酒扬雄浑不管。", "天与邻翁，来慰穷愁眼。", "似惊鸿，吹又散。", "画柯横江，望断江南岸。", "地角天涯无尽远。", "一阕清歌，且放梨花满。"]'),
('song-ci-988','一剪梅・一翦梅','周紫芝','宋','宋词','song-ci','一剪梅・一翦梅','["\u957f\u6c5f"]','无限江山无限愁。',72,'宋词/ci.song.5000.json','["无限江山无限愁。", "两岸斜阳，人上扁舟。", "阑干吹浪不多时，酒在离尊，情满沧洲。", "早是霜华两鬓秋。", "目送飞鸿，那更难留。", "问君尺素几时来，莫道长江，不解西流。"]'),
('song-ci-989','千秋岁','周紫芝','宋','宋词','song-ci','千秋岁','[]','小春时候。',87,'宋词/ci.song.5000.json','["小春时候。", "晴日吴山秀。", "霜尚浅，梅先透。", "波翻醽醁盏，雾暖芙蓉绣。", "持寿酒。", "仙娥特地回双袖。", "试问春多少。", "恩入芝兰厚。", "松不老，山长久。", "星占南极远，家是椒房旧。", "君一笑。", "金鸾看取人归后。"]'),
('song-ci-990','千秋岁','周紫芝','宋','宋词','song-ci','千秋岁','[]','当年文焰。',87,'宋词/ci.song.5000.json','["当年文焰。", "蜀锦词华烂。", "年正少，声初远。", "手攀天上桂，书奏蓬莱殿。", "人尽道，洛阳盛事今重见。", "千尺青苍干。", "直节凌霄汉。", "天未识，应嗟晚。", "饮残长寿盏，归奉春皇燕。", "金叶满。", "擗麟且受麻姑劝。"]'),
('song-ci-991','千秋岁','周紫芝','宋','宋词','song-ci','千秋岁','[]','送春归去。',87,'宋词/ci.song.5000.json','["送春归去。", "说与愁无数。", "君去后，归何处。", "人应空懊恼，春亦无言语。", "寒日暮，腾腾醉梦随风絮。", "尽日间庭雨。", "红湿秋千柱。", "人恨切，莺声苦。", "拟倾浇闷酒，留取残红树。", "春去也，不成不为愁人住。"]'),
('song-ci-992','风入松','周紫芝','宋','宋词','song-ci','风入松','[]','禁烟过后落花天。',88,'宋词/ci.song.5000.json','["禁烟过后落花天。", "无奈轻寒。", "东风不管春归去，共残红、飞上秋千。", "看尽天涯芳草，春愁堆在阑干。", "楚江横断夕阳边。", "无限青烟。", "旧时云去今何处，山无数、柳涨平川。", "与问风前回雁，甚时吹过江南。"]'),
('song-ci-993','忆王孙','周紫芝','宋','宋词','song-ci','忆王孙','[]','梅子生时春渐老。',66,'宋词/ci.song.5000.json','["梅子生时春渐老。", "红满地、落花谁扫。", "旧年池馆不归来，又绿尽、今年草。", "思量千里乡关道。", "山共水、几时得到。", "杜鹃只解怨残春，也不管、人烦恼。"]'),
('song-ci-994','减字木兰花','周紫芝','宋','宋词','song-ci','减字木兰花','[]','快风消暑。',52,'宋词/ci.song.5000.json','["快风消暑。", "门近雨边梅子树。", "昼梦腾腾。", "急雨声中唤不醒。", "轻衫短箑。", "林下日长聊散发。", "无计医贫。", "长作云山高卧人。"]'),
('song-ci-995','采桑子','周紫芝','宋','宋词','song-ci','采桑子','[]','云踪老去浑无定，飘泊寒空。',52,'宋词/ci.song.5000.json','["云踪老去浑无定，飘泊寒空。", "又被东风。", "吹过江南第几峰。", "长安市上看花眼，不到衰翁。", "好趁归鸿。", "家在西岩碧桂丛。"]'),
('song-ci-996','渔父词・渔父','周紫芝','宋','宋词','song-ci','渔父词・渔父','[]','好个神仙张志和。',32,'宋词/ci.song.5000.json','["好个神仙张志和。", "平生只是一渔蓑。", "和月醉，棹船歌。", "乐在江湖可奈何。"]'),
('song-ci-997','渔父词・渔父','周紫芝','宋','宋词','song-ci','渔父词・渔父','[]','禁中图画访玄真。',32,'宋词/ci.song.5000.json','["禁中图画访玄真。", "晚得歌词献紫宸。", "天一笑，物皆春。", "依旧扁舟钓白苹。"]'),
('song-ci-998','渔父词・渔父','周紫芝','宋','宋词','song-ci','渔父词・渔父','[]','解印归来暂结庐。',32,'宋词/ci.song.5000.json','["解印归来暂结庐。", "有时同钓水西鱼。", "闲著屐，醉骑驴。", "分明人在辋川图。"]'),
('song-ci-999','渔父词・渔父','周紫芝','宋','宋词','song-ci','渔父词・渔父','[]','趁梅寻得水边枝。',32,'宋词/ci.song.5000.json','["趁梅寻得水边枝。", "独棹渔船却过溪。", "人似玉，醉如泥。", "闲歌五色线中诗。"]'),
('song-ci-0','渔父词・渔父','周紫芝','宋','宋词','song-ci','渔父词・渔父','[]','人间何物是穷通。',32,'宋词/ci.song.6000.json','["人间何物是穷通。", "终向烟波作钓翁。", "江不动，月横空。", "漫郎船过小回中。"]'),
('song-ci-1','花心动','李弥逊','宋','宋词','song-ci','花心动','[]','水馆风亭，晚香浓、一番荷芰经雨。',127,'宋词/ci.song.6000.json','["水馆风亭，晚香浓、一番荷芰经雨。", "簟枕乍闲，襟裾初试，散尽满轩袢暑。", "断云却送轻雷去，疏林外、玉钩微吐。", "夜未阑，秋生败叶，暗催庭树。", "天上佳期久阻。", "星河畔，仙车缥缈云路。", "旧恨未平，幽欢难驻，洒落半天风露。", "绮罗人散金猊冷，醉魂到、华胥深处。", "洞户悄，南楼画角自语。"]'),
('song-ci-2','一寸金','李弥逊','宋','宋词','song-ci','一寸金','[]','仙李盘根，自有云仍霭芳裔。',133,'宋词/ci.song.6000.json','["仙李盘根，自有云仍霭芳裔。", "更留雨霜皮，临风玉树，紫髯丹颊，长生久视。", "鹤帐琅书至。", "长庚梦、当年暗记。", "佳辰近，回首西风，渐喜秋英弄霜蕊。", "暂卷双旌，鸣金吹竹，萱堂伴新戏。", "对璧月流光，屏山供翠，碧云乍合，飞觞如缀。", "早晚岩廊侍。", "终不负、黄楼一醉。", "丹青手、先与翻阶，万叶增春媚。"]'),
('song-ci-3','蝶恋花','李弥逊','宋','宋词','song-ci','蝶恋花','[]','百尺游丝当秀户。',70,'宋词/ci.song.6000.json','["百尺游丝当秀户。", "不系春晖，只系闲愁住。", "拾翠归来芳草路。", "避人蝴蝶双飞去。", "困脸羞眉无意绪。", "陌上行人，记得清明否。", "消息未来池阁暮。", "濛濛一饷梨花雨。"]'),
('song-ci-4','蝶恋花','李弥逊','宋','宋词','song-ci','蝶恋花','[]','足力穷时山已晦。',70,'宋词/ci.song.6000.json','["足力穷时山已晦。", "却上轻舟，急棹穿沙背。", "云影渐随风力退。", "一川月白寒光碎。", "唤客主人陶谢辈。", "拂石移尊，不管游人醉。", "罗绮丛中无此会。", "只疑身在烟霞外。"]'),
('song-ci-5','蝶恋花','李弥逊','宋','宋词','song-ci','蝶恋花','[]','清晓天容争显晦。',70,'宋词/ci.song.6000.json','["清晓天容争显晦。", "溪上群山，戢戢分驼背。", "谁似浮云知进退。", "疏林嫩日黄金碎。", "夜枕不眠憎鼠辈。", "困眼贪晴，拚被风烟醉。", "天意有情人不会。", "分明置我风波外。"]'),
('song-ci-6','蝶恋花','李弥逊','宋','宋词','song-ci','蝶恋花','[]','百叠青山江一缕。',70,'宋词/ci.song.6000.json','["百叠青山江一缕。", "十里人家，路绕南台去。", "榕叶满川飞白鹭。", "疏帘半卷黄昏雨。", "楼阁峥嵘天尺五。", "荷芰风清，习习消袢暑。", "老子人间无著处。", "一尊来作横山主。"]'),
('song-ci-7','蝶恋花','李弥逊','宋','宋词','song-ci','蝶恋花','[]','小小芙蕖红半展。',70,'宋词/ci.song.6000.json','["小小芙蕖红半展。", "占早争先，不奈腰肢软。", "罗袜凌波娇欲颤。", "向人如诉闺中怨。", "把酒与君成眷恋。", "约束新荷，四面低歌扇。", "不放游人偷眼盼。", "鸳鸯叶底潜窥见。"]'),
('song-ci-8','虞美人','李弥逊','宋','宋词','song-ci','虞美人','[]','上阳迟日千门锁。',66,'宋词/ci.song.6000.json','["上阳迟日千门锁。", "花外流莺过。", "一番春去又经秋。", "惟有深宫明月、照人愁。", "暗中白发随芳草。", "却恨容颜好。", "更无魂梦到昭阳。", "肠断一双飞燕、在雕粱。"]'),
('song-ci-9','虞美人','李弥逊','宋','宋词','song-ci','虞美人','[]','海棠开后春谁主。',66,'宋词/ci.song.6000.json','["海棠开后春谁主。", "日日催花雨。", "可怜新绿遍残枝。", "不见香腮和粉、晕燕脂。", "去年携手听金缕。", "正是花飞处。", "老来先自不禁愁。", "这样愁来欺老、几时休。"]'),
('song-ci-10','虞美人','李弥逊','宋','宋词','song-ci','虞美人','[]','金泥捍拨春声碎。',66,'宋词/ci.song.6000.json','["金泥捍拨春声碎。", "恨入相思泪。", "醉欺秋水绿云斜。", "浑似梦中重到、阿环家。", "主人著意留春住。", "不醉无归去。", "只愁银烛晓生寒。", "明日落花飞絮、满长安。"]'),
('song-ci-11','虞美人','李弥逊','宋','宋词','song-ci','虞美人','[]','年年江上清秋节。',66,'宋词/ci.song.6000.json','["年年江上清秋节。", "盏面分霜月。", "不堪对月已伤离。", "那更梅花开后、海棠时。", "剑溪难驻仙游路。", "直上云霄去。", "藕花恰莫碍行舟。", "要趁潮头八月、到扬州。"]'),
('song-ci-12','虞美人','李弥逊','宋','宋词','song-ci','虞美人','[]','方壶小有人谁到。',66,'宋词/ci.song.6000.json','["方壶小有人谁到。", "底事春知早。", "使君和气粲如花。", "更筑百花深处、驻春华。", "云关远枕苕溪浅。", "未放归怀展。", "看残红紫绿阴斜。", "鸾凤干霄却上、玉皇家。"]'),
('song-ci-13','青玉案','李弥逊','宋','宋词','song-ci','青玉案','[]','杨花尽做难拘管。',82,'宋词/ci.song.6000.json','["杨花尽做难拘管。", "也解趁、飞红伴。", "骢马无情人渐远。", "沙平浅渡，雨湿孤村，何处长亭晚。", "欲凭桃叶传春怨。", "算不似、斜风倩双燕。", "纵得书来春又换。", "只将心事，分付眉尖，寂寞梨花院。"]'),
('song-ci-14','菩萨蛮','李弥逊','宋','宋词','song-ci','菩萨蛮','[]','小山娇翠低歌扇。',52,'宋词/ci.song.6000.json','["小山娇翠低歌扇。", "雏莺学语春犹浅。", "无力响方檀。", "声随玉笋翻。", "垂鬟云乍染。", "媚靥香微点。", "未解作轻颦。", "凝情已动人。"]'),
('song-ci-15','菩萨蛮','李弥逊','宋','宋词','song-ci','菩萨蛮','[]','凉飙轻散馀霞绮。',52,'宋词/ci.song.6000.json','["凉飙轻散馀霞绮。", "疏星冷浸明河水。", "敧枕画檐风。", "秋生草际蛩。", "雁门离塞晚。", "不道衡阳远。", "归恨隔重山。", "楼高莫凭栏。"]'),
('song-ci-16','菩萨蛮','李弥逊','宋','宋词','song-ci','菩萨蛮','[]','风庭瑟瑟灯明灭。',52,'宋词/ci.song.6000.json','["风庭瑟瑟灯明灭。", "碧梧枝上蝉声歇。", "枕冷梦魂惊。", "一阶寒水明。", "鸟飞人未起。", "月露清如洗。", "无语听残更。", "愁从两鬓生。"]'),
('song-ci-17','菩萨蛮','李弥逊','宋','宋词','song-ci','菩萨蛮','[]','馀霞收尽寒烟绿。',52,'宋词/ci.song.6000.json','["馀霞收尽寒烟绿。", "江山一片团明玉。", "敧枕画楼风。", "愁生草际蛩。", "金茎秋未老。", "两鬓吴霜早。", "忍负广寒期。", "清尊对语谁。"]'),
('song-ci-18','浣溪沙','李弥逊','宋','宋词','song-ci','浣溪沙','[]','小小茅茨隐翠微。',48,'宋词/ci.song.6000.json','["小小茅茨隐翠微。", "桥平双手弄涟漪。", "好风还动去年枝。", "得雨疏梅肥欲展，人家次第有芳菲。", "惜花恰莫探春迟。"]'),
('song-ci-19','浣溪沙','李弥逊','宋','宋词','song-ci','浣溪沙','[]','箫鼓哀吟乐楚臣。',48,'宋词/ci.song.6000.json','["箫鼓哀吟乐楚臣。", "牙樯锦缆簇江漘。", "调高彩笔逞尖新。", "海角逢时伤老大，莫辞卮酒话情亲。", "与君同是异乡人。"]'),
('song-ci-20','浣溪沙','李弥逊','宋','宋词','song-ci','浣溪沙','[]','向日南枝不奈晴。',48,'宋词/ci.song.6000.json','["向日南枝不奈晴。", "无风绛雪自飘零。", "画楼更作断肠声。", "小侧金荷迎落蕊，高烧银烛照残英。", "生愁斜月酒初醒。"]'),
('song-ci-21','临江仙','李弥逊','宋','宋词','song-ci','临江仙','[]','枝上子规催去旆，柳条偏系离情。',70,'宋词/ci.song.6000.json','["枝上子规催去旆，柳条偏系离情。", "片云留雨锁愁城。", "不堪明月夜，寂寞照南荣。", "莫作东山今日计，风雷已促鹏程。", "功成来伴赤松行。", "却寻鸿雁侣，尊酒会如星。"]'),
('song-ci-22','临江仙','李弥逊','宋','宋词','song-ci','临江仙','[]','燕去莺来昏又晓，劳生莫负心期。',70,'宋词/ci.song.6000.json','["燕去莺来昏又晓，劳生莫负心期。", "菊花何必待开时。", "十分浮玉蚁，一拍贯珠词。", "少借笔端烟雨力，不须露染风披。", "芳心微露定因谁。", "风流今太傅，萧洒古东篱。"]'),
('song-ci-23','临江仙','李弥逊','宋','宋词','song-ci','临江仙','[]','多病渊明刚止酒，不禁秋蕊浮香。',70,'宋词/ci.song.6000.json','["多病渊明刚止酒，不禁秋蕊浮香。", "饮船歌板已兼忘。", "吴霜羞鬓改，无语对红妆。", "小拈青枝撩鼻观，绝胜娇额涂黄。", "独醒滋味怕新凉。", "归来烛影乱，敧枕听更长。"]'),
('song-ci-24','临江仙','李弥逊','宋','宋词','song-ci','临江仙','[]','一片花飞春已减，那堪万点愁人。',70,'宋词/ci.song.6000.json','["一片花飞春已减，那堪万点愁人。", "可能春便负闲身。", "细思愁不饮，却是自辜春。", "且共一尊追落蕊，犹胜陌上成尘。", "杯行到手莫辞频。", "杏花须记取，曾与此翁邻。"]'),
('song-ci-25','临江仙','李弥逊','宋','宋词','song-ci','临江仙','[]','试问花枝馀几许，卷帘细雨随人。',70,'宋词/ci.song.6000.json','["试问花枝馀几许，卷帘细雨随人。", "风光犹恋苦吟身。", "海棠浑怯冷，为我强留春。", "细听惜花歌白雪，不知盏面生尘。", "吹开吹谢漫惊频。", "少陵真有味，爱酒觅南邻。"]'),
('song-ci-26','醉花阴','李弥逊','宋','宋词','song-ci','醉花阴','[]','翠箔阴阴笼画阁。',62,'宋词/ci.song.6000.json','["翠箔阴阴笼画阁。", "昨夜东风恶。", "香迳慢春泥，南陌东郊，惆怅妨行乐。", "伤春比似年时觉。", "潘鬓新来薄。", "何处不禁愁，雨滴花腮，和泪胭脂落。"]'),
('song-ci-27','醉花阴','李弥逊','宋','宋词','song-ci','醉花阴','[]','紫菊红萸开犯早。',62,'宋词/ci.song.6000.json','["紫菊红萸开犯早。", "独占秋光老。", "酝造一般清，比著芝兰，犹自争多少。", "霜刀翦叶呈纤巧。", "手拈迎人笑。", "云鬓一枝斜，小阁幽窗，是处都香了。"]'),
('song-ci-28','清平乐','李弥逊','宋','宋词','song-ci','清平乐','[]','烛花催晓。',54,'宋词/ci.song.6000.json','["烛花催晓。", "醉玉颓春酒。", "一骑东风消息到。", "占得鳖头龙首。", "长安去路骎骎。", "明朝跃马芳阴。", "应是花繁莺巧，东君著意琼林。"]'),
('song-ci-29','清平乐','李弥逊','宋','宋词','song-ci','清平乐','[]','一帘红雨。',54,'宋词/ci.song.6000.json','["一帘红雨。", "飘荡谁家去。", "门外垂杨千万缕。", "不把东风留住。", "旧巢燕子来迟。", "故园绿暗残枝。", "肠断画桥烟水，此情不许春知。"]'),
('song-ci-30','浪淘沙','李弥逊','宋','宋词','song-ci','浪淘沙','[]','把酒挽芳时。',64,'宋词/ci.song.6000.json','["把酒挽芳时。", "醉袖淋漓。", "多情楚客为秋悲。", "未抵香飘红褪也，独绕空枝。", "天女宝刀迟。", "露染风披。", "翠云叠叠拥铢衣。", "知道筠溪春寂寞，来慰相思。"]'),
('song-ci-31','浪淘沙','李弥逊','宋','宋词','song-ci','浪淘沙','[]','乐事信难逢。',64,'宋词/ci.song.6000.json','["乐事信难逢。", "莫放匆匆。", "飞红撩乱减春容。", "临水不禁频送客，风袖龙锺。", "小阁画堂东。", "绮绣相重。", "尊前谁唱夏云峰。", "醒后欲寻溪上路，烟水无穷。"]'),
('song-ci-32','谒金门','李弥逊','宋','宋词','song-ci','谒金门','[]','春又老。',53,'宋词/ci.song.6000.json','["春又老。", "愁似落花难扫。", "一醉一回才忘了。", "醒来还满抱。", "此恨欲凭谁道。", "柳外数声啼鸟。", "只恐春风吹不到。", "断云连碧草。"]'),
('song-ci-33','滴滴金','李弥逊','宋','宋词','song-ci','滴滴金','[]','广平未拚心如铁。',60,'宋词/ci.song.6000.json','["广平未拚心如铁。", "恨梅花、隔年别。", "化工翦水斗春风，似南枝和月。", "长鲸一饮宁论石。", "想高歌、醉瑶席。", "几时归去共尊罍，看寒花连陌。"]'),
('song-ci-34','诉衷情','李弥逊','宋','宋词','song-ci','诉衷情','[]','小桃初破两三花。',54,'宋词/ci.song.6000.json','["小桃初破两三花。", "深浅散馀霞。", "东君也解人意，次第到山家。", "临水岸，一枝斜。", "照笼纱。", "可怜何事，苦爱施朱，减尽容华。"]'),
('song-ci-35','好事近','李弥逊','宋','宋词','song-ci','好事近','[]','春苑杂花芳，诗老剩夸梅格。',53,'宋词/ci.song.6000.json','["春苑杂花芳，诗老剩夸梅格。", "谁道武陵深处，便不如姑射。", "莫分红浅与红深，点点是春色。", "生怕一番风雨，半飘零江国。"]'),
('song-ci-36','鹤冲天','李弥逊','宋','宋词','song-ci','鹤冲天','[]','篘玉液，酿花光。',57,'宋词/ci.song.6000.json','["篘玉液，酿花光。", "来趁北窗凉。", "为君小摘蜀葵黄。", "一似嗅枝香。", "饮中仙，山中相。", "也道十分宫样。", "一般时候最宜尝。", "竹院月侵床。"]'),
('song-ci-37','天仙子','李弥逊','宋','宋词','song-ci','天仙子','[]','飞盖追春春约伫。',80,'宋词/ci.song.6000.json','["飞盖追春春约伫。", "繁杏枝头红未雨。", "小楼翠幕不禁风，芳草路。", "无尘处。", "明月满庭人欲去。", "一醉邻翁须记取。", "见说新妆桃叶女。", "明年却对此花时，留不住。", "花前语。", "总向似花人付与。"]'),
('song-ci-38','清平乐','李弥逊','宋','宋词','song-ci','清平乐','[]','断桥缺月。',54,'宋词/ci.song.6000.json','["断桥缺月。", "点点枝头雪。", "画角吹残声未歇。", "早是一年春别。", "寿阳弄粉成妆。", "柔肠结结丁香。", "可怕真梅轻妒，游蜂说与何妨。"]'),
('song-ci-39','清平乐','李弥逊','宋','宋词','song-ci','清平乐','[]','推愁何计。',54,'宋词/ci.song.6000.json','["推愁何计。", "车下忘乘坠。", "日上南枝春有意。", "已讶红酥如缀。", "儿童缓整馀杯。", "芒鞋午夜重来。", "素面应憎月冷，真香不逐风回。"]'),
('song-ci-40','清平乐','李弥逊','宋','宋词','song-ci','清平乐','[]','长红小白。',54,'宋词/ci.song.6000.json','["长红小白。", "何处寻梅格。", "日日南山云满额。", "暗老一分春色。", "广平赋罢瑶香。", "细□花蕊商量。", "留得笔端雨露，后来收拾群芳。"]'),
('song-ci-41','点绛唇','李弥逊','宋','宋词','song-ci','点绛唇','[]','翦翦疏花，托根宛在长松底。',50,'宋词/ci.song.6000.json','["翦翦疏花，托根宛在长松底。", "蔓柯相倚。", "便有凌霄志。", "丹凤忽来，小队迎秋起。", "留无计。", "待公归侍。", "重与分红翠。"]'),
('song-ci-42','虞美人','李弥逊','宋','宋词','song-ci','虞美人','[]','梨花院落溶溶雨。',66,'宋词/ci.song.6000.json','["梨花院落溶溶雨。", "弱柳低金缕。", "画檐风露为谁明。", "青翼来时试问、董双成。", "去年春酒为眉寿。", "花影浮金斗。", "不须更觅老人星。", "但愿一年一上、一千龄。"]'),
('song-ci-43','醉花阴','李弥逊','宋','宋词','song-ci','醉花阴','[]','池面芙蕖红散绮。',62,'宋词/ci.song.6000.json','["池面芙蕖红散绮。", "鹊噪朱门喜。", "环佩响天风，香霭杯盘，更约麻姑侍。", "尘寰不隔蓬莱水。", "束带岩廊戏。", "瘦鹤与长松，且伴臞仙，久住人间世。"]'),
('song-ci-44','醉花阴','李弥逊','宋','宋词','song-ci','醉花阴','[]','帘卷西风轻雨外。',62,'宋词/ci.song.6000.json','["帘卷西风轻雨外。", "揖数峰横翠。", "楼上地行仙，压玉为醪，旋摘黄金蕊。", "一觞一阕千秋岁。", "不愿封侯贵。", "长伴紫髯翁，踏月吹箫，笑咏云山里。"]'),
('song-ci-45','感皇恩','李弥逊','宋','宋词','song-ci','感皇恩','[]','花院小回廊，庭萱成行。',81,'宋词/ci.song.6000.json','["花院小回廊，庭萱成行。", "水面红妆翠绡帐。", "蓬莱云近，风露一番清旷。", "星郎来碧落，长庚象。", "素志未酬，丹心益壮。", "且醉真珠小槽酿。", "不须皓齿，拍手狂歌清唱。", "一尊为寿庆，羲皇上。"]'),
('song-ci-46','感皇恩','李弥逊','宋','宋词','song-ci','感皇恩','[]','密竹翦轻绡，华堂初建。',81,'宋词/ci.song.6000.json','["密竹翦轻绡，华堂初建。", "卷上虾须待开宴。", "寿期春聚，芍药一番开遍。", "砌成锦步帐，笼弦管。", "绛节近颁，丹雏重见。", "花里双双乍归燕。", "重重乐事，凭仗东风拘管。", "一时分付与，金荷劝。"]'),
('song-ci-47','小重山','李弥逊','宋','宋词','song-ci','小重山','[]','鞭凤骖鸾自斗杓。',70,'宋词/ci.song.6000.json','["鞭凤骖鸾自斗杓。", "老君亲抱送，下层霄。", "人间仙李占春饶。", "千秋里，松月伴吹箫。", "故国水云遥。", "谪仙丹荔熟，剥红绡。", "南山影转卧金蕉。", "倾寒绿，眉寿比山高。"]'),
('song-ci-48','小重山','李弥逊','宋','宋词','song-ci','小重山','[]','星斗心胸锦绣肠。',70,'宋词/ci.song.6000.json','["星斗心胸锦绣肠。", "厌随尘土客，逐炎凉。", "江山风月伴行藏。", "无人识，高卧水云乡。", "肘后有仙方。", "假饶丹未就，寿须长。", "儒冠多误莫思量。", "十分酒，菡萏小池塘。"]'),
('song-ci-49','花心动','李弥逊','宋','宋词','song-ci','花心动','[]','红日当楼，绣屏开、风裀舞花随步。',127,'宋词/ci.song.6000.json','["红日当楼，绣屏开、风裀舞花随步。", "绛拂佩兰，香染妆梅，彷佛紫烟真侣。", "雪消池馆年年会，玻璃泛、小槽新注。", "弄箫语。", "云璈未彻，暖回芳树。", "瑶检曾攽寿缕。", "好系日萦春，驭鸾深驻。", "桂殿影寒，蓬山波阔，未似彩衣庭户。", "坐看鹤鬓云来戏，重重拜、天阶雨露。", "纵游处。", "人间遍寻洞府。"]'),
('song-ci-50','渔家傲','李弥逊','宋','宋词','song-ci','渔家傲','[]','海角秋高风力骤。',72,'宋词/ci.song.6000.json','["海角秋高风力骤。", "楼台四面山容瘦。", "季子貂裘寒欲透。", "悬弧昼。", "高歌棣萼聊卮酒。", "且共追欢宽白首。", "清闲赢得身长久。", "世上功名翻覆手。", "为君寿。", "腰间要看悬金斗。"]'),
('song-ci-51','阮郎归','李弥逊','宋','宋词','song-ci','阮郎归','[]','黄花犹未拆霜枝。',56,'宋词/ci.song.6000.json','["黄花犹未拆霜枝。", "今年秋较迟。", "六么催泛玉东西。", "登高庆诞时。", "神仙事，古来稀。", "且为千岁期。", "戏莱堂上两庞眉。", "何妨举案齐。"]'),
('song-ci-52','醉落托','李弥逊','宋','宋词','song-ci','醉落托','[]','霜林变绿。',67,'宋词/ci.song.6000.json','["霜林变绿。", "画帘桂子排香粟。", "一声檀板惊飞鹜。", "弦管楼高，谁在阑干曲。", "人生一笑难相属。", "满堂何必堆金玉。", "但求身健儿孙福。", "鹤发年年，同泛清尊菊。"]'),
('song-ci-53','柳梢青','李弥逊','宋','宋词','song-ci','柳梢青','[]','寿烟笼席。',61,'宋词/ci.song.6000.json','["寿烟笼席。", "采莲新按，舞腰无力。", "占尽风光，人间天上，今夕何夕。", "蓝袍换了莱衣，庆岁岁、君恩屡锡。", "连夜欢声，满城佳气，和春留得。"]'),
('song-ci-54','点绛唇','李弥逊','宋','宋词','song-ci','点绛唇','[]','花信争先，暗将春意传桃李。',50,'宋词/ci.song.6000.json','["花信争先，暗将春意传桃李。", "寿卿同醉。", "绿野连珠履。", "麟阁丹青，眷注耆英裔。", "眉间喜。", "日边飞骑。", "来促东山起。"]'),
('song-ci-55','十样花','李弥逊','宋','宋词','song-ci','十样花','[]','陌上风光浓处。',204,'宋词/ci.song.6000.json','["陌上风光浓处。", "第一寒梅先吐。", "待得春来也，香销减，态凝伫。", "百花休谩妒。", "陌上风光浓处。", "繁杏枝头春聚。", "艳态最娇娆，堪比并，东邻女。", "红梅何足数。", "陌上风光浓处。", "日暖山樱红露。", "结子点朱唇，花谢后，君看取。", "流莺偏嘱付。", "陌上风光浓处。", "忘却桃园归路。", "洞口水流迟，香风动，红无数。", "吹愁何处去。", "陌上风光浓处。", "最是海棠风措。", "翠袖衬轻红，盈盈泪，怨春去。", "黄昏微带雨。", "陌上风光浓处。", "自有花王为主。", "富艳压群芳，蜂蝶戏，燕莺语。", "东君都付与。"]'),
('song-ci-56','菩萨蛮','李弥逊','宋','宋词','song-ci','菩萨蛮','[]','江城烽火连三月。',52,'宋词/ci.song.6000.json','["江城烽火连三月。", "不堪对酒长亭别。", "休作断肠声。", "老来无泪倾。", "风高帆影疾。", "目送舟痕碧。", "锦字几时来。", "薰风无雁回。"]'),
('song-ci-57','水调歌头','王以宁','宋','宋词','song-ci','水调歌头','[]','岁晚橘洲上，老叶舞愁红。',114,'宋词/ci.song.6000.json','["岁晚橘洲上，老叶舞愁红。", "西山光翠，依旧影落酒杯中。", "人在子亭高处，下望长沙城郭，猎猎酒帘风。", "远水湛寒碧，独钓绿蓑翁。", "怀往事，追昨梦，转头空。", "孙郎前日，豪健颐指五都雄。", "起拥奇才剑客，十万银戈赤帻，歌鼓壮军容。", "何似裴相国，谈道老圭峰。"]'),
('song-ci-58','水调歌头','王以宁','宋','宋词','song-ci','水调歌头','[]','大别我知友，突兀起西州。',114,'宋词/ci.song.6000.json','["大别我知友，突兀起西州。", "十年重见，依旧秀色照清眸。", "常记鲒碕狂客，邀我登楼雪霁，杖策拥羊裘。", "山吐月千仞，残夜水明楼。", "黄粱梦，未觉枕，几经秋。", "与君邂逅，相逐飞步碧山头。", "举酒一觞今古，叹息英雄骨冷，清泪不能收。", "鹦鹉更谁赋，遗恨满芳洲。"]'),
('song-ci-59','满庭芳','王以宁','宋','宋词','song-ci','满庭芳','[]','山耸方壶，潮通碧海，江东自昔名家。',118,'宋词/ci.song.6000.json','["山耸方壶，潮通碧海，江东自昔名家。", "玉真仙子，珰佩粲朝霞。", "一种天香胜味，笑杨梅、不数枇杷。", "难模写，牟尼妙质，光透紫丹砂。", "咨嗟。", "如此辈，不知何为，留滞天涯。", "料甘心远引，无意纷华。", "一任姚黄魏紫，供吟赏、银烛笼纱。", "南游士，日餐千颗，不愿九霞车。"]'),
('song-ci-60','满庭芳','王以宁','宋','宋词','song-ci','满庭芳','[]','千古南阳，刘郎乡国，依约楚俗秦风。',118,'宋词/ci.song.6000.json','["千古南阳，刘郎乡国，依约楚俗秦风。", "英姿豪气，耆旧笑谈中。", "珰佩来从帝所，许洲花、潭菊从容。", "霜秋晓，凉生日观，极目送飞鸿。", "主公。", "天下士，挥豪万字，一饮千锺。", "醉高歌起舞，唤醒人龙。", "我自人间漫浪，平生事、南北西东。", "辞公去，寒眸激电，曾识小安丰。"]'),
('song-ci-61','满庭芳','王以宁','宋','宋词','song-ci','满庭芳','[]','五十七年，侵寻老矣，小庵初筑林坰。',118,'宋词/ci.song.6000.json','["五十七年，侵寻老矣，小庵初筑林坰。", "故人相过，喜雪舞祥霙。", "遍野跳珠浅玉，纵儿童、收满金瓶。", "明年待，洗光银海，袖手看升平。", "先生。", "齐物久，蚁丘罢战，蜗角休征。", "趁尊前身健，有酒须倾。", "随分村歌社舞，何须问、武宿文星。", "忘怀矣，未能忘酒，相与醉忘形。"]'),
('song-ci-62','满庭芳','王以宁','宋','宋词','song-ci','满庭芳','[]','千古黄州，雪堂奇胜，名与赤壁齐高。',118,'宋词/ci.song.6000.json','["千古黄州，雪堂奇胜，名与赤壁齐高。", "竹楼千字，笔势压江涛。", "笑问江头皓月，应曾照、今古英豪。", "菖蒲酒，窊尊无恙，聊共访临皋。", "陶陶。", "谁晤对，粲花吐论，宫锦纫袍。", "借银涛雪浪，一洗尘劳。", "好在江山如画，人易老、双鬓难茠。", "升平代，凭高望远，当赋反离骚。"]'),
('song-ci-63','蓦山溪','王以宁','宋','宋词','song-ci','蓦山溪','[]','平山堂上，侧盏歌南浦。',102,'宋词/ci.song.6000.json','["平山堂上，侧盏歌南浦。", "醉望五州山，渺千里、银涛东注。", "钱郎英远，满腹贮精神，窥素壁，墨栖鸦，历历题诗处。", "风裘雪帽，踏遍荆湘路。", "回首古扬州，沁天外、残霞一缕。", "德星光次，何日照长沙，渔夫曲，竹枝词，万古歌来暮。"]'),
('song-ci-64','蓦山溪','王以宁','宋','宋词','song-ci','蓦山溪','[]','雕弓绣帽。',102,'宋词/ci.song.6000.json','["雕弓绣帽。", "戏马秦淮道。", "风入马啼轻，曾踏遍、淮堤芳草。", "飞英点点，春事已阑珊，风雨横，别离多，断送英雄老。", "功名终在，休惜芳尊倒。", "谈笑下燕云，看千里、风驱电扫。", "男儿此事，莫待鬓丝棼，汉都护，万年觞，玉殿春风早。"]'),
('song-ci-65','念奴娇','王以宁','宋','宋词','song-ci','念奴娇','[]','天工何意，碎琼珰玉佩，书空千尺。',120,'宋词/ci.song.6000.json','["天工何意，碎琼珰玉佩，书空千尺。", "箬笠蓑衫扁舟下，淮口烟林如织。", "飞观嶙峋，子亭突兀，影浸澄淮碧。", "纶巾鹤氅，是谁独笑携策。", "遥想易水燕山，有人方醉赏，六花如席。", "云重天低酣歌罢，胆壮乾坤犹窄。", "射雉归来，铁鳞十万，踏碎千山白。", "紫箫声断，唤回春满南陌。"]'),
('song-ci-66','念奴娇','王以宁','宋','宋词','song-ci','念奴娇','[]','云收天碧。',120,'宋词/ci.song.6000.json','["云收天碧。", "渐风高露冷，群喧初寂。", "远浦归舟荒渡口，搴篷横棹堤侧。", "一带澄江，十分蟾影，千里寒光白。", "襟怀迎爽，有人独步携策。", "遥想帘卷琼楼，凭阑凝望，此意知何极。", "声断琴箫双凤驾，凌厉飞仙同籍。", "问汉乘槎，采珠临海，往事空踪迹。", "莫辞吟赏，终宵清景难得。"]'),
('song-ci-67','念奴娇','王以宁','宋','宋词','song-ci','念奴娇','[]','晚烟凝碧。',120,'宋词/ci.song.6000.json','["晚烟凝碧。", "渐渔村山市，人归寂寂。", "有客飞舟还顾访，应讶纶巾敧侧。", "得意忘年，推诚投分，高论追元白。", "英标逸气，笑予穷抱真策。", "兴尽又复言归，秋风分袂，浩荡思无极。", "咫尺昭山明翠壁，那知中隐咸籍。", "说梦难听，闭门寻梦，肯念栖萍迹。", "浪吟狂醉，几时还共重得。"]'),
('song-ci-68','鹧鸪天','王以宁','宋','宋词','song-ci','鹧鸪天','[]','昔有书生荐寿杯。',64,'宋词/ci.song.6000.json','["昔有书生荐寿杯。", "清词妙绝贺方回。", "黄花也欲为君寿，先向重阳六日开。", "跻楚俗，上春台。", "政成归去位三台。", "明年寿酒君王劝，知有传宣敕使来。"]'),
('song-ci-69','鹧鸪天','王以宁','宋','宋词','song-ci','鹧鸪天','[]','帝乙何年骑玉龙。',64,'宋词/ci.song.6000.json','["帝乙何年骑玉龙。", "武夷仙伯笑相从。", "长庚瑞应游仙梦，碧藕花开解愠风。", "歌既醉，乐元丰。", "明良相悦寿无穷。", "野人更有深深祝，笑指三台十八公。"]'),
('song-ci-70','鹧鸪天','王以宁','宋','宋词','song-ci','鹧鸪天','[]','桃李纷纷春事催。',64,'宋词/ci.song.6000.json','["桃李纷纷春事催。", "桐花风定牡丹开。", "天麟下作人间瑞，玉燕清宵入梦来。", "红玉酎，紫霞杯。", "五云深处望三台。", "君家况有庭前柏，好个擎天八柱材。"]'),
('song-ci-71','临江仙','王以宁','宋','宋词','song-ci','临江仙','[]','眼看西园红与紫，年来几度芳菲。',70,'宋词/ci.song.6000.json','["眼看西园红与紫，年来几度芳菲。", "吾生四十渐知非。", "祗思青箬笠，江上雨霏霏。", "饮酒但知寻夏季，不须远慕安期。", "丹成仙去是何时。", "龟藏何必学，春日正迟迟。"]'),
('song-ci-72','临江仙','王以宁','宋','宋词','song-ci','临江仙','[]','此理循环如引锯，春来百草菲菲。',70,'宋词/ci.song.6000.json','["此理循环如引锯，春来百草菲菲。", "道人一笑悟前非。", "功名真长物，夕霭与朝霏。", "梦褥清孙今绿隐，漫郎自许风期。", "江楼景物得旬时。", "平芜三百里，天阔夕阳迟。"]'),
('song-ci-73','临江仙','王以宁','宋','宋词','song-ci','临江仙','[]','闻道洛阳花正好，家家遮户春风。',70,'宋词/ci.song.6000.json','["闻道洛阳花正好，家家遮户春风。", "道人饮处百壶空。", "年年花下醉，看尽几番红。", "此拐又从何处去，飘蓬一任西东。", "语声虽异笑声同。", "一轮清夜月，何处不相逢。"]'),
('song-ci-74','浣溪沙','王以宁','宋','宋词','song-ci','浣溪沙','[]','起看船头蜀锦张。',48,'宋词/ci.song.6000.json','["起看船头蜀锦张。", "沙汀红叶舞斜阳。", "杖拿惊起睡鸳鸯。", "木落群山雕玉□，霜和冷月浸澄江。", "疏篷今夜梦潇湘。"]'),
('song-ci-75','西江月慢','吕渭老','宋','宋词','song-ci','西江月慢','[]','春风淡淡，清昼永、落英千尺。',128,'宋词/ci.song.6000.json','["春风淡淡，清昼永、落英千尺。", "桃杏散平郊，晴蜂来往，妙香飘掷。", "傍画桥、煮酒青帘，绿杨风外，数声长笛。", "记去年、紫陌朱门，花下旧相识。", "向宝帕、裁书凭燕翼。", "望翠阁、烟林似织。", "闻道春衣犹未整，过禁烟寒食。", "但记取、角枕情题，东窗休误，这些端的。", "更莫待、青子绿阴春事寂。"]'),
('song-ci-76','思佳客','吕渭老','宋','宋词','song-ci','思佳客','[]','曾醉扬州十里楼。',64,'宋词/ci.song.6000.json','["曾醉扬州十里楼。", "竹西歌吹至今愁。", "燕衔柳絮春心远，鱼入晴江水自流。", "情渺渺，梦悠悠。", "重寻罗带认银钩。", "挂帆欲伴渔人去，只恐桃花误客舟。"]'),
('song-ci-77','思佳客','吕渭老','宋','宋词','song-ci','思佳客','[]','薄薄山云欲湿花。',64,'宋词/ci.song.6000.json','["薄薄山云欲湿花。", "双双燕子入帘斜。", "西楼尚记垂垂雪，酌酒犹残片片霞。", "人已远，发成华。", "小楼疏竹宅谁家。", "试凭去雁通消息，仙子当乘八月槎。"]'),
('song-ci-78','夜游宫','吕渭老','宋','宋词','song-ci','夜游宫','[]','帘外繁霜未扫。',71,'宋词/ci.song.6000.json','["帘外繁霜未扫。", "楼角动、玉绳横晓。", "百和交焚瑞烟绕。", "霁霞明，画屏深，天渺渺。", "喜色连池沼。", "荐眉寿、玉儿娇小。", "早晚除书下天表。", "日初长，莫等闲，孤一笑。"]'),
('song-ci-79','浣溪沙','吕渭老','宋','宋词','song-ci','浣溪沙','[]','风扫长林雪压枝。',48,'宋词/ci.song.6000.json','["风扫长林雪压枝。", "纷纷冻鹊傍帘飞。", "一尊聊作破寒威。", "春意正愁梅漏泄，客情尤怕病禁持。", "曲阑干外日初迟。"]'),
('song-ci-80','南歌子','吕渭老','宋','宋词','song-ci','南歌子','[]','片片云藏雨，重重雾隐山。',62,'宋词/ci.song.6000.json','["片片云藏雨，重重雾隐山。", "可怜新月似眉弯。", "今夜断肠凝望、小楼寒。", "梦断云房远，书长蜡炬残。", "夜妆应罢短屏间。", "都把一春心事、付梅酸。"]'),
('song-ci-81','如梦令','吕渭老','宋','宋词','song-ci','如梦令','[]','珠阁雨帘高卷。',40,'宋词/ci.song.6000.json','["珠阁雨帘高卷。", "望断碧梧墙院。", "短梦有幽寻，晓枕一峰云乱。", "谁见。", "谁见。", "风散菊英千片。"]'),
('song-ci-82','浣溪沙','吕渭老','宋','宋词','song-ci','浣溪沙','[]','微绽樱桃一颗红。',48,'宋词/ci.song.6000.json','["微绽樱桃一颗红。", "断肠声里唱玲珑。", "轻罗小扇掩酥胸。", "惹鬓蛛丝新有喜，窥窗月彩旧相从。", "清宵一醉许谁同。"]'),
('song-ci-83','浪淘沙','吕渭老','宋','宋词','song-ci','浪淘沙','[]','凉露洗秋空。',64,'宋词/ci.song.6000.json','["凉露洗秋空。", "菊径鸣蛩。", "水晶帘外月玲珑。", "烛蕊双悬人似玉，簌簌啼红。", "宋玉在墙东。", "醉袖摇风。", "心随月影入帘栊。", "戏著锦茵天样远，一段愁浓。"]'),
('song-ci-84','醉桃源・阮郎归','吕渭老','宋','宋词','song-ci','醉桃源・阮郎归','[]','棂香新染砑红绫。',56,'宋词/ci.song.6000.json','["棂香新染砑红绫。", "腰肢瘦不胜。", "合欢小幌掩馀酲。", "芙蓉入梦频。", "山不尽，水无情。", "锦河隔锦茵。", "刘郎仙骨未应轻。", "桃花已误人。"]'),
('song-ci-85','思佳客','吕渭老','宋','宋词','song-ci','思佳客','[]','梦里相逢不记时。',64,'宋词/ci.song.6000.json','["梦里相逢不记时。", "断肠多在杏花西。", "微开笑语兜鞋急，远有灯光掠鬓迟。", "辞永夜，失深期。", "一枝黄菊对伤悲。", "夜凉窗外闻裁剪，应熨沈香制舞衣。"]'),
('song-ci-86','小重山','吕渭老','宋','宋词','song-ci','小重山','[]','雨洗檐花湿画帘。',70,'宋词/ci.song.6000.json','["雨洗檐花湿画帘。", "知他因甚地，瘦厌厌。", "玉人风味似冰蟾。", "愁不见，烟雾晓来添。", "烦恼旧时谙。", "新来一段事，未心甘。", "满怀离绪过春蚕。", "灯残也，谁见我眉尖。"]'),
('song-ci-87','柳梢青','吕渭老','宋','宋词','song-ci','柳梢青','[]','远帘笼月。',61,'宋词/ci.song.6000.json','["远帘笼月。", "谁见南陌，子规啼血。", "萸糁菊英，整冠落帽，一时虚说。", "五湖自有深期，曾指定、灯花细说。", "燕子巢空，秋鸿程远，音书中绝。"]'),
('song-ci-88','卜算子','吕渭老','宋','宋词','song-ci','卜算子','[]','云破月高悬，照我双双泪。',52,'宋词/ci.song.6000.json','["云破月高悬，照我双双泪。", "人在朱桥转曲西，翠幕重重闭。", "要见索商量，见了还无计。", "心似长檠一点灯，到晓清清地。"]'),
('song-ci-89','卜算子','吕渭老','宋','宋词','song-ci','卜算子','[]','眉为占愁多，镇日长长敛。',52,'宋词/ci.song.6000.json','["眉为占愁多，镇日长长敛。", "试问心中有底愁，泪早千千点。", "莫唱短因缘，缘短犹伤感。", "谁信萧郎是路人，常有深深念。"]'),
('song-ci-90','卜算子','吕渭老','宋','宋词','song-ci','卜算子','[]','一日抵三秋，半月如千岁。',52,'宋词/ci.song.6000.json','["一日抵三秋，半月如千岁。", "自夏经秋到雪飞，一向都无计。", "续续说相思，不尽无穷意。", "若写幽怀一段愁，应用天为纸。"]'),
('song-ci-91','卜算子','吕渭老','宋','宋词','song-ci','卜算子','[]','得酒解愁烦，多病还疏酒。',52,'宋词/ci.song.6000.json','["得酒解愁烦，多病还疏酒。", "本是多情失意人，此味如何受。", "沈醉且高歌，不饮心常有。", "守著残灯斗著眉，怎不腰肢瘦。"]'),
('song-ci-92','如梦令','吕渭老','宋','宋词','song-ci','如梦令','[]','多谢西池桃李。',40,'宋词/ci.song.6000.json','["多谢西池桃李。", "伴我一春沈醉。", "能有几多香，陪了一江来泪。", "憔悴。", "憔悴。", "又是落花铺地。"]'),
('song-ci-93','木兰花慢','吕渭老','宋','宋词','song-ci','木兰花慢','[]','石榴花谢了，正荷叶、盖平池。',124,'宋词/ci.song.6000.json','["石榴花谢了，正荷叶、盖平池。", "试玛瑙杯深，琅玕簟冷，临水帘帷。", "知他故人甚处，晚霞明、断浦柳枝垂。", "唯有松风水月，向人长似当时。", "依依。", "望断水穷，云起处、是天涯。", "奈燕子楼高，江南梦断，虚费相思。", "新愁暗生旧恨，更流萤、弄月入纱衣。", "除却幽花软草，此情未许人知。"]'),
('song-ci-94','木兰花慢','吕渭老','宋','宋词','song-ci','木兰花慢','[]','对修篁万个，更疏雨、洗琅玕。',124,'宋词/ci.song.6000.json','["对修篁万个，更疏雨、洗琅玕。", "望燕外晴丝，鸥边水叶，胡蝶成团。", "榴红劝人把酒，泛菖蒲、对客不成欢。", "金缕新番彩索，始知今岁衣宽。", "年年。", "此日青楼，花缺处、倚阑干。", "记小扇清歌，蛮笺妙墨，不觉更残。", "可怜旧游似梦，向人人、未减一枝兰。", "纵有千金莫惜，大家沈醉花间。"]'),
('song-ci-95','木兰花慢','吕渭老','宋','宋词','song-ci','木兰花慢','[]','桂乡云万缕，更飞雨、洗香车。',124,'宋词/ci.song.6000.json','["桂乡云万缕，更飞雨、洗香车。", "念密会经年，银潢浪阻，玉露期赊。", "灵星瑞桥对展，散匆匆、喜色满天涯。", "回首丁宁晓角，未宜吹动梅花。", "家家。", "竟赏彩茸，穿桂影、醉流霞。", "渐舞袖翻鸾，歌声缀凤，钗影交加。", "人间共饶宴乐，算天孙、怎忍遣河斜。", "莫惜西楼剪烛，大家同到啼鸦。"]'),
('song-ci-96','恋香衾','吕渭老','宋','宋词','song-ci','恋香衾','[]','记得花阴同携手，指定日、许我同欢。',112,'宋词/ci.song.6000.json','["记得花阴同携手，指定日、许我同欢。", "唤做真成，耳热心安。", "打叠从来不成器，待做个、平地神仙。", "又却不成些事，蓦地心残。", "据我如今没投奔，见著你、泪早偷弹。", "对月临风，一味埋冤。", "笑则人前不妨笑，行笑里、斗觉心烦。", "怎生分得烦恼，两处匀摊。"]'),
('song-ci-97','豆叶黄・忆王孙','吕渭老','宋','宋词','song-ci','豆叶黄・忆王孙','[]','芰荷香外一声蝉。',36,'宋词/ci.song.6000.json','["芰荷香外一声蝉。", "风撼琅玕惊昼眠。", "刻烛题诗花满笺。", "小神仙。", "对倚阑干月正圆。"]'),
('song-ci-98','豆叶黄・忆王孙','吕渭老','宋','宋词','song-ci','豆叶黄・忆王孙','[]','晚妆新试碧衫凉。',36,'宋词/ci.song.6000.json','["晚妆新试碧衫凉。", "金鸭犹残昨夜香。", "柳际风来月满廊。", "一双双。", "人对鸳鸯浴小塘。"]'),
('song-ci-99','豆叶黄・忆王孙','吕渭老','宋','宋词','song-ci','豆叶黄・忆王孙','[]','轻罗团扇掩微羞。',36,'宋词/ci.song.6000.json','["轻罗团扇掩微羞。", "酒满玻璃花满头。", "小板齐声唱石州。", "月如钩。", "一寸横波入鬓流。"]'),
('song-ci-100','豆叶黄・忆王孙','吕渭老','宋','宋词','song-ci','豆叶黄・忆王孙','[]','林花著雨褪胭脂。',36,'宋词/ci.song.6000.json','["林花著雨褪胭脂。", "叶底双桃结子迟。", "对镜凭郎略皱眉。", "笑微微。", "燕子羞人必懒归。"]'),
('song-ci-101','豆叶黄・忆王孙','吕渭老','宋','宋词','song-ci','豆叶黄・忆王孙','[]','玉萧风外一声清。',36,'宋词/ci.song.6000.json','["玉萧风外一声清。", "粉面婵娟月对明。", "紫府楼台夜不扃。", "羽衣轻。", "稳驾双鸾谒帝庭。"]'),
('song-ci-102','千秋岁','吕渭老','宋','宋词','song-ci','千秋岁','[]','宝蟾悬镜。',87,'宋词/ci.song.6000.json','["宝蟾悬镜。", "露颗倾荷柄。", "飞萤点点明花径。", "凝愁情不展，宿酒风还醒。", "天似晓，银河半落星相趁。", "心事都无定。", "才致元相称。", "春过了，秋将近。", "小窗通竹圃，野色连金井。", "得仗个，多情燕子分明问。"]'),
('song-ci-103','好事近','吕渭老','宋','宋词','song-ci','好事近','[]','心事已成空，春尽百花零落。',53,'宋词/ci.song.6000.json','["心事已成空，春尽百花零落。", "谁见黄鹂百啭，索东君评泊。", "晓来枝上语绵蛮，应悔向来错。", "看则绿阴青子，却恓惶无托。"]'),
('song-ci-104','南乡子','吕渭老','宋','宋词','song-ci','南乡子','[]','小雨阻行舟。',66,'宋词/ci.song.6000.json','["小雨阻行舟。", "人在烟林古渡头。", "欲挈一尊相就醉，无由。", "谁见横波入鬓流。", "百计不迟留。", "明月他时独上楼。", "水尽又山山又水，温柔。", "占断江南万斛愁。"]'),
('song-ci-105','南乡子','吕渭老','宋','宋词','song-ci','南乡子','[]','樊子唤春归。',66,'宋词/ci.song.6000.json','["樊子唤春归。", "梦逐杨花满院飞。", "吹过西家人不见，依依。", "萍点荷钱又满池。", "屈指数佳期。", "何日凭肩对展眉。", "倾尽十分应不醉，迟迟。", "何惜樱桃杏子时。"]'),
('song-ci-106','浪淘沙','吕渭老','宋','宋词','song-ci','浪淘沙','[]','纤指捧玻璃。',64,'宋词/ci.song.6000.json','["纤指捧玻璃。", "莫惜重持。", "自离阆苑失回期。", "门掩东风桃著子，帘影迟迟。", "楼上正横篦。", "荷气沾衣。", "谁将名玉碾花枝。", "不比寻常红与紫，取次芳菲。"]'),
('song-ci-107','卜算子','吕渭老','宋','宋词','song-ci','卜算子','[]','渡口看潮生，水满蒹葭浦。',52,'宋词/ci.song.6000.json','["渡口看潮生，水满蒹葭浦。", "长记扁舟载月明，深入红云去。", "荷尽覆平池，忘了归来路。", "谁信南楼百尺高，不见如莲步。"]'),
('song-ci-108','小重山','吕渭老','宋','宋词','song-ci','小重山','[]','云护柔条雪压枝。',70,'宋词/ci.song.6000.json','["云护柔条雪压枝。", "斜风吹绛蜡，点胭脂。", "蔷薇柔水麝分脐。", "园林晚，脉脉带斜晖。", "深阁绣帘低。", "宝奁匀泪粉，晚妆迟。", "一枝屏外对依依。", "清宵永，谁伴破寒卮。"]'),
('song-ci-109','惜分钗・撷芳词','吕渭老','宋','宋词','song-ci','惜分钗・撷芳词','[]','春将半。',74,'宋词/ci.song.6000.json','["春将半。", "莺声乱。", "柳丝拂马花迎面。", "小堂风。", "暮楼锺。", "草色连云，暝色连空。", "重重。", "秋千畔。", "何人见。", "宝钗斜照春妆浅。", "酒霞红。", "与谁同。", "试问别来，近日情悰。", "忡忡。"]'),
('song-ci-110','惜分钗・撷芳词','吕渭老','宋','宋词','song-ci','惜分钗・撷芳词','[]','重帘挂。',74,'宋词/ci.song.6000.json','["重帘挂。", "微灯下。", "背兰同说春风话。", "月盈楼。", "泪盈眸。", "觑著红裀，无计迟留。", "休休。", "莺花谢。", "春残也。", "等闲泣损香罗帕。", "见无由。", "恨难收。", "梦短屏深，清夜悠悠。", "悠悠。"]'),
('song-ci-111','如梦令','吕渭老','宋','宋词','song-ci','如梦令','[]','花趁清明争展。',40,'宋词/ci.song.6000.json','["花趁清明争展。", "白白红红满院。", "莫怪泪痕多，爱底不能得见。", "凝恋。", "凝恋。", "门外雨飞帘卷。"]'),
('song-ci-112','水龙吟','吕渭老','宋','宋词','song-ci','水龙吟','["\u897f\u6e56"]','年年九月西湖，绣船继日笙箫拥。',126,'宋词/ci.song.6000.json','["年年九月西湖，绣船继日笙箫拥。", "五云深处，红帘一桁，语莺歌凤。", "群玉峰头，影娥池畔，烟霞飞动。", "认蓬瀛仙子，云程路远，贪人世、瑶池梦。", "要看黄尘清海，戏真珠、麻姑清纵。", "曲门自有，菊金芳砌，月篦浮栋。", "子著宫桃，舞翻官柳，霞杯纤捧。", "待明年更把，西风妙曲，按成新弄。"]'),
('song-ci-113','鹊桥仙','吕渭老','宋','宋词','song-ci','鹊桥仙','[]','西风不落，薄衾孤枕，记起花时些个。',68,'宋词/ci.song.6000.json','["西风不落，薄衾孤枕，记起花时些个。", "宿愁新恨两关心，说道理、分疏不可。", "别愁如絮，佳期何在，古屋萧萧灯火。", "打窗风雨又何消，梦未就、依前惊破。"]'),
('song-ci-114','点绛唇','吕渭老','宋','宋词','song-ci','点绛唇','[]','扇列红鸾，赭黄日色明金殿。',50,'宋词/ci.song.6000.json','["扇列红鸾，赭黄日色明金殿。", "御香葱茜。", "宝仗香风暖。", "咫尺天颜，九奏朝阳管。", "群臣宴。", "醉霞凝面。", "午漏传宫箭。"]'),
('song-ci-115','点绛唇','吕渭老','宋','宋词','song-ci','点绛唇','[]','俊眼犀心，尊前如有乘鸾便。',50,'宋词/ci.song.6000.json','["俊眼犀心，尊前如有乘鸾便。", "过愁传怨。", "只许灯光见。", "见了重休，河汉明遮断。", "深深院。", "乱风飘霰。", "揉了双罗燕。"]'),
('song-ci-116','水调歌头','吕渭老','宋','宋词','song-ci','水调歌头','[]','解衣同一笑，聊复起厨烟。',114,'宋词/ci.song.6000.json','["解衣同一笑，聊复起厨烟。", "醉乡何处，与君舒啸入壶天。", "长怪时情狭隘，杯酒岂容我辈，不上谪仙船。", "雅志念湖海，小艇一丝竿。", "夜迢迢，灯烛下，几心闲。", "平生得处，不在内外及中间。", "点检春风欢计，惟有诗情宛转，馀事尽疏残。", "彩笔题桐叶，佳句问平安。"]'),
('song-ci-117','好事近','吕渭老','宋','宋词','song-ci','好事近','[]','世事莫牵萦，乐取这闲时节。',54,'宋词/ci.song.6000.json','["世事莫牵萦，乐取这闲时节。", "且恁醉来醒去，免光阴虚设。", "有则有个泼心儿，不敢被利名啜。", "却待两手分付，与风花雪月。"]'),
('song-ci-118','好事近','吕渭老','宋','宋词','song-ci','好事近','[]','长记十年前，彼此玉颜云发。',53,'宋词/ci.song.6000.json','["长记十年前，彼此玉颜云发。", "尊酒几番相对，乐春花秋月。", "而今各自困飘零，憔悴几年别。", "说著大家烦恼，且大家休说。"]'),
('song-ci-119','青玉案','吕渭老','宋','宋词','song-ci','青玉案','[]','一尊聊对西风醉。',80,'宋词/ci.song.6000.json','["一尊聊对西风醉。", "况九日、明朝是。", "曾与茱萸论子细。", "江天虚旷，暮林横远，人隔银河水。", "碧云渐展天无际。", "吹不断、黄昏泪。", "若作欢期须早计。", "如何得似，鬓边新菊，双结黄金蕊。"]'),
('song-ci-120','倾杯乐','林季仲','宋','宋词','song-ci','倾杯乐','[]','璧月初圆，彩云轻护，散雪叠冰凉馆。',131,'宋词/ci.song.6000.json','["璧月初圆，彩云轻护，散雪叠冰凉馆。", "张眉竞巧，赵瑟新成，整顿戏衫歌扇。", "寿酒殷勤，娇语温柔，只愁杯浅。", "正连山玉枕，回波瑶席，漏长更款。", "良会久、细拥香肩，瑶庭闲步，共指渡河星点。", "今朝此日，同祝卿卿，福寿禄星齐转。", "但愿与君，歌舞常新，欢娱无算。", "看河桥鹊架，重会双星燕婉。"]'),
('song-ci-121','庆清朝','王之道','宋','宋词','song-ci','庆清朝','[]','晓日彤墀，春风黄伞，天颜咫尺清光。',118,'宋词/ci.song.6000.json','["晓日彤墀，春风黄伞，天颜咫尺清光。", "恩袍初赐，一时玉质金相。", "济济满廷鹓鹭，月卿映、日尹星郎。", "鸣鞘绕，锦鞯归路，醉舞醒狂。", "追随宝津琼苑，看穿花帽侧，拂柳鞭长。", "临流夹径，参差绿荫红芳。", "宴罢西城向晚，歌呼笑语溢平康。", "休相恼，争揭疏帘，半出新妆。"]'),
('song-ci-122','谒金门','王之道','宋','宋词','song-ci','谒金门','[]','春睡起。',53,'宋词/ci.song.6000.json','["春睡起。", "金鸭暖消沈水。", "笑比梅花鸾鉴里。", "嗅香还嚼蕊。", "琼户倚来重倚。", "又见夕阳西坠。", "门外马嘶郎且至。", "失惊心暗喜。"]'),
('song-ci-123','蝶恋花','王之道','宋','宋词','song-ci','蝶恋花','[]','春入花梢红欲半。',70,'宋词/ci.song.6000.json','["春入花梢红欲半。", "水外绿杨，掩映笙歌院。", "霁日迟迟风扇暖。", "天光上下青浮岸。", "归去画楼烟暝晚。", "步拾梅英，点缀宫妆面。", "美目碧长眉翠浅。", "消魂正值回头看。"]'),
('song-ci-124','蝶恋花','王之道','宋','宋词','song-ci','蝶恋花','[]','檐溜潺潺朝复暮。',70,'宋词/ci.song.6000.json','["檐溜潺潺朝复暮。", "燕子衔泥，穿幕来还去。", "素锦青袍知有处。", "花光草色迷汀渚。", "春不负人人自负。", "君看流觞，只恁良宵度。", "厌浥小桃如泣诉。", "东风莫漫飘红雨。"]'),
('song-ci-125','蝶恋花','王之道','宋','宋词','song-ci','蝶恋花','[]','城上春旗催日暮。',70,'宋词/ci.song.6000.json','["城上春旗催日暮。", "柳絮沾泥，花蕊随流去。", "记得前时行乐处。", "小桥水渌初平渚。", "玉子纹楸谁胜负。", "不道光阴，暗向闲中度。", "天若有情容我诉。", "春来底事多阴雨。"]'),
('song-ci-126','蝶恋花','王之道','宋','宋词','song-ci','蝶恋花','[]','庭院雨馀秋意晚。',70,'宋词/ci.song.6000.json','["庭院雨馀秋意晚。", "一阵风来，到处清香遍。", "把酒对花情不浅。", "花前敢避金杯满。", "薝卜酴醿虽惯见。", "常恨搀先，不是君徒伴。", "莫把龙涎轻斗远。", "流芳肯逐炉烟断。"]'),
('song-ci-127','蝶恋花','王之道','宋','宋词','song-ci','蝶恋花','[]','碧雾暗消香篆半。',70,'宋词/ci.song.6000.json','["碧雾暗消香篆半。", "花影穿帘，厌浥苍苔院。", "鸂鶒一双塘水暖。", "浮沈时近垂杨岸。", "雨过不知春事晚。", "但怪朱唇，得酒红潮面。", "野蔌山肴三四盏。", "携尊更向花前看。"]'),
('song-ci-128','蝶恋花','王之道','宋','宋词','song-ci','蝶恋花','[]','玉子纹楸频较路。',70,'宋词/ci.song.6000.json','["玉子纹楸频较路。", "胜负等闲，休冶黄金注。", "黑白斑斑乌间鹭。", "明窗净几谁知处。", "逼剥声中人不语。", "见可知难，步武来还去。", "何日挂冠宫一亩。", "相从识取棋中趣。"]'),
('song-ci-129','蝶恋花','王之道','宋','宋词','song-ci','蝶恋花','[]','曾向水边云外见。',70,'宋词/ci.song.6000.json','["曾向水边云外见。", "争似霜蕤，照映苍苔院。", "檀口半开金袅线。", "端相消得纶巾岸。", "点缀南枝红旋旋。", "准拟杯盘，日向花前宴。", "飞雪飘飘云不卷。", "何人览镜凭阑看。"]'),
('song-ci-130','蝶恋花','王之道','宋','宋词','song-ci','蝶恋花','[]','杏靥桃腮俱有靦。',70,'宋词/ci.song.6000.json','["杏靥桃腮俱有靦。", "常避孤芳，独斗红深浅。", "犯雪凌霜芳意展。", "玉容似带春寒怨。", "分得数枝来小院。", "依倚铜瓶，标致能清远。", "淡月帘栊疏影转。", "骚人为尔柔肠断。"]'),
('song-ci-131','蝶恋花','王之道','宋','宋词','song-ci','蝶恋花','[]','寒雨霏霏江上路。',70,'宋词/ci.song.6000.json','["寒雨霏霏江上路。", "不见书邮，病目空凝注。", "沙觜尽头飞白鹭。", "篙师指似人来处。", "自笑自怜还自语。", "钝滞如君，只合归田去。", "竹屋数间环甽亩。", "个中自有无穷趣。"]'),
('song-ci-132','宴山亭・燕山亭','王之道','宋','宋词','song-ci','宴山亭・燕山亭','[]','微雨斑斑，晕湿海棠，渐觉燕脂红褪。',123,'宋词/ci.song.6000.json','["微雨斑斑，晕湿海棠，渐觉燕脂红褪。", "迟日短垣，娇怯和风，摇曳一成春困。", "玉软酴酥，扶不起、晚妆慵整。", "愁恨。", "对佳时媚景，可堪重省。", "曾约小桃新燕，有蜂媒蝶使，为传芳信。", "西蜀杜郎，东坡苏老，道也道应难尽。", "一朵风流，雅称且、凤翘云鬓。", "相映。", "眉拂黛、梅腮弄粉。"]'),
('song-ci-133','风流子','王之道','宋','宋词','song-ci','风流子','[]','扁舟南浦岸，分携处、鸣佩忆珊珊。',136,'宋词/ci.song.6000.json','["扁舟南浦岸，分携处、鸣佩忆珊珊。", "见十里长堤，数声啼鴂，至今清泪，襟袖斓斑。", "谁信道，沈腰成瘦减，潘鬓就衰残。", "漫把酒临风，看花对月，不言拄笏，无绪凭阑。", "相逢复相感，但凝情秋水，送恨春山。", "应念马催行色，泥溅征衫。", "况芳菲将过，红英婉娩，追随正乐，黄鸟间关。", "争得此心无著，浑似云闲。"]'),
('song-ci-134','玉连环・解连环','王之道','宋','宋词','song-ci','玉连环・解连环','[]','流水细通何处。',55,'宋词/ci.song.6000.json','["流水细通何处。", "柳溪新雨。", "清风十里送篮舆，行不尽、山无数。", "一簇楼台窣堵。", "老僧常住。", "悬知俗客不曾来，门外苍苔如许。"]'),
('song-ci-135','江城子','王之道','宋','宋词','song-ci','江城子','[]','新篁初上箨龙陂。',86,'宋词/ci.song.6000.json','["新篁初上箨龙陂。", "绿阴稀。", "绿阴稀。", "墙外石榴，花放两三枝。", "裙褶绛纱还半皱，追往事，惜佳期。", "流莺娇婉燕双飞。", "雨晴时。", "雨晴时。", "卢橘攒金，梅子更红肥。", "浊酒一杯从径醉，家纵远，梦中归。"]'),
('song-ci-136','江城子','王之道','宋','宋词','song-ci','江城子','[]','寒光凌乱六花纤。',86,'宋词/ci.song.6000.json','["寒光凌乱六花纤。", "巧穿帘。", "不鸣檐。", "十里黄垆，遥望辨青帘。", "玉树参差何处觅，吟雪曲，拈霜髯。", "坐来令我看无厌。", "拟名盐。", "试尝甜。", "飞入深潭，应照老蛟潜。", "三白频占来岁稔，良可喜，更何嫌。"]'),
('song-ci-137','水调歌头','王之道','宋','宋词','song-ci','水调歌头','[]','颢气遍寰宇，风露逼衣裘。',114,'宋词/ci.song.6000.json','["颢气遍寰宇，风露逼衣裘。", "中秋昨夜，明月千里满西楼。", "人道当年今日，海上骑鲸仙客，乘兴下瀛州。", "雅志在扶世，来佐紫宸游。", "庙堂上，须早计，要嘉谋。", "牙床锦帐，三岁江北叹淹留。", "好在蟹螯如臂，判取兵厨百斛，与客醉瑶舟。", "待得蟠桃熟，相约访浮丘。"]'),
('song-ci-138','水调歌头','王之道','宋','宋词','song-ci','水调歌头','[]','湖上有佳色，黄菊傲霜秋。',114,'宋词/ci.song.6000.json','["湖上有佳色，黄菊傲霜秋。", "一尊相属，谈咏彼此得无愁。", "何处鲈鱼初荐，错俎金齑点脍，令我忆东州。", "双鹭带斜日，飞下白苹洲。", "晚风劲，吹残酒，袭破裘。", "故人俱在，江左底事独淹留。", "归去草堂侵夜，一点青荧灯火，得句可忘忧。", "欲识无穷意，终日倚城楼。"]'),
('song-ci-139','水调歌头','王之道','宋','宋词','song-ci','水调歌头','[]','斜阳明薄暮，暗雨霁凉秋。',117,'宋词/ci.song.6000.json','["斜阳明薄暮，暗雨霁凉秋。", "弱云狼藉，晚来风起，席卷更无留。", "天外老蟾高挂，皎皎寒光照水，金璧共沈浮。", "宾主一时杰，倾动庾公楼。", "渡银汉，漙玉露，势欲流。", "不妨吟赏，坐拥红袖舞还讴。", "暗祝今宵素魄，助我清才逸气，稳步上瀛洲。", "欲识瀛洲路，雄据六鳌头。"]'),
('song-ci-140','水调歌头','王之道','宋','宋词','song-ci','水调歌头','[]','琼树挂初日，珠箔卷清霜。',114,'宋词/ci.song.6000.json','["琼树挂初日，珠箔卷清霜。", "夜来溪上微雨，佳节过重阳。", "共庆当年此际，曾见天麟协梦，华阀挂蓬桑。", "人作鲁侯祝，俾尔寿而臧。", "保疲瘵，旌德善，致吉祥。", "会看报政，朝夕芝检趣徵黄。", "不藉灵丹九转，不用蟠桃三窃，源远自流长。", "愿借沧溟富，斟酌荐瑶觞。"]'),
('song-ci-141','水调歌头','王之道','宋','宋词','song-ci','水调歌头','[]','败屋拥破衲，惊飙漫飕飔。',114,'宋词/ci.song.6000.json','["败屋拥破衲，惊飙漫飕飔。", "不离当处人见，操慧上蓝游。", "弹指九州四海，浪说其来云聚，其去等风休。", "莫作袈裟看，吾道惯聃丘。", "齐死生，同宠辱，泯春秋。", "高名厚利，眇若天地一蜉蝣。", "闲举前人公案，试问把锄空手，何似步骑牛。", "会得个中语，净土在阎浮。"]'),
('song-ci-142','水调歌头','王之道','宋','宋词','song-ci','水调歌头','[]','暑雨湿修竹，凉吹入高檐。',114,'宋词/ci.song.6000.json','["暑雨湿修竹，凉吹入高檐。", "鹭洲锺阜如画，霁色为秾纤。", "槛外藕花无数，妆点休祥嘉应，不觉有秋炎。", "谪仙堕人世，香雾郁重帘。", "富才艺，强记览，三万签。", "须信公侯有种，道义自相渐。", "此去腰金佩玉，回视依莲泛水，岁月亦何淹。", "称觞还戏彩，无惜醉厌厌。"]'),
('song-ci-143','青玉案','王之道','宋','宋词','song-ci','青玉案','[]','金尊照坐红裙绕。',81,'宋词/ci.song.6000.json','["金尊照坐红裙绕。", "怪一饷、歌声悄。", "乱扑珠帘风絮晓。", "香薰笑语，酒烘颜色，莫逐流年老。", "诗涛入笔悬河倒。", "快万里云天为君扫。", "检点春容何处早。", "柳条青眼，梅梢粉面，得恁於人好。"]'),
('song-ci-144','青玉案','王之道','宋','宋词','song-ci','青玉案','["\u897f\u6e56"]','逢人借问钱塘路。',80,'宋词/ci.song.6000.json','["逢人借问钱塘路。", "我亦欲、西湖去。", "目送兰桡知几度。", "鳌峰浮玉，鲸波飞雪，正是潮来处。", "海棠花下春将暮。", "缓唱新词味佳句。", "见说东君曾梦许。", "柏台冠豸，金銮视草，便作商岩雨。"]'),
('song-ci-145','青玉案','王之道','宋','宋词','song-ci','青玉案','[]','半年不踏轩车路。',80,'宋词/ci.song.6000.json','["半年不踏轩车路。", "仿佛过、长桥去。", "贴水行云风送度。", "两行高柳，一坡修竹，是我尝游处。", "黄鹂休叹青春暮。", "出谷迁乔旧家句。", "天意从人还许诉。", "凝寒和气，沈阴霁色，大旱滂沱雨。"]'),
('song-ci-146','凤箫吟・芳草','王之道','宋','宋词','song-ci','凤箫吟・芳草','[]','雨溟濛。',124,'宋词/ci.song.6000.json','["雨溟濛。", "年年今日，农夫共卜新丰。", "登高随处好，银瓶突兀，南峙对三公。", "真珠漙露菊，更芙蓉、照水匀红。", "但华发衰颜，不堪频鉴青铜。", "相逢。", "行藏休借问，且徘徊、目送飞鸿。", "十年湖海，千里云山，几番残照凄风。", "蟹螯粗似臂，金英碎、琥珀香浓。", "请细读离骚，为君一饮千锺。"]'),
('song-ci-147','谒金门','曹勋','宋','宋词','song-ci','谒金门','[]','春待去。',53,'宋词/ci.song.6000.json','["春待去。", "帘外连天飞絮。", "老大心情慵纵步。", "草迷池上路。", "春去不知何处。", "欲问谁能分付。", "但有清阴遮院宇。", "晚莺和暮雨。"]'),
('song-ci-148','玉楼春','曹勋','宋','宋词','song-ci','玉楼春','[]','昔年曾到神清洞。',64,'宋词/ci.song.6000.json','["昔年曾到神清洞。", "笑领希夷非夙梦。", "看时须到月边乌，养处且论铅与汞。", "土膏仍有黄芽动。", "神水浇香灵气种。", "夜深谁伴玉琴闲，鹤在九华松露重。"]'),
('song-ci-149','饮马歌','曹勋','宋','宋词','song-ci','饮马歌','[]','边头春未到。',42,'宋词/ci.song.6000.json','["边头春未到。", "雪满交河道。", "暮沙明残照。", "塞烽云间小。", "断鸿悲。", "陇月低。", "泪湿征衣悄。", "岁华老。"]'),
('song-ci-150','长寿仙促拍','曹勋','宋','宋词','song-ci','长寿仙促拍','[]','舜德日辉光，正初冬盛期。',91,'宋词/ci.song.6000.json','["舜德日辉光，正初冬盛期。", "东朝喜、诞生时。", "向彤闱、清净均化有，自然和气。", "长生久视，金殿熙熙。", "宴瑶池。", "褘衣俱侍、玳筵启。", "花如锦、耀朝晖。", "太平际天子，天下养、共瞻诚意。", "南山虔祝，亿万同岁。"]'),
('song-ci-151','长寿仙促拍','曹勋','宋','宋词','song-ci','长寿仙促拍','[]','绛阙岹嶢，正春光到时。',92,'宋词/ci.song.6000.json','["绛阙岹嶢，正春光到时。", "当人日、诞芳仪。", "向宫壶、雅著徽誉美，懿德无亏。", "深被恩荣，金殿宴嬉。", "气融怡。", "贤均樛木，宜颂二南诗。", "天心喜、锦筵启。", "阖部奏笙箫，祝寿处、愿与山齐。", "年年常奉，明主禁掖。"]'),
('song-ci-152','浣溪沙','曹勋','宋','宋词','song-ci','浣溪沙','[]','西苑烟光倚槛新。',48,'宋词/ci.song.6000.json','["西苑烟光倚槛新。", "桃花艳艳静无尘。", "照溪红映一天云。", "肯放落红流出水，且寻歌舞赏明春。", "持杯知是洞中人。"]'),
('song-ci-153','浣溪沙','曹勋','宋','宋词','song-ci','浣溪沙','[]','日上龙城散晓阴。',48,'宋词/ci.song.6000.json','["日上龙城散晓阴。", "琼芳堂下玉成林。", "江梅开未十分深。", "随处锦亭穹帐暖，冷香邀住入衣襟。", "酒肠判断付频斟。"]'),
('song-ci-154','酒泉子','曹勋','宋','宋词','song-ci','酒泉子','[]','连面霜风。',53,'宋词/ci.song.6000.json','["连面霜风。", "野馆山村逢至日，开怀欲殢酒杯空。", "与谁同。", "一缄来信托飞鸿。", "信里催归无限意，黄昏应是出房栊。", "夜香浓。"]'),
('song-ci-155','诉衷情','曹勋','宋','宋词','song-ci','诉衷情','[]','人情世态饱经过。',54,'宋词/ci.song.6000.json','["人情世态饱经过。", "眼也见来多。", "忙中掉得便去，不是有人唆。", "云似舞，水如歌。", "笑呵呵。", "这回还我，半世偎绥，一味磨跎。"]'),
('song-ci-156','诉衷情','曹勋','宋','宋词','song-ci','诉衷情','[]','得抽头处好抽头。',54,'宋词/ci.song.6000.json','["得抽头处好抽头。", "等待几时休。", "贤且广张四至，我早已优游。", "黄道服，布钱绉。", "煞风流。", "往来熟后，也没惊怕，也没忧愁。"]'),
('song-ci-157','朝中措','曹勋','宋','宋词','song-ci','朝中措','[]','酴醿芳架引繁英。',57,'宋词/ci.song.6000.json','["酴醿芳架引繁英。", "香远透帘清。", "更与洛阳花市，一齐移在宫庭。", "琉璃万朵，娇红嫩紫，总是嘉名。", "殿阁真仙同赏，天颜喜入欢声。"]'),
('song-ci-158','朝中措','曹勋','宋','宋词','song-ci','朝中措','[]','斜斜整整暗江湾。',57,'宋词/ci.song.6000.json','["斜斜整整暗江湾。", "蓑笠有无间。", "应与君家却暑，冷看白满群山。", "想来何处，金炉焰兽，玉斝酡颜。", "好是溪涵寒影，山影一棹人还。"]'),
('song-ci-159','谒金门','曹勋','宋','宋词','song-ci','谒金门','[]','香乍起。',53,'宋词/ci.song.6000.json','["香乍起。", "满院垂垂岩桂。", "未卷珠帘香已至。", "酒杯言笑里。", "叶下茸金繁蕊。", "别是清妍风致。", "更远随人闻细细。", "月华天似水。"]'),
('song-ci-160','谒金门','曹勋','宋','宋词','song-ci','谒金门','[]','春渐至。',53,'宋词/ci.song.6000.json','["春渐至。", "雪染梅梢轻细。", "试路新芜殊可喜。", "冷云闲照水。", "白苎今年不寄。", "最好且寻幽会。", "不怕清寒侵紫绮。", "看灯同晚醉。"]'),
('song-ci-161','玉蹀躞・解蹀躞','曹勋','宋','宋词','song-ci','玉蹀躞・解蹀躞','[]','雨过池台秋静，桂影凉清昼。',90,'宋词/ci.song.6000.json','["雨过池台秋静，桂影凉清昼。", "槁叶喧空，疏黄满堤柳。", "风外残菊枯荷，凭阑一饷，犹喜冷香襟袖。", "少欢偶。", "人道消愁须酒。", "酒又怕醒后。", "这般光景，愁怀煞难受。", "谁念千种秋情，乍凉虽好，还恨夜长时候。"]'),
('song-ci-162','水调歌头','曹勋','宋','宋词','song-ci','水调歌头','[]','江影浮空阔，江水拍天流。',114,'宋词/ci.song.6000.json','["江影浮空阔，江水拍天流。", "山藏地秘，伟观须是伟人收。", "闻道烟斜雨暗，还留月底风边，墨客一凝眸。", "阑槛随指顾，江海还生秋。", "绣帘卷，开绮宴，翠香浮。", "邹枚宾从俱咏，韵闲出嘉谋。", "点点群山吴楚，历历三州灯火，潮落没沙鸥。", "老子会心处，应已付南楼。"]'),
('song-ci-163','醉思仙','曹勋','宋','宋词','song-ci','醉思仙','[]','记华堂。',113,'宋词/ci.song.6000.json','["记华堂。", "对宝台绛蜡，红艳成行。", "亸乌云髻映，浅浅宫妆。", "江梅媚，生嫩脸，莹素质，自有清香。", "歌喉稳，按镂版缓拍，娇倚银床。", "天外行云驻，轻尘暗落雕梁。", "似晓莺历历，琼韵锵锵。", "别来久，春将老，但梦里、也思量。", "仗何人，细说与，为伊潘鬓成霜。"]'),
('song-ci-164','江神子・江城子','曹勋','宋','宋词','song-ci','江神子・江城子','[]','南丰诗将驻灵江。',86,'宋词/ci.song.6000.json','["南丰诗将驻灵江。", "下明光。", "惹天香。", "十雨五风，连岁致丰穰。", "初夏清和才四日，开寿席、宴华堂。", "严宸已奏二南章。", "眷循良。", "比龚黄。", "玉笋班联，宜冠紫微郎。", "从此锋车宣室召，摅相业、寿而康。"]'),
('song-ci-165','满庭芳','曹勋','宋','宋词','song-ci','满庭芳','[]','老不求名，心惟耽静，旧缘历过艰难。',118,'宋词/ci.song.6000.json','["老不求名，心惟耽静，旧缘历过艰难。", "杜门无事，一味放痴顽。", "只藉炉香上彻，与天地、平直交关。", "真人喜，扶晨遣客，时暂下仙班。", "矜怜。", "身已病，九疑夙驾，来顾台山。", "看神超清境，玉炼朱颜。", "为向芝田桂圃，收妙有、与作真丹。", "他年报，冲融朝礼，香火紫云间。"]'),
('song-ci-166','满庭芳','曹勋','宋','宋词','song-ci','满庭芳','[]','秋色澄晖，蟾波增莹，桂华宫殿香凝。',118,'宋词/ci.song.6000.json','["秋色澄晖，蟾波增莹，桂华宫殿香凝。", "夜凉天半，横管度新声。", "应是齐吹万指，岩谷震、石裂霜清。", "天如水，飞云散尽，江月照还明。", "人间，何处有，祥风缓引，飘下层城。", "想广寒光冷，妙舞轻盈。", "愿上君王万寿，空伫忆、酒海吞鲸。", "归来也，惊涛隐隐，馀韵入青冥。"]'),
('song-ci-167','武陵春','曹勋','宋','宋词','song-ci','武陵春','[]','今岁重阳经闰早，金蕊粲繁枝。',56,'宋词/ci.song.6000.json','["今岁重阳经闰早，金蕊粲繁枝。", "玉殿珠楼步辇随。", "高兴在东篱。", "且泛金英同潋滟，休与傲霜期。", "只恐秋香一夜衰。", "须插满头归。"]'),
('song-ci-168','武陵春','曹勋','宋','宋词','song-ci','武陵春','[]','玉露金风寻胜去，一月看三州。',56,'宋词/ci.song.6000.json','["玉露金风寻胜去，一月看三州。", "红叶黄花满意秋。", "真是巧装愁。", "我在天台山下住，松菊占深幽。", "归趁梅花映小楼。", "应问久迟留。"]'),
('song-ci-169','武陵春','曹勋','宋','宋词','song-ci','武陵春','[]','惨惨江云浑不动，玉雪耿孤芳。',56,'宋词/ci.song.6000.json','["惨惨江云浑不动，玉雪耿孤芳。", "萼绿仙人带暗香。", "风韵冷尤长。", "陇信不来寒日晚，疏影照澄江。", "肯借横斜伴酒觞。", "应共月商量。"]'),
('song-ci-170','武陵春','曹勋','宋','宋词','song-ci','武陵春','[]','春到小园春草绿，烟雨湿云山。',56,'宋词/ci.song.6000.json','["春到小园春草绿，烟雨湿云山。", "池上梅花已半残。", "无奈晚来寒。", "不怕醉多只怕醒，花影上阑干。", "人在东风缥缈间。", "谁与伴幽闲。"]'),
('song-ci-171','玉楼春','曹勋','宋','宋词','song-ci','玉楼春','[]','九重盛旦薰风候。',64,'宋词/ci.song.6000.json','["九重盛旦薰风候。", "佳气氛氲横永昼。", "眉心烟彩拥群仙，华宴重开同圣后。", "箫韶宫殿锵金奏。", "香绕祥云腾宝兽。", "三千嫔御奉严宸，亿万斯年祈圣寿。"]'),
('song-ci-172','玉楼春','曹勋','宋','宋词','song-ci','玉楼春','[]','佳时莫放游鞍倦。',64,'宋词/ci.song.6000.json','["佳时莫放游鞍倦。", "梅润清薰随处宴。", "不妨一半雨兼风，况对有情莺与燕。", "琼艘百柁花千点。", "肯使笙歌容易转。", "兴来人事酒消磨，谁问蚊雷和蚁战。"]'),
('song-ci-173','浪淘沙','曹勋','宋','宋词','song-ci','浪淘沙','[]','归意逐飞鸿。',64,'宋词/ci.song.6000.json','["归意逐飞鸿。", "点点书空。", "爱渠南去晓烟中。", "不似老人尘土里，一似痴聋。", "庭院晚来风。", "还过秋客。", "旧时与客绕珍丛。", "有酒不曾无客醉，欢与秋浓。"]'),
('song-ci-174','浪淘沙','曹勋','宋','宋词','song-ci','浪淘沙','[]','秋杪喜新凉。',64,'宋词/ci.song.6000.json','["秋杪喜新凉。", "烟淡池塘。", "团团岩桂作风光。", "多少水云萧散意，都付芬芳。", "雨逐漏声长。", "小院回廊。", "枕边清梦几悠扬。", "只恐四檐声未断，洗褪幽香。"]'),
('song-ci-175','鹧鸪天','曹勋','宋','宋词','song-ci','鹧鸪天','["\u6d1e\u5ead\u6e56"]','枫落吴江肃晓霜。',64,'宋词/ci.song.6000.json','["枫落吴江肃晓霜。", "洞庭波静耿云光。", "芳苞照眼黄金嫩，纤指开新白玉香。", "盐胜雪，喜初尝。", "微酸历齿助新妆。", "直须满劝三山酒，更喜持杯云水乡。"]'),
('song-ci-176','鹧鸪天','曹勋','宋','宋词','song-ci','鹧鸪天','[]','准拟中秋快客情。',64,'宋词/ci.song.6000.json','["准拟中秋快客情。", "新亭雨后喜登临。", "彩蟾特地中宵出，吹散层云十日阴。", "松露重，月烟深。", "祥云捧玉到天心。", "金波动是经年别，为酌金荷醉碧琳。"]'),
('song-ci-177','鹧鸪天','曹勋','宋','宋词','song-ci','鹧鸪天','[]','曾到东风最上头。',64,'宋词/ci.song.6000.json','["曾到东风最上头。", "低云阁雨接溪流。", "只应缟袂闺房秀，尚带天香汗漫游。", "当日暇，从贤侯。", "冲寒迎翠小迟留。", "归骖白凤来何处，更指玉霄城畔楼。"]'),
('song-ci-178','鹧鸪天','曹勋','宋','宋词','song-ci','鹧鸪天','[]','雪后疏香一两枝。',64,'宋词/ci.song.6000.json','["雪后疏香一两枝。", "高轩乘兴访春时。", "金蕉酌酒应须醉，玉指传觞岂易辞。", "嗟老大，喜追随。", "南楼宵漏任迟迟。", "已闻水部神仙语，更诵骑鲸短李诗。"]'),
('song-ci-179','好事近','曹勋','宋','宋词','song-ci','好事近','[]','花动两山春，绿绕翠围时节。',53,'宋词/ci.song.6000.json','["花动两山春，绿绕翠围时节。", "雨涨晓来湖面，际天光清彻。", "移尊兰棹压深波，歌吹与尘绝。", "应向断云浓淡，见湖山真色。"]'),
('song-ci-180','好事近','曹勋','宋','宋词','song-ci','好事近','[]','密密偃蜂房，香远未应时霎。',53,'宋词/ci.song.6000.json','["密密偃蜂房，香远未应时霎。", "薇露紫烟浥尽，任风欺雪压。", "老人曾饮百川空，相对肯微呷。", "揽取占先风度，醉高烧红蜡。"]'),
('song-ci-181','好事近','曹勋','宋','宋词','song-ci','好事近','[]','潮尽海波平，赏尽绿烟凉月。',53,'宋词/ci.song.6000.json','["潮尽海波平，赏尽绿烟凉月。", "罗袂乍迎风快，悄喜欢不彻。", "一年好处记如今，朝暮更无热。", "庭院晚来些雨，是开尊时节。"]'),
('song-ci-182','胜胜慢・声声慢','曹勋','宋','宋词','song-ci','胜胜慢・声声慢','[]','素商吹景，西真赋巧，桂子秋借蟾光。',117,'宋词/ci.song.6000.json','["素商吹景，西真赋巧，桂子秋借蟾光。", "层层翠葆，深隐幽艳清香。", "占得秀岩分种，天教薇露染娇黄。", "珍庭晓，透肌破鼻，细细芬芳。", "应是月中倒影，喜馀叶婆娑，灏色迎凉。", "移根上苑，雅称曲槛回廊。", "趁取蕊珠密缀，与收花雾著宫裳。", "帘栊静，好围四坐，对赏瑶觞。"]'),
('song-ci-183','一剪梅・一翦梅','曹勋','宋','宋词','song-ci','一剪梅・一翦梅','[]','不占前村占宝阶。',68,'宋词/ci.song.6000.json','["不占前村占宝阶。", "芳影横斜积渐开。", "水边竹外冷摇春，一带冲寒，香满襟怀。", "管领东风要有才。", "频携歌酒上春台。", "直须日日玉花前，金殿仙人，同赏同来。"]'),
('song-ci-184','御街行','曹勋','宋','宋词','song-ci','御街行','[]','凌寒架雪知春近。',92,'宋词/ci.song.6000.json','["凌寒架雪知春近。", "闲探处、如相问。", "溪流清浅暮云低，玉蓓横斜风定。", "晚枝雀啅，幽姿方展，还映疏篁冷。", "镜鸾妆罢明梢嫩。", "犹记宜相并。", "如今却月别传香，知引何人幽兴。", "不堪楼上，昭华吹断，声与愁肠尽。"]'),
('song-ci-185','行香子','曹勋','宋','宋词','song-ci','行香子','[]','也爱休官。',84,'宋词/ci.song.6000.json','["也爱休官。", "也爱清闲。", "谢神天、教我愚顽。", "眼前万事，都不相干。", "访好林峦。", "好洞府，好溪山。", "日月如盘。", "缺又还圆。", "自然他、虎踞龙蟠。", "河东上下，一撞三关。", "看也非悭。", "也非易，也非难。"]'),
('song-ci-186','蓦山溪','曹勋','宋','宋词','song-ci','蓦山溪','[]','乌龙云洞，神护红尘外。',102,'宋词/ci.song.6000.json','["乌龙云洞，神护红尘外。", "金鼎养丹砂，有仙卿、清修名世。", "三千功行，活字少人知，松露閟，紫烟深，知是聃翁裔。", "吹箫后约，岂慕穿青紫。", "八十在人间，比当日、何须指李。", "相逢一笑，酒量海同宽，拔宅隐，玉霄寒，升举应新岁。"]'),
('song-ci-187','千秋岁','曹勋','宋','宋词','song-ci','千秋岁','[]','洞房秀韵，结绮临春后。',87,'宋词/ci.song.6000.json','["洞房秀韵，结绮临春后。", "都压尽，名花柳。", "锦堂笼翡翠，璨枕同清昼。", "谁似得，佳时占断长欢偶。", "我昔闻名久。", "欲见成消瘦。", "寻不遇，空回首。", "征途难驻马，坐想冰姿秀。", "凭寄语，南归更趁酴醿酒。"]'),
('song-ci-188','水龙吟','曹勋','宋','宋词','song-ci','水龙吟','[]','冻云阁雨，长风送雪，万里无凝滞。',127,'宋词/ci.song.6000.json','["冻云阁雨，长风送雪，万里无凝滞。", "斜斜整整，纯白入素，应同太始。", "袁巷萧条，冷光寒透，有人曾至。", "但圆虚上下，澄明莹洁，如□□、混元气。", "时听松篁泻坠。", "任山川、珠联玉缀。", "一尘不染，一毫不现，真空妙治。", "祥应三白，润归多稼，已成丰岁。", "待收拾大翁，茶盐贺喜，兴村东醉。"]'),
('song-ci-189','念奴娇','曹勋','宋','宋词','song-ci','念奴娇','[]','烘帘昼暖，正飞花堆锦，风迟烟暮。',120,'宋词/ci.song.6000.json','["烘帘昼暖，正飞花堆锦，风迟烟暮。", "绿叶成阴春又老，甲子谁能重数。", "梅已青圆，雪深犹记，曾拈疏枝否。", "须知物外，这些光景常驻。", "闻道江水东头，同门相过，不作儿女语。", "醉墨凌波歌数阕，心迹都忘逆旅。", "胸次扶摇，壶中光景，肯与人同趣。", "栖尘功就，浩然俱待飞去。"]'),
('song-ci-190','念奴娇','曹勋','宋','宋词','song-ci','念奴娇','[]','半阴未雨，洞房深、门掩清润芳晨。',122,'宋词/ci.song.6000.json','["半阴未雨，洞房深、门掩清润芳晨。", "古鼎金炉，烟细细、飞起一缕轻云。", "罗绮娇春。", "争拢翠袖，笑语惹兰芬。", "歌筵初罢，最宜斗帐黄昏。", "楼上念远佳人。", "心随沈水，学兰灺俱焚。", "事与人非，争似此、些子香气常存。", "记得临分。", "罗巾馀赠，尽日把浓熏。", "一回开看，一回肠断重闻。"]'),
('song-ci-191','沁园春','曹勋','宋','宋词','song-ci','沁园春','[]','浓绿交阴，脆圆经雨，夏景正新。',139,'宋词/ci.song.6000.json','["浓绿交阴，脆圆经雨，夏景正新。", "遽紫泥封检，红幢建钺，飘然吹起，一片闲云。", "禁殿趋班，玉音亲诏，并遣皇华通宝邻。", "凌歊去，任重霄温暑，万里风薰。", "炎曦正斡天钧。", "更午气均齐天地根。", "运至精感化，千和万合，涤堤旁说，必自成真。", "已约归期，秋风前后，梨枣黄花满地匀。", "阊阖晚，待朝元紫府，上达明君。"]'),
('song-ci-192','菩萨蛮','曹勋','宋','宋词','song-ci','菩萨蛮','[]','稽山鉴水无寒暑。',52,'宋词/ci.song.6000.json','["稽山鉴水无寒暑。", "荷香莲露相倾注。", "堂拟揖樵风。", "山围晚照红。", "桃根随秀叶。", "玉麈频招客。", "客况不言蓬。", "回船逸兴同。"]'),
('song-ci-193','菩萨蛮','曹勋','宋','宋词','song-ci','菩萨蛮','[]','萧萧还是秋容暮。',52,'宋词/ci.song.6000.json','["萧萧还是秋容暮。", "炉薰已冷氲香注。", "犹记踏香尘。", "东风满院春。", "冷烟迷望处。", "声断阑干雨。", "无计问行云。", "黄昏空掩门。"]'),
('song-ci-194','菩萨蛮','曹勋','宋','宋词','song-ci','菩萨蛮','[]','花飞零乱随风舞。',52,'宋词/ci.song.6000.json','["花飞零乱随风舞。", "花梢犹带虚檐雨。", "帘幕映黄昏。", "江天日暮云。", "有人楼上望。", "生怕褰虚幌。", "冷落对炉薰。", "一春常怨春。"]'),
('song-ci-195','菩萨蛮','曹勋','宋','宋词','song-ci','菩萨蛮','[]','等闲将度三春景。',52,'宋词/ci.song.6000.json','["等闲将度三春景。", "景春三度将闲等。", "愁怕更高楼。", "楼高更怕愁。", "弄花梅已动。", "动已梅花弄。", "梅看几年催。", "催年几看梅。"]'),
('song-ci-196','菩萨蛮','曹勋','宋','宋词','song-ci','菩萨蛮','[]','雨昏连夜催炎暑。',52,'宋词/ci.song.6000.json','["雨昏连夜催炎暑。", "暑炎催夜连昏雨。", "长簟水波凉。", "凉波水簟长。", "翠鬟双倚醉。", "醉倚双鬟翠。", "香枕印红妆。", "妆红印枕香。"]'),
('song-ci-197','菩萨蛮','曹勋','宋','宋词','song-ci','菩萨蛮','[]','玉珰摇素腰如束。',52,'宋词/ci.song.6000.json','["玉珰摇素腰如束。", "束如腰素摇珰玉。", "宜更醉春期。", "期春醉更宜。", "绣鸳闲永昼。", "昼永闲鸳绣。", "归念不曾稀。", "稀曾不念归。"]'),
('song-ci-198','清平乐','曹勋','宋','宋词','song-ci','清平乐','[]','秋凉破暑。',54,'宋词/ci.song.6000.json','["秋凉破暑。", "暑气迟迟去。", "最喜连日风和雨。", "断送凉生庭户。", "晚来灯火回廊。", "有人新酒初尝。", "且喜薄衾围暖，却愁秋月如霜。"]'),
('song-ci-199','清平乐','曹勋','宋','宋词','song-ci','清平乐','[]','一春老病。',54,'宋词/ci.song.6000.json','["一春老病。", "空过春光永。", "药鼎煎炉朝暮景。", "只是医方药性。", "经旬日色云遮。", "山高寒透窗纱。", "常恨檐头倾雨，犹能枕上看花。"]'),
('song-ci-200','清平乐','曹勋','宋','宋词','song-ci','清平乐','[]','赵家燕燕。',54,'宋词/ci.song.6000.json','["赵家燕燕。", "宜在昭阳殿。", "春入馆娃深宫宴。", "秀色从来未见。", "浅颦轻笑都宜。", "临风好是腰肢。", "今夜松江归路，月明愁满清辉。"]'),
('song-ci-201','点绛唇','曹勋','宋','宋词','song-ci','点绛唇','[]','怯雨羞云，翠鬟初按檀槽就。',50,'宋词/ci.song.6000.json','["怯雨羞云，翠鬟初按檀槽就。", "赏心时候。", "常劝花间酒。", "慢拈轻拢，怨感随纤手。", "胡沙奏。", "几行红袖。", "都道谁家有。"]'),
('song-ci-202','点绛唇','曹勋','宋','宋词','song-ci','点绛唇','[]','不厌频来，探梅选胜湖山里。',50,'宋词/ci.song.6000.json','["不厌频来，探梅选胜湖山里。", "瑶林琼蕊。", "真是游方外。", "玉殿珠楼，不并人间世。", "何妨醉。", "都无寒意。", "满坐惟和气。"]'),
('song-ci-203','点绛唇','曹勋','宋','宋词','song-ci','点绛唇','[]','有个庵儿，做来不大元非小。',50,'宋词/ci.song.6000.json','["有个庵儿，做来不大元非小。", "阳光常照。", "坐卧谁知道。", "炼得丹砂，不是人间灶。", "冲和妙。", "鹤鸣猿啸。", "一任西风老。"]'),
('song-ci-204','点绛唇','曹勋','宋','宋词','song-ci','点绛唇','[]','一气冲融，浩然识取生缘处。',50,'宋词/ci.song.6000.json','["一气冲融，浩然识取生缘处。", "敛归灵府。", "便作真铅柱。", "九任玄归，行处龙先虎。", "山头雨。", "散成清露。", "玛瑙生玄圃。"]'),
('song-ci-205','点绛唇','曹勋','宋','宋词','song-ci','点绛唇','[]','石洞清寒，柳烟吹散松风静。',50,'宋词/ci.song.6000.json','["石洞清寒，柳烟吹散松风静。", "日华光映。", "翠水环云径。", "道境多闲，不是人间景。", "谈清净。", "道师歌咏。", "花转云房影。"]'),
('song-ci-206','失调名','曹勋','宋','宋词','song-ci','失调名','["\u9ec4\u6cb3"]','自叹孤身早岁，黄河渡口蒙情。',14,'宋词/ci.song.6000.json','["自叹孤身早岁，黄河渡口蒙情。"]'),
('song-ci-207','水调歌头','胡寅','宋','宋词','song-ci','水调歌头','[]','不见严夫子，寂寞富春山。',114,'宋词/ci.song.6000.json','["不见严夫子，寂寞富春山。", "空留千丈危石，高出暮云端。", "想象羊裘披了，一笑两望身世，来插钓鱼竿。", "肯似林间翮，飞倦始知还。", "中兴主，功业就，鬓毛斑。", "驱驰一世人物，相与济时艰。", "独委狂奴心事，未羡痴儿鼎足，放去任疏顽。", "爽气动星斗，终古照林峦。"]'),
('song-ci-208','蓦山溪','吴舜选','宋','宋词','song-ci','蓦山溪','[]','园林何有，修竹摇苍翠。',102,'宋词/ci.song.6000.json','["园林何有，修竹摇苍翠。", "春到小桃蹊，看绿满、一池春水。", "花开日暖，儿侄竞追随，挑野蔌，网溪鱼，有酒多且旨。", "去来聚散，无必亦无意。", "说地或谈天，更休问、语言粗细。", "谁强谁弱，谁是又谁非，过去事，未来事，一枕腾腾睡。"]'),
('song-ci-209','西江月','赵桓','宋','宋词','song-ci','西江月','[]','历代恢文偃武，四方晏粲无虞。',58,'宋词/ci.song.6000.json','["历代恢文偃武，四方晏粲无虞。", "奸臣招致北匈奴。", "边境年年侵侮。", "一旦金汤失守，万邦不救銮舆。", "我今父子在穹庐。", "壮士忠臣何处。"]'),
('song-ci-210','西江月','赵桓','宋','宋词','song-ci','西江月','[]','塞雁嗈嗈南去，高飞难寄音书。',58,'宋词/ci.song.6000.json','["塞雁嗈嗈南去，高飞难寄音书。", "只应宗社已丘墟。", "愿有真人为主。", "岭外云藏晓日，眼前路忆平芜。", "寒沙风紧泪盈裾。", "难望燕山归路。"]'),
('song-ci-211','眼儿媚','赵桓','宋','宋词','song-ci','眼儿媚','[]','宸传三百旧京华。',58,'宋词/ci.song.6000.json','["宸传三百旧京华。", "仁孝自名家。", "一旦奸邪，倾天拆地，忍听琵琶。", "如今在外多萧索，迤逦近胡沙。", "家邦万里，伶仃父子，向晓霜花。"]'),
('song-ci-212','蓦溪山・蓦山溪','刘子翬','宋','宋词','song-ci','蓦溪山・蓦山溪','[]','浮烟冷雨，今日还重九。',102,'宋词/ci.song.6000.json','["浮烟冷雨，今日还重九。", "秋去又秋来，但黄花、年年如旧。", "平台戏马，无处问英雄，茅舍底，竹篱东，伫立时搔首。", "客来何有。", "草草三杯酒。", "一醉万缘空，莫贪伊、金印如斗。", "病翁老矣，谁共赋归来，芟垅麦，网溪鱼，未落他人后。"]'),
('song-ci-213','满庭芳','刘子翬','宋','宋词','song-ci','满庭芳','[]','秋入微阴，凉生平远，小山愁绝天南。',118,'宋词/ci.song.6000.json','["秋入微阴，凉生平远，小山愁绝天南。", "似闻还断，飞策遍千岩。", "叶底轻黄纂纂，恼人是、微裂芳缄。", "け然胜，清真冷淡，无艳寄尘凡。", "澄潭。", "敧两岸，波光摇动，碧影相参。", "任西风十里，吹度松杉。", "我自寒灰槁木，□神处、不觉醺酣。", "归来晚，飞花无迹，明月满空函。"]'),
('song-ci-214','南歌子','刘子翬','宋','宋词','song-ci','南歌子','[]','卜夜容三献，微欢极一时。',62,'宋词/ci.song.6000.json','["卜夜容三献，微欢极一时。", "风流太守未庞眉。", "放出笔头光焰、压金闺。", "藻丽花骈蕊，清高雪亚枝。", "曼声恰与贯珠宜。", "听此直教拚得、醉翻卮。"]'),
('song-ci-215','南歌子','刘子翬','宋','宋词','song-ci','南歌子','[]','伎俩无多子，逍遥自许时。',62,'宋词/ci.song.6000.json','["伎俩无多子，逍遥自许时。", "闲愁且莫著双眉。", "恰有梅香一点、到幽闺。", "宠辱棋翻局，光阴鸟度枝。", "颓然径醉是便宜。", "拟倩潭风吹绿、涨瑶卮。"]'),
('song-ci-216','小重山','何大圭','宋','宋词','song-ci','小重山','[]','绿树莺啼春正浓。',70,'宋词/ci.song.6000.json','["绿树莺啼春正浓。", "钗头青杏小，绿成丛。", "玉船风动酒鳞红。", "歌声咽，相见几时重。", "车马去匆匆。", "路随芳草远，恨无穷。", "相思只在梦魂中。", "今宵月，偏照小楼东。"]'),
('song-ci-217','水调歌头','何大圭','宋','宋词','song-ci','水调歌头','[]','今夕出佳月，银汉泻高寒。',114,'宋词/ci.song.6000.json','["今夕出佳月，银汉泻高寒。", "风缠云卷，转觉天陛玉楼宽。", "疑是金华仙子，又喜经年药就，倾出玉团团。", "收拾江河影，都向镜中蟠。", "横霜笛，吹明影，到中天。", "要令四海瞻望，千古此轮安。", "何岁何年无月，唯有谪仙著语，高绝不能攀。", "我欲唤空起，云海路漫漫。"]'),
('song-ci-218','蝶恋花','何大圭','宋','宋词','song-ci','蝶恋花','[]','鱼尾霞收明远树。',70,'宋词/ci.song.6000.json','["鱼尾霞收明远树。", "翠色黏天，一叶迎风举。", "一笑相逢蓬海路。", "人间风月如尘土。", "翦水双眸云鬓吐。", "醉倒天瓢，笑语生香雾。", "此会未阑须记取。", "蟠桃几度吹红雨。"]'),
('song-ci-219','浣溪沙','胡铨','宋','宋词','song-ci','浣溪沙','[]','忽忽春归没计遮。',48,'宋词/ci.song.6000.json','["忽忽春归没计遮。", "百年都似散馀霞。", "持杯聊听浣溪沙。", "但觉暗添双鬓雪，不知落尽一番花。", "东风寒似夜来些。"]'),
('song-ci-220','转调定风波・定风波','胡铨','宋','宋词','song-ci','转调定风波・定风波','[]','从古将军自有真。',73,'宋词/ci.song.6000.json','["从古将军自有真。", "引杯看剑坐生春。", "扰扰介鳞何足扫。", "谈笑。", "纶巾羽扇典刑新。", "试问天山何日定。", "伫听。", "雅歌长啸静烟尘。", "解道汾阳是人杰。", "见说。", "如今也有谪仙人。"]'),
('song-ci-221','转调二郎神・二郎神','张孝祥','宋','宋词','song-ci','转调二郎神・二郎神','[]','闷来无那，暗数尽、残更不寐。',129,'宋词/ci.song.6000.json','["闷来无那，暗数尽、残更不寐。", "念楚馆香车，吴溪兰棹，多少愁云恨水。", "阵阵回风吹雪霰，更旅雁、一声沙际。", "想静拥孤衾，频挑寒灺，数行珠泪。", "凝睇。", "傍人笑我，终朝如醉。", "便锦织回鸾，素传双鲤，难写衷肠密意。", "绿鬓点霜，玉肌消雪，两处十分憔悴。", "争忍见，旧时娟娟素月，照人千里。"]'),
('song-ci-222','满江红','张孝祥','宋','宋词','song-ci','满江红','[]','秋满蘅皋，烟芜外、吴山历历。',115,'宋词/ci.song.6000.json','["秋满蘅皋，烟芜外、吴山历历。", "风乍起，兰舟不住，浪花摇碧。", "离岸橹声惊渐远，盈襟泪颗凄犹滴。", "问此情、能有几人知，新相识。", "追往事，欢连夕。", "经旧馆，人非昔。", "把轻颦浅笑，细思重忆。", "红叶题诗谁与寄，青楼薄幸空遗迹。", "但长洲、茂苑草萋萋，愁如织。"]'),
('song-ci-223','满江红','张孝祥','宋','宋词','song-ci','满江红','[]','千古凄凉，兴亡事、但悲陈迹。',115,'宋词/ci.song.6000.json','["千古凄凉，兴亡事、但悲陈迹。", "凝望眼、吴波不动，楚山丛碧。", "巴滇绿骏追风远，武昌云旆连江赤。", "笑老奸、遗臭到如今，留空壁。", "边书静，烽烟息。", "通轺传，销锋镝。", "仰太平天子，坐收长策。", "蹙踏扬州开帝里，渡江天马龙为匹。", "看东南、佳气郁葱葱，传千亿。"]'),
('song-ci-224','满江红','张孝祥','宋','宋词','song-ci','满江红','[]','秋满漓源，瘴云净、晓山如簇。',115,'宋词/ci.song.6000.json','["秋满漓源，瘴云净、晓山如簇。", "动远思、空江小艇，高丘乔木。", "策策西风双鬓底，晖晖斜日朱栏曲。", "试侧身、回首望京华，迷南北。", "思归梦，天边鹄。", "游宦事，蕉中鹿。", "想一年好处，砌红堆绿。", "罗帕分柑霜落齿，冰磐剥芡珠盈掬。", "倩春纤、缕鲙捣香齑，新篘熟。"]'),
('song-ci-225','青玉案','张孝祥','宋','宋词','song-ci','青玉案','["\u6d1e\u5ead\u6e56"]','红尘冉冉长安路。',80,'宋词/ci.song.6000.json','["红尘冉冉长安路。", "看风度、凝然去。", "唱彻阳关留不住。", "甘棠庭院，芰荷香渚。", "尽是相思处。", "龟鱼从此谁为主。", "好记江湖断肠句。", "万斛离愁休更诉。", "洞庭烟棹，楚楼风露。", "去作为霖雨。"]'),
('song-ci-226','蓦山溪','张孝祥','宋','宋词','song-ci','蓦山溪','[]','清都绛阕，我自经行惯。',102,'宋词/ci.song.6000.json','["清都绛阕，我自经行惯。", "璧月带珠星，引钧天、笙箫不断。", "宝簪瑶佩，玉立拱清班。", "天一笑，物皆春，结得清虚伴。", "还丹九转。", "凡骨亲曾换。", "携剑到人间，偶相逢、依然青眼。", "狂歌醉舞，心事有谁知，明月下，好风前，相对纶巾岸。"]'),
('song-ci-227','蝶恋花','张孝祥','宋','宋词','song-ci','蝶恋花','[]','漠漠飞来双属玉。',70,'宋词/ci.song.6000.json','["漠漠飞来双属玉。", "一片秋光，染就潇湘绿。", "雪转寒芦花蔌蔌。", "晚风细起波纹縠。", "落日闲云归意促。", "小倚蓬窗，写作思家曲。", "过尽碧湾三十六。", "扁舟只在滩头宿。"]'),
('song-ci-228','蝶恋花','张孝祥','宋','宋词','song-ci','蝶恋花','[]','恰则杏花红一树，拈指来时，结子青无数。',70,'宋词/ci.song.6000.json','["恰则杏花红一树，拈指来时，结子青无数。", "漠漠春阴缠柳絮。", "一天风雨将春去。", "春到家山须小住。", "芍药樱桃，更是寻芳处。", "绕院碧莲三百亩。", "留春伴我春应许。"]'),
('song-ci-229','蝶恋花','张孝祥','宋','宋词','song-ci','蝶恋花','[]','画戟斿闲刀入鞘。',70,'宋词/ci.song.6000.json','["画戟斿闲刀入鞘。", "安石榴花，影落红栏小。", "似劝先生须饮釂。", "枕中鸿宝微传妙。", "衮衮锋车还急诏。", "满眼潇湘，总是恩波渺。", "归去槐庭思楚峤。", "觚稜月晓期分照。"]'),
('song-ci-230','蝶恋花','张孝祥','宋','宋词','song-ci','蝶恋花','[]','君泛仙槎银海去。',70,'宋词/ci.song.6000.json','["君泛仙槎银海去。", "后日相思，地角天涯路。", "草草杯磐深夜语。", "冥冥四月黄梅雨。", "莫拾明珠并翠羽。", "但使邦人，爱我如慈母。", "待得政成民按堵。", "朝天衣袂翩翩举。"]'),
('song-ci-231','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','咏彻琼章夜向阑。',64,'宋词/ci.song.6000.json','["咏彻琼章夜向阑。", "天移星斗下人间。", "九光倒影腾青简，一气回春绕绛坛。", "瞻北阕，祝南山。", "遥知仙仗簇清班。", "何人曾侍传柑宴，翡翠帘开识圣颜。"]'),
('song-ci-232','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','子夜封章扣紫清。',64,'宋词/ci.song.6000.json','["子夜封章扣紫清。", "五霞光里佩环声。", "驿传风火龙鸾舞，步入烟宵孔翠迎。", "瑶简重，羽衣轻。", "金童双引到通明。", "三湘五管同民乐，万岁千秋与帝龄。"]'),
('song-ci-233','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','忆昔追游翰墨场。',64,'宋词/ci.song.6000.json','["忆昔追游翰墨场。", "武夷仙伯较文章。", "琅函奏号银台省，毡笔书名御苑墙。", "经十载，过三湘。", "横楣丽锦照传觞。", "醉馀吐出胸中墨，只欠彭宣到后堂。"]'),
('song-ci-234','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','月地云阶欢意阑。',64,'宋词/ci.song.6000.json','["月地云阶欢意阑。", "仙姿不合住人间。", "骖鸾已恨车尘远，泣凤空馀烛影残。", "情脉脉，泪珊珊。", "梅花音信隔关山。", "只应楚雨清留梦，不那吴霜绿易斑。"]'),
('song-ci-235','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','去日清霜菊满丛。',64,'宋词/ci.song.6000.json','["去日清霜菊满丛。", "归来高柳絮缠空。", "长驱万里山收瘴，径度层波海不风。", "阴得遍，岭西东。", "天教慈母寿无穷。", "遥知今夕称觞处，衣彩还将衣绣同。"]'),
('song-ci-236','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','阿母蟠桃不记春。',64,'宋词/ci.song.6000.json','["阿母蟠桃不记春。", "长沙星里寿星明。", "金花罗纸新裁诏，贝叶旁行别授经。", "同犬子，祝龟龄。", "天教二老鬓长青。", "明年今日称觞处，更有孙枝满谢庭。"]'),
('song-ci-237','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','舞凤飞龙五百年。',64,'宋词/ci.song.6000.json','["舞凤飞龙五百年。", "尽将锦绣裹山川。", "王家券册诸孙嗣，主第笙歌故国传。", "居玉铉，拥金蝉。", "祗今门户庆蝉联。", "君侯合侍明光殿，且作横槎海上仙。"]'),
('song-ci-238','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','浴殿西头白玉堂。',64,'宋词/ci.song.6000.json','["浴殿西头白玉堂。", "湘江东畔碧玉幢。", "北辰躔次瞻星象，南国山川解印章。", "随步武，谢恩光。", "送公归趣舍人装。", "它年若肯传衣钵，今日应须传寿觞。"]'),
('song-ci-239','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','昼得游嬉夜得眠。',64,'宋词/ci.song.6000.json','["昼得游嬉夜得眠。", "农桑欲遍楚山川。", "问看百姓知公否，馀子纷纷定不然。", "思主眷，酌民言。", "与民称寿拜公前。", "只将心与天通处，合住人间五百年。"]'),
('song-ci-240','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','割镫难留乘马东。',64,'宋词/ci.song.6000.json','["割镫难留乘马东。", "花枝争看袅长红。", "衮衣空使斯民恋，绿竹谁歌入相同。", "回武事，致年丰。", "几多遗爱在湘中。", "须知楚水枫林下，不似初闻长乐钟。"]'),
('song-ci-241','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','楚楚吾家千里驹。',64,'宋词/ci.song.6000.json','["楚楚吾家千里驹。", "老人心事正关渠。", "风流合是阶除玉，爱惜真成掌上珠。", "纡彩绶，荐芳壶。", "老人还醉弟兄扶。", "问将何物为儿寿，付与家传万卷书。"]'),
('song-ci-242','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','又向荆州住半年。',64,'宋词/ci.song.6000.json','["又向荆州住半年。", "西风催放五湖船。", "来时露菊团金颗，去日池荷叠绿钱。", "斟别酒，扣离弦。", "一时宾从最多贤。", "今宵拼醉花迷坐，后夜相思月满川。"]'),
('song-ci-243','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','忆昔彤庭望日华。',64,'宋词/ci.song.6000.json','["忆昔彤庭望日华。", "匆匆枯笔梦生花。", "郁轮袍曲惭新奏，风送银湾犯斗槎。", "追往事，甫新瓜。", "飞蓬何事及兰麻。", "一江湘水流馀润，十里河堤筑浅沙。"]'),
('song-ci-244','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','瞻跸门前识个人。',64,'宋词/ci.song.6000.json','["瞻跸门前识个人。", "柳眉桃脸不胜春。", "短襟衫子新来棹，四直冠儿内样新。", "秋色净，晓妆匀。", "不知何事在风尘。", "主翁若也怜幽独，带取妖饶上玉宸。"]'),
('song-ci-245','虞美人','张孝祥','宋','宋词','song-ci','虞美人','[]','庐敖夫妇骖鸾侣。',66,'宋词/ci.song.6000.json','["庐敖夫妇骖鸾侣。", "相敬如宾主。", "森然兰玉满尊前。", "举案齐眉乐事、看年年。", "我家白发双垂雪。", "已是经年别。", "今宵归梦楚江滨。", "也学君家儿子、寿吾亲。"]'),
('song-ci-246','虞美人','张孝祥','宋','宋词','song-ci','虞美人','[]','雪花一尺江南北。',66,'宋词/ci.song.6000.json','["雪花一尺江南北。", "薪尽炊无粟。", "老仙活国拭刀圭。", "十万人家生意、与春回。", "天公一笑酬阴德。", "赐与长生籍。", "今朝雪霁寿尊前。", "看我双亲都是、地行仙。"]'),
('song-ci-247','虞美人','张孝祥','宋','宋词','song-ci','虞美人','[]','雪消烟涨清江浦。',66,'宋词/ci.song.6000.json','["雪消烟涨清江浦。", "碧草春无数。", "江南几树夕阳红。", "点点归帆吹尽、晚来风。", "楼头自擫昭华管。", "我已无肠断。", "断行双雁向人飞。", "织锦回文空住、寄它谁。"]'),
('song-ci-248','虞美人','张孝祥','宋','宋词','song-ci','虞美人','[]','溪西竹榭溪东路。',66,'宋词/ci.song.6000.json','["溪西竹榭溪东路。", "溪上山无数。", "小舟却在晚烟中。", "更看萧萧微雨、打疏篷。", "无聊情绪如中酒。", "此意君知否。", "年时曾向此中行。", "有个人人相对、坐调筝。"]'),
('song-ci-249','虞美人','张孝祥','宋','宋词','song-ci','虞美人','[]','柳梢梅萼春全未。',66,'宋词/ci.song.6000.json','["柳梢梅萼春全未。", "谁曾伤春意。", "一年好处是新春。", "柳底梅边只欠、那人人。", "凭春约住梅和柳。", "略待些时候。", "锦帆风送彩舟来。", "却遗香包娇叶、一齐开。"]'),
('song-ci-250','虞美人','张孝祥','宋','宋词','song-ci','虞美人','[]','罗衣怯雨轻寒透。',66,'宋词/ci.song.6000.json','["罗衣怯雨轻寒透。", "陡做伤春瘦。", "个人无奈语佳期。", "徙倚黄昏池阁、等多时。", "当初不似休来好。", "来后空烦恼。", "倩人传语更商量。", "只得千金一笑、也甘当。"]'),
('song-ci-251','鹊桥仙','张孝祥','宋','宋词','song-ci','鹊桥仙','[]','北窗凉透，南窗月上，浴罢满怀风露。',68,'宋词/ci.song.6000.json','["北窗凉透，南窗月上，浴罢满怀风露。", "不知何处有花来，但怪底、清香无数。", "炎州珍产，吴儿未识，天与幽芳独步。", "冰肌玉骨岁寒时，倩间止、堂中留住。"]'),
('song-ci-252','鹊桥仙','张孝祥','宋','宋词','song-ci','鹊桥仙','[]','吹香成阵，飞花如雪，不那朝来风雨。',68,'宋词/ci.song.6000.json','["吹香成阵，飞花如雪，不那朝来风雨。", "可怜无处避春寒，但玉立、仙衣数缕。", "清愁万斛，柔肠千结，醉里一时分付。", "与君不用叹飘零，待结子、成阴归去。"]'),
('song-ci-253','鹊桥仙','张孝祥','宋','宋词','song-ci','鹊桥仙','[]','横波滴素，遥山蹙翠，江北江南肠断。',68,'宋词/ci.song.6000.json','["横波滴素，遥山蹙翠，江北江南肠断。", "不知何处驭风来。", "云雾里、钗横鬓乱。", "香罗叠恨，蛮笺写意，付与瑶台女伴。", "醉时言语醒时羞，道醒了、休教再看。"]'),
('song-ci-254','鹊桥仙','张孝祥','宋','宋词','song-ci','鹊桥仙','[]','湘江东畔，去年今日，堂上簪缨罗绮。',68,'宋词/ci.song.6000.json','["湘江东畔，去年今日，堂上簪缨罗绮。", "弟兄同拜寿尊前，共一笑、欢欢喜喜。", "渚宫风月，边城鼓角，更好亲庭一醉。", "醉时同唱去年词，愿来岁、强如今岁。"]'),
('song-ci-255','鹊桥仙','张孝祥','宋','宋词','song-ci','鹊桥仙','[]','南州名酒，北园珍果，都与黄香为寿。',68,'宋词/ci.song.6000.json','["南州名酒，北园珍果，都与黄香为寿。", "风流文物是家传，睨血指、旁观袖手。", "东风消息，西山爽气，总聚君家户牖。", "旧时曾识玉堂仙，在帝所、频开荐口。"]'),
('song-ci-256','鹊桥仙','张孝祥','宋','宋词','song-ci','鹊桥仙','[]','明珠盈斗，黄金作屋，占了湘中秋色。',68,'宋词/ci.song.6000.json','["明珠盈斗，黄金作屋，占了湘中秋色。", "金风玉露不胜情，看天上、人间今夕。", "枝头一点，琴心三叠，算有诗名消得。", "野堂从此不萧疏，问何日、尊前唤客。"]'),
('song-ci-257','鹊桥仙','张孝祥','宋','宋词','song-ci','鹊桥仙','[]','黄陵庙下，送君归去，上水船儿一只。',68,'宋词/ci.song.6000.json','["黄陵庙下，送君归去，上水船儿一只。", "离歌声断酒杯空，容易里、东西南北。", "重湖风月，九秋天气，冉冉清愁如织。", "我家住在楚江滨，为频寄、双鱼素尺。"]'),
('song-ci-258','鹊桥仙','张孝祥','宋','宋词','song-ci','鹊桥仙','[]','东明大士，吾家老子，是一元知非二。',68,'宋词/ci.song.6000.json','["东明大士，吾家老子，是一元知非二。", "共携甘雨趁生朝，做万里、丰年欢喜。", "司空山上，长沙星里，乞与无边祥瑞。", "仙家日月镇常春，笑人说、长生久视。"]'),
('song-ci-259','南乡子','张孝祥','宋','宋词','song-ci','南乡子','[]','江上送归船。',66,'宋词/ci.song.6000.json','["江上送归船。", "风雨排空浪拍天。", "赖有清尊浇别恨，凄然。", "宝蜡烧花看吸川。", "楚舞对湘弦。", "暖响围春锦帐毡。", "坐上定知无俗客，俱贤。", "便是朱张与少连。"]'),
('song-ci-260','画堂春','张孝祥','宋','宋词','song-ci','画堂春','[]','蟠桃一熟九千年。',55,'宋词/ci.song.6000.json','["蟠桃一熟九千年。", "仙家春色无边。", "书堂日暖卷非烟。", "昼永风妍。", "看取蔬封汤沐，何妨频棹觥船。", "方瞳绿发对儒仙。", "岁岁尊前。"]'),
('song-ci-261','柳梢青','张孝祥','宋','宋词','song-ci','柳梢青','[]','重阳时节。',61,'宋词/ci.song.6000.json','["重阳时节。", "满城风雨，更催行色。", "陇树寒轻，海山秋老，清愁如织。", "一杯莫惜留连，我亦是、天涯倦客。", "后夜相思，水长山远，东西南北。"]'),
('song-ci-262','柳梢青','张孝祥','宋','宋词','song-ci','柳梢青','[]','今年元夕。',61,'宋词/ci.song.6000.json','["今年元夕。", "探尽江梅，都无消息。", "草市梢头，柳庄深处，雪花如席。", "一尊邻里相过，也随分、移时换节。", "玉辇端门，红旗夜市、凭君休说。"]'),
('song-ci-263','柳梢青','张孝祥','宋','宋词','song-ci','柳梢青','[]','溪南溪北。',61,'宋词/ci.song.6000.json','["溪南溪北。", "玉香消尽，翠娇无力。", "月淡黄昏，烟横清晓，都无消息。", "无聊更绕空枝，断魂远、重招怎得。", "驿使归来，戍楼吹断，空成凄恻。"]'),
('song-ci-264','踏莎行','张孝祥','宋','宋词','song-ci','踏莎行','[]','杨柳东风，海棠春雨。',68,'宋词/ci.song.6000.json','["杨柳东风，海棠春雨。", "清愁冉冉无来处。", "曲径惊飞蛱蝶丛，回塘冻湿鸳鸯侣。", "舞彻霓裳，歌残金缕。", "蘼芜白芷愁烟渚。", "不识阳台梦里云，试听华表归来语。"]'),
('song-ci-265','踏莎行','张孝祥','宋','宋词','song-ci','踏莎行','[]','洛下根株，江南栽种。',68,'宋词/ci.song.6000.json','["洛下根株，江南栽种。", "天香国色千金重。", "花边三阁建康春，风前十里扬州梦。", "油壁轻车，青丝短鞚。", "看花日日催宾从。", "而今何许定王城，一枝且为邻翁送。"]'),
('song-ci-266','踏莎行','张孝祥','宋','宋词','song-ci','踏莎行','[]','旋葺荒园，初开小径。',68,'宋词/ci.song.6000.json','["旋葺荒园，初开小径。", "物华还与东风竞。", "曲槛晖晖落照明，高城冉冉孤烟暝。", "柳色金寒，梅花雪静。", "道人随处成幽兴。", "一杯不惜小淹留，归期已理沧浪艇。"]'),
('song-ci-267','踏莎行','张孝祥','宋','宋词','song-ci','踏莎行','[]','万里扁舟，五年三至。',68,'宋词/ci.song.6000.json','["万里扁舟，五年三至。", "故人相见犹堪喜。", "山阴乘兴不须回，毗耶问疾难为对。", "不药身轻，高谈心会。", "匆匆我又成归计。", "它时江海肯相寻，绿蓑青弱看清贵。"]'),
('song-ci-268','踏莎行','张孝祥','宋','宋词','song-ci','踏莎行','[]','藕叶池塘，榕阴庭院。',68,'宋词/ci.song.6000.json','["藕叶池塘，榕阴庭院。", "年时好月今宵见。", "云鬓玉臂共清寒，冰绡雾縠谁裁剪。", "扑粉口绵，侵尘宝扇。", "遥知掩抑成凄怨。", "去程何许是归程，离觞为我深深劝。"]'),
('song-ci-269','踏莎行','张孝祥','宋','宋词','song-ci','踏莎行','[]','古屋丛祠，孤舟野渡。',68,'宋词/ci.song.6000.json','["古屋丛祠，孤舟野渡。", "长年与客分携处。", "漠漠愁阴岭上云，萧萧别意溪边树。", "我已北归，君方南去。", "天涯客里多歧路。", "须君早出瘴烟来，江南山色青无数。"]'),
('song-ci-270','踏莎行','张孝祥','宋','宋词','song-ci','踏莎行','[]','时雨初晴，诏书随至。',68,'宋词/ci.song.6000.json','["时雨初晴，诏书随至。", "邦人父老为君喜。", "十年江海始归来，祥曦殿里搀班对。", "日月开明，风云感会。", "切须稳上平戎计。", "天教慈母寿无穷，看君黄发腰金贵。"]'),
('song-ci-271','踏莎行','张孝祥','宋','宋词','song-ci','踏莎行','[]','桂岭南边，湘江东畔。',68,'宋词/ci.song.6000.json','["桂岭南边，湘江东畔。", "三年两见生申旦。", "知君心地与天通，天教仙骨年年换。", "趁此仙风，乘槎宵汉。", "看看黄纸书来唤。", "但令丹鼎汞频添，莫辞酒盏春无算。"]'),
('song-ci-272','丑奴儿・采桑子','张孝祥','宋','宋词','song-ci','丑奴儿・采桑子','[]','年年有个人生日，谁似君家。',52,'宋词/ci.song.6000.json','["年年有个人生日，谁似君家。", "谁似君家。", "八十慈亲发未华。", "棠阴阁上棠阴满，满劝流霞。", "满劝流霞。", "来岁应添宰路沙。"]'),
('song-ci-273','丑奴儿・采桑子','张孝祥','宋','宋词','song-ci','丑奴儿・采桑子','[]','伯鸾德耀贤夫妇，见说宜家。',52,'宋词/ci.song.6000.json','["伯鸾德耀贤夫妇，见说宜家。", "见说宜家。", "庭砌森森长玉华。", "天公遣注长生籍，服日餐霞。", "服日餐霞。", "寿纪应须海算沙。"]'),
('song-ci-274','丑奴儿・采桑子','张孝祥','宋','宋词','song-ci','丑奴儿・采桑子','[]','十年闻说查山好，何日追游。',52,'宋词/ci.song.6000.json','["十年闻说查山好，何日追游。", "木落霜秋。", "梦想云溪不那愁。", "主人好事长留客，尊酒夷犹。", "一笑登楼。", "兴在西峰上上头。"]'),
('song-ci-275','丑奴儿・采桑子','张孝祥','宋','宋词','song-ci','丑奴儿・采桑子','[]','十分济楚邦之媛，此日追游。',52,'宋词/ci.song.6000.json','["十分济楚邦之媛，此日追游。", "雨霁云收。", "梦入潇湘不那愁。", "主人白玉堂中老，曾侍凝旒。", "满酌琼舟。", "即上虚皇香案头。"]'),
('song-ci-276','丑奴儿・采桑子','张孝祥','宋','宋词','song-ci','丑奴儿・采桑子','[]','珠灯璧月年时节，织手同携。',52,'宋词/ci.song.6000.json','["珠灯璧月年时节，织手同携。", "今夕谁知，自拈梅花劝一卮。", "逢人问道归来也，日日佳期。", "管有来时。", "趁得手灯也未迟。"]'),
('song-ci-277','丑奴儿・采桑子','张孝祥','宋','宋词','song-ci','丑奴儿・采桑子','[]','无双谁似黄郎子，自郐无讥。',52,'宋词/ci.song.6000.json','["无双谁似黄郎子，自郐无讥。", "月满星稀。", "想见歌场夜打围。", "画眉京兆风流甚，应赋蛜蝛。", "杨柳依依。", "何日文箫共驾归。"]'),
('song-ci-278','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','卷旗直入蔡州城。',48,'宋词/ci.song.6000.json','["卷旗直入蔡州城。", "只倚精忠不要兵。", "贼营半夜落妖星。", "万旅云屯看整暇，十眉环坐却娉婷。", "白麻早晚下天庭。"]'),
('song-ci-279','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','玉节珠幢出翰林。',48,'宋词/ci.song.6000.json','["玉节珠幢出翰林。", "诗书谋帅眷方深。", "威声虎啸复龙吟。", "我是先生门下士，相逢有酒且教斟。", "高山流水遇知音。"]'),
('song-ci-280','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','绝代佳人淑且真。',48,'宋词/ci.song.6000.json','["绝代佳人淑且真。", "雪为肌骨月为神。", "烛前花底不胜春。", "倚竹袖长寒卷翠，凌波袜小暗生尘。", "十分京落旧家人。"]'),
('song-ci-281','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','妙手何人为写真。',48,'宋词/ci.song.6000.json','["妙手何人为写真。", "只难传处是精神。", "一枝占断洛城春。", "暮雨不堪巫峡梦，西风莫障瘐公尘。", "扁舟湖海要诗人。"]'),
('song-ci-282','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','腊后春前别一般。',48,'宋词/ci.song.6000.json','["腊后春前别一般。", "梅花枯淡水仙寒。", "翠云裘著紫霞冠。", "仙品只今推第一，清香元不是人间。", "为君更拭小龙团。"]'),
('song-ci-283','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','宝蜡烧春夜影红。',48,'宋词/ci.song.6000.json','["宝蜡烧春夜影红。", "梅花枝傍锦薰笼。", "曲琼低卷瑞香风。", "万里江山供燕几，一时宾主看谈锋。", "问君归计莫匆匆。"]'),
('song-ci-284','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','六客西来共一舟。',48,'宋词/ci.song.6000.json','["六客西来共一舟。", "吴儿踏浪剪轻鸥。", "水光山色翠相浮。", "我欲吹箫明月下，略须停棹晚风头。", "从前五度到蕲州。"]'),
('song-ci-285','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','已是人间不系舟。',48,'宋词/ci.song.6000.json','["已是人间不系舟。", "此心元自不惊鸥。", "卧看骇浪与天浮。", "对月只应频举酒，临风何必更搔头。", "暝烟多处是神州。"]'),
('song-ci-286','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','冉冉幽香解钿囊。',48,'宋词/ci.song.6000.json','["冉冉幽香解钿囊。", "兰桡烟雨暗春江。", "十分清瘦为箫郎。", "遥忆牙樯收楚缆，应将玉箸点吴妆。", "有人萦断九回肠。"]'),
('song-ci-287','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','楼下西流水拍堤。',48,'宋词/ci.song.6000.json','["楼下西流水拍堤。", "楼头日日望春归。", "雪晴风静燕来迟。", "留得梅花供半额，要将杨叶画新眉。", "莫教辜负早春时。"]'),
('song-ci-288','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','["\u5cb3\u9633\u697c"]','方舡载酒下江东。',48,'宋词/ci.song.6000.json','["方舡载酒下江东。", "箫鼓喧天浪拍空。", "万山紫翠映云重。", "拟看岳阳楼上月，不禁石首岸头风。", "作笺我欲问龙公。"]'),
('song-ci-289','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','罗袜生尘洛浦东。',48,'宋词/ci.song.6000.json','["罗袜生尘洛浦东。", "美人春梦琐窗空。", "眉山蹙恨几千重。", "海上蟠桃留结子，渥洼天马去追风。", "不须多怨主人公。"]'),
('song-ci-290','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','一片西飞一片东。',48,'宋词/ci.song.6000.json','["一片西飞一片东。", "高情已逐落花空。", "旧欢休问几时重。", "结习正如刀舔蜜，扫除须著絮因风。", "请君持此问龙公。"]'),
('song-ci-291','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','鳷鹊楼高晚雪融。',48,'宋词/ci.song.6000.json','["鳷鹊楼高晚雪融。", "鸳鸯池暖暗潮通。", "郁金黄染柳丝风。", "油壁不来春草绿，栏干倚遍夕阳红。", "江南山色有无中。"]'),
('song-ci-292','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','妒妇滩头十八姨。',48,'宋词/ci.song.6000.json','["妒妇滩头十八姨。", "颠狂无赖占佳期。", "唤它滕六把春欺。", "﹀︽莺莺并燕燕，凄惶柳柳与梅梅。", "东君独自落便宜。"]'),
('song-ci-293','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','["\u6d1e\u5ead\u6e56"]','行尽潇湘到洞庭。',48,'宋词/ci.song.6000.json','["行尽潇湘到洞庭。", "楚天阔处数峰青。", "旗梢不动晚波平。", "红蓼一湾纹缬乱，白鱼双尾玉刀明。", "夜凉船影浸疏星。"]'),
('song-ci-294','浪淘沙','宋先生','宋','宋词','song-ci','浪淘沙','[]','师指炼金丹。',64,'宋词/ci.song.6000.json','["师指炼金丹。", "牢锁金关。", "工夫进火莫交闲。", "向己澄心观内景，闪电眉间。", "妙用在泥丸。", "神思难看。", "愚迷不悟隔千山。", "悟即如同观返掌，出世何难。"]'),
('song-ci-295','浪淘沙','宋先生','宋','宋词','song-ci','浪淘沙','[]','铅汞要加添。',64,'宋词/ci.song.6000.json','["铅汞要加添。", "火候频煎。", "体中气足返阳全。", "养就婴儿并姹女，同坐同眠。", "髓实自身坚。", "运满三田。", "刀圭服了得神仙。", "只候功成并行满，独步朝元。"]'),
('song-ci-296','糖多令・唐多令','宋先生','宋','宋词','song-ci','糖多令・唐多令','["\u9ec4\u6cb3"]','搬载渡黄河。',74,'宋词/ci.song.6000.json','["搬载渡黄河。", "金关牢闭锁。", "运九还、须是功多。", "光透帘帏红似火。", "见金钱、万千朵。", "过水涌银波。", "充开牛斗过。", "进工夫、□□蹉跎。", "见个真人便是我。", "暗欢喜、笑呵呵。"]'),
('song-ci-297','桃源忆故人','宋先生','宋','宋词','song-ci','桃源忆故人','[]','自从师指天机道。',56,'宋词/ci.song.6000.json','["自从师指天机道。", "万卷仙经都晓。", "若会连精归脑。", "颜貌长不老。", "真铅真汞人知少。", "乌兔烹煎成宝。", "身外有身方了。", "玉帝金书召。"]'),
('song-ci-298','惜黄花','宋先生','宋','宋词','song-ci','惜黄花','[]','天机大道。',82,'宋词/ci.song.6000.json','["天机大道。", "达者稀少。", "运戊己、龙蟠更虎绕。", "这一颗丹砂，凡世人难晓。", "间木金、坎离颠倒。", "阳全阴尽，形容不老。", "将水火烹煎，自然炉灶。", "待行功成就，炼无价宝。", "去朝元、七祖都了。"]'),
('song-ci-299','阮郎归','宋先生','宋','宋词','song-ci','阮郎归','[]','一轮明月照三峰。',56,'宋词/ci.song.6000.json','["一轮明月照三峰。", "彩霞飞满空。", "分明见我主人公。", "明珠透上宫。", "丹药炼，鼎中红。", "频频要用功。", "功成定是出樊笼。", "闲游仙洞中。"]'),
('song-ci-300','武陵春','宋先生','宋','宋词','song-ci','武陵春','[]','七返阳全阴去尽，精髓满三田。',56,'宋词/ci.song.6000.json','["七返阳全阴去尽，精髓满三田。", "修道无为必自然。", "论甚后和先。", "认取五行真水火，须要识根源。", "自己丹砂著意看。", "何用外寻丹。"]'),
('song-ci-301','西江月','叶适','宋','宋词','song-ci','西江月','[]','识贯事中枢纽，笔开象外精神。',58,'宋词/ci.song.6000.json','["识贯事中枢纽，笔开象外精神。", "传观弓力异常钧。", "衣我六铢羞问。", "周后数茎命粒，鲁儒一点芳心。", "啄残栖老付谁论。", "谩要睡馀支枕。"]'),
('song-ci-302','望江南・忆江南','王','宋','宋词','song-ci','望江南・忆江南','[]','三杰后，福寿两无涯。',64,'宋词/ci.song.6000.json','["三杰后，福寿两无涯。", "食乳相君功未既，妩眉京兆眷方兹。", "富贵莫推辞。", "门两戟，却棹一纶丝。", "莼菜秋风鲈鲙美，桃花春水鳜鱼肥。", "笑傲霅溪湄。"]'),
('song-ci-303','水龙吟','刘褒','宋','宋词','song-ci','水龙吟','[]','东风初縠池波，轻阴未放游丝堕。',127,'宋词/ci.song.6000.json','["东风初縠池波，轻阴未放游丝堕。", "新春歌管，丰年笑语，六街灯火。", "绣毂雕鞍，飞尘卷雾，水流云过。", "恍扬州十里，三生梦觉，卷珠箔、映青琐。", "金猊戏掣星桥锁。", "博山香、烟浓百和。", "使君行乐，绛纱万炬，雪梅千朵。", "羯鼓轰空，鵾弦沸晓，樱梢微破。", "想明年更好，传柑侍宴，醉扶狨座。"]'),
('song-ci-304','雨中花慢','刘褒','宋','宋词','song-ci','雨中花慢','[]','缥蒂缃枝，玉叶翡英，百梢争赴春忙。',121,'宋词/ci.song.6000.json','["缥蒂缃枝，玉叶翡英，百梢争赴春忙。", "正雨后、蜂黏落絮，燕扑晴香。", "遗策谁家荡子，唾花何处新妆。", "想流红有恨，拾翠无心，往事凄凉。", "春愁如海，客思翻空，带围只看东阳。", "更那堪、玉笙度曲，翠羽传觞。", "红泪不胜闺怨，白云应老他乡。", "梦回羁枕，风惊庭树，月在西厢。"]'),
('song-ci-305','满庭芳','刘褒','宋','宋词','song-ci','满庭芳','[]','柳袅金丝，梨铺香雪，一年春事方中。',117,'宋词/ci.song.6000.json','["柳袅金丝，梨铺香雪，一年春事方中。", "烛前一见，花艳觉羞红。", "枕臂香痕未落，舟横岸、作计匆匆。", "明朝去，暮天平水，双桨碧云东。", "隔离歌一阕，琵琶声断，燕子楼空。", "叹阳台梦杳，行雨无踪。", "后会芙蕖未老，从今去、日望归鸿。", "愁如织，断肠啼鴂，饶舌诉东风。"]'),
('song-ci-306','六州歌头','刘褒','宋','宋词','song-ci','六州歌头','[]','凭深负阻，蜂舞肆奔腾。',181,'宋词/ci.song.6000.json','["凭深负阻，蜂舞肆奔腾。", "龙江上，妖氛涨，鲸海外，白波惊。", "羽檄交飞急，玉帐静，金韬閟，恢远驭，振长樱。", "密分兵。", "细草黄沙渺渺，西关路、风袅高旌。", "听飞霜令肃，坚壁夜无声。", "鼓角何神。", "地中鸣。", "看追风骑，攒云槊，雷野毂，激天钲。", "飞箭集，旄头坠，长围掩，郭东倾。", "振旅观旋凯，笳鼓竞，绣旗明。", "刀换犊，戈藏革，士休营。", "黄色赤云交映，论功何止蔡州平。", "想环城苍玉，深刻入青冥。", "永诏来今。"]'),
('song-ci-307','水调歌头','刘褒','宋','宋词','song-ci','水调歌头','[]','天淡四垂幕，云细不成衣。',114,'宋词/ci.song.6000.json','["天淡四垂幕，云细不成衣。", "西风扫尽绣翳，凉我鬓边丝。", "破匣菱花飞动，跨海清光无际，草露滴明玑。", "杯到莫停手，何用问来期。", "坐虚堂，揩病眼，溯流辉。", "云山应有幽恨，瑶瑟掩金徽。", "河汉无声自转，玉兔有情亦老，世事巧相违。", "一写谪仙怨，双泪满君颐。"]'),
('song-ci-308','小重山','章良能','宋','宋词','song-ci','小重山','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','柳暗花明春事深。',70,'宋词/ci.song.6000.json','["柳暗花明春事深。", "小阑红芍药，已抽簪。", "雨馀风软碎鸣禽。", "迟迟日，犹带一分阴。", "往事莫沈吟。", "身闲时序好，且登临。", "旧游无处不堪寻。", "无寻处，惟有少年心。"]'),
('song-ci-309','水调歌头','熊以宁','宋','宋词','song-ci','水调歌头','[]','天地有英气，锺秀在人间。',114,'宋词/ci.song.6000.json','["天地有英气，锺秀在人间。", "流虹甫近华旦，维岳预生贤。", "千载明良会遇，三世勋庸忠烈，谁得似家传。", "高论排风俗，抗志遏狂澜。", "记年时，胡尘外，拥朱幡。", "洪枢紫府功业，指日复青毡。", "拭目泥封飞下，趁取梅花消息，去去簉朝班。", "骨相元不老，何必颂南山。"]'),
('song-ci-310','醉蓬莱','熊以宁','宋','宋词','song-ci','醉蓬莱','[]','渐荷收绿盖，桂吐金英，嫩凉天气。',120,'宋词/ci.song.6000.json','["渐荷收绿盖，桂吐金英，嫩凉天气。", "香案仙官，向人间游戏。", "道貌孤高，灵扃恬淡，有寿星标致。", "梦得文章，水心谈论，家声相继。", "芙蓉上幕，龙藩胜地。", "剡荐交飞，宸衷简记。", "行趣朝班，便鸾坡螭陛。", "赞画堂中，垂弧节届，且举觞一醉。", "试问桩椿，春秋多少，八千馀岁。"]'),
('song-ci-311','鹊桥仙','熊以宁','宋','宋词','song-ci','鹊桥仙','[]','隐君仙裔，帅垣佳配。',70,'宋词/ci.song.6000.json','["隐君仙裔，帅垣佳配。", "谁似硕人清贵。", "几番鸾诰自天来，森绿绶、彩衣当砌。", "莲开十丈，蓂留十荚，迟十日、瑶池秋至。", "殷勤祝寿指蟠桃，更重数、三千馀岁。"]'),
('song-ci-312','失调名','詹克爱','宋','宋词','song-ci','失调名','[]','天孙亲织云锦，一笑天下河西。',14,'宋词/ci.song.6000.json','["天孙亲织云锦，一笑天下河西。"]'),
('song-ci-313','失调名','詹克爱','宋','宋词','song-ci','失调名','[]','空将别泪，洒作人间雨。',11,'宋词/ci.song.6000.json','["空将别泪，洒作人间雨。"]'),
('song-ci-314','失调名','詹克爱','宋','宋词','song-ci','失调名','[]','后会不知谁健，茱萸莫厌重看。',14,'宋词/ci.song.6000.json','["后会不知谁健，茱萸莫厌重看。"]'),
('song-ci-315','齐天乐','李寅仲','宋','宋词','song-ci','齐天乐','[]','摩挲阅古堂前柳，尽是世臣乔木。',124,'宋词/ci.song.6000.json','["摩挲阅古堂前柳，尽是世臣乔木。", "故国风流，中兴事业，都写南山修竹。", "商颜自绿。", "甚当日君王，浩歌鸿鹄。", "谁识宫中，有人先定大横卜。", "簪貂更鸣佩玉。", "退朝归较晚，留传黄屋。", "雨露无边，风云在手，宜享长生福。", "神京未复。", "看先取鸿沟，次封函谷。", "岁岁初寒，小桃花下跨青鹿。"]'),
('song-ci-316','长相思','张鎡','宋','宋词','song-ci','长相思','[]','晴时看。',44,'宋词/ci.song.6000.json','["晴时看。", "雨时看。", "红绿云中驾彩鸾。", "阳台梦未阑。", "咏伊难。", "画伊难。", "服透东皇九转丹。", "光生玉炼颜。"]'),
('song-ci-317','梦游仙・戚氏','张鎡','宋','宋词','song-ci','梦游仙・戚氏','[]','骖鸾侣，娇小怯云期。',64,'宋词/ci.song.6000.json','["骖鸾侣，娇小怯云期。", "柳戏花游能几日，顿抛尘幻学希夷。", "清梦到瑶池。", "霞袂稳，那顾缕金衣。", "自与长生分姓谱，恰逢长老铸丹时。", "此意有谁知。"]'),
('song-ci-318','梦游仙・戚氏','张鎡','宋','宋词','song-ci','梦游仙・戚氏','[]','晴昼永，闲步小园中。',64,'宋词/ci.song.6000.json','["晴昼永，闲步小园中。", "羽帔云轻苍佩响，宝冠星莹绀纱笼。", "波秀浅蛾峰。", "琳洞窈，人静理丝桐。", "泛指馀音摇桂影，过墙高韵入松风。", "月上翠楼东。"]'),
('song-ci-319','梦游仙・戚氏','张鎡','宋','宋词','song-ci','梦游仙・戚氏','[]','飞梦去，闲到玉京游。',64,'宋词/ci.song.6000.json','["飞梦去，闲到玉京游。", "尘隔天高那得暑，月明云薄淡於秋。", "宫殿锁金虬。", "冰佩冷，风扬紫绡裘。", "五色光中瞻帝所，方知碧落胜炎洲。", "香雾湿帘钩。"]'),
('song-ci-320','梦游仙・戚氏','张鎡','宋','宋词','song-ci','梦游仙・戚氏','[]','归兴动，骑鹤下青冥。',64,'宋词/ci.song.6000.json','["归兴动，骑鹤下青冥。", "几点山河浮色界，一簪风露拂寒星。", "银汉悄无声。", "鸾啸舞，仙乐送霓旌。", "摘得琪花飞散了，却将何物送仙卿。", "衣上彩云轻。"]'),
('song-ci-321','昭君怨','张鎡','宋','宋词','song-ci','昭君怨','[]','拂晓拿舟东去。',48,'宋词/ci.song.6000.json','["拂晓拿舟东去。", "细看荷花垂露。", "红绿总吹香。", "一般凉。", "会享人天清福。", "休把两眉轻蹙。", "谁道做神仙。", "戴貂蝉。"]'),
('song-ci-322','昭君怨','张鎡','宋','宋词','song-ci','昭君怨','[]','船过柳湾亭曲。',48,'宋词/ci.song.6000.json','["船过柳湾亭曲。", "万叶圆荷浮绿。", "月照水珠明。", "一池星。", "光透玻璃香蒂。", "梦入藕丝中戏。", "却上小金台。", "罢归来。"]'),
('song-ci-323','昭君怨','张鎡','宋','宋词','song-ci','昭君怨','[]','月在碧虚中住。',48,'宋词/ci.song.6000.json','["月在碧虚中住。", "人向乱荷中去。", "花气杂风凉。", "满船香。", "云被歌声摇动。", "酒被诗情掇送。", "醉里卧花心。", "拥红衾。"]'),
('song-ci-324','霜天晓角','张鎡','宋','宋词','song-ci','霜天晓角','[]','荷花闲拨。',53,'宋词/ci.song.6000.json','["荷花闲拨。", "撑破玻璃滑。", "拂拂香风微度，吹雪乱、数根发。", "弄泉罗盖匝。", "万颗真珠撒。", "唱我莲歌归去，凌波步、水仙袜。"]'),
('song-ci-325','如梦令','张鎡','宋','宋词','song-ci','如梦令','[]','人在骖鸾深院。',40,'宋词/ci.song.6000.json','["人在骖鸾深院。", "误认落梅疏片。", "零乱舞东风，云淡水平天远。", "帘卷。", "帘卷。", "飞上绣裀不见。"]'),
('song-ci-326','南乡子','张鎡','宋','宋词','song-ci','南乡子','[]','翠袖怯春寒。',66,'宋词/ci.song.6000.json','["翠袖怯春寒。", "对雪偏宜傍彩阑。", "弱骨丰肌无限韵，凭肩。", "共看南窗玉数竿。", "羔酒莫留残。", "更觉娇随饮量宽。", "小立妖娇何所似，风前。", "柳絮飞时见牡丹。"]'),
('song-ci-327','乌夜啼','张鎡','宋','宋词','song-ci','乌夜啼','[]','月儿犹未全明。',45,'宋词/ci.song.6000.json','["月儿犹未全明。", "乞怜生。", "几片彩云来去、更风轻。", "应见我。", "行又坐。", "苦凝情。", "卷起帘儿不睡、到三更。"]'),
('song-ci-328','菩萨蛮','张鎡','宋','宋词','song-ci','菩萨蛮','[]','风流不把花为主。',52,'宋词/ci.song.6000.json','["风流不把花为主。", "多情管定烟和雨。", "潇洒绿衣长。", "满身无限凉。", "文笺舒卷处。", "似索题诗句。", "莫凭小阑干。", "月明生夜寒。"]'),
('song-ci-329','菩萨蛮','张鎡','宋','宋词','song-ci','菩萨蛮','[]','前生曾是风流侣。',52,'宋词/ci.song.6000.json','["前生曾是风流侣。", "返魂却向南枝住。", "疏影卧晴溪。", "恰如沙暖时。", "绿窗娇插鬓。", "依约犹交颈。", "微笑语还羞。", "愿郎同白头。"]'),
('song-ci-330','菩萨蛮','张鎡','宋','宋词','song-ci','菩萨蛮','[]','藤床巧织波文小。',52,'宋词/ci.song.6000.json','["藤床巧织波文小。", "翻书欲睡莺惊觉。", "绕舍灿明霞。", "短长旌节花。", "此身无系著。", "南北东西乐。", "碧宇朗吟归。", "天风香染衣。"]'),
('song-ci-331','折丹桂','张鎡','宋','宋词','song-ci','折丹桂','[]','玉为楼观银为地。',60,'宋词/ci.song.6000.json','["玉为楼观银为地。", "秋到中分际。", "淡金光衬水晶球，上碧虚、千万里。", "香风浩荡吹蟾桂。", "影落澄波底。", "揭天箫鼓要诗成，任惊觉、鱼龙睡。"]'),
('song-ci-332','清平乐','张鎡','宋','宋词','song-ci','清平乐','[]','苍涯叠嶂。',54,'宋词/ci.song.6000.json','["苍涯叠嶂。", "有路梯云上。", "忽见地平方数丈。", "坐石风林相向。", "凤膺时作龙声。", "夜深惊动寒星。", "几点光芒欲下，傍人头上来听。"]'),
('song-ci-333','清平乐','张鎡','宋','宋词','song-ci','清平乐','[]','猬房秋熟。',54,'宋词/ci.song.6000.json','["猬房秋熟。", "紫实包黄玉。", "吹叶风高销旧绿。", "疏影半遮茅屋。", "山居未觉全贫。", "园收今岁盈囷。", "自拨砖炉松火，细煨分饷幽人。"]'),
('song-ci-334','谒金门','张鎡','宋','宋词','song-ci','谒金门','[]','秋淡淡。',53,'宋词/ci.song.6000.json','["秋淡淡。", "弥望暮天云暗。", "窗小新糊便老眼。", "不应疏酒盏。", "菊净橙香霜晚。", "何处数声来雁。", "飞下湖边红蓼岸。", "有诗方许看。"]'),
('song-ci-335','谒金门','张鎡','宋','宋词','song-ci','谒金门','["\u897f\u6e56"]','何许住。',53,'宋词/ci.song.6000.json','["何许住。", "不属西湖烟雨。", "雪后偏怜香猛处。", "全胜开半树。", "试倩暖云收贮。", "桃杏尽教羞妒。", "只把新词林下去。", "一春休著雨。"]'),
('song-ci-336','柳梢青','张鎡','宋','宋词','song-ci','柳梢青','[]','一望清溪。',61,'宋词/ci.song.6000.json','["一望清溪。", "两堤翠阴，半纸新诗。", "凉满衣裳，香生笔砚，风动窗扉。", "月明撑过船儿。", "载龙玉、双娥对吹。", "竹外山亭，花边水槛，不醉休归。"]'),
('song-ci-337','柳梢青','张鎡','宋','宋词','song-ci','柳梢青','[]','烟淡波平。',61,'宋词/ci.song.6000.json','["烟淡波平。", "蓬松岸蓼，红浅红深。", "满院西风，连宵良月，几处清砧。", "区区宦海浮沈。", "幸隐去、将愁素心。", "两鬓吴霜，一屏秦梦，谁是知音。"]'),
('song-ci-338','柳梢青','张鎡','宋','宋词','song-ci','柳梢青','[]','雨后天涯。',61,'宋词/ci.song.6000.json','["雨后天涯。", "微云送晚，过尽归鸦。", "何处开尊，海棠亭小，飞燕风斜。", "有人粲玉娇花。", "更翳凤、曾游帝家。", "长远身心，温柔情态，不枉多他。"]'),
('song-ci-339','好事近','张鎡','宋','宋词','song-ci','好事近','[]','手种满阑花，瑞露一枝先坼。',53,'宋词/ci.song.6000.json','["手种满阑花，瑞露一枝先坼。", "拄个杖儿来看，两三人门客。", "今朝欢笑且衔杯，休更问明日。", "此意悠然谁会，有湖边风月。"]'),
('song-ci-340','诉衷情','张鎡','宋','宋词','song-ci','诉衷情','[]','筠笼白雁得时双。',54,'宋词/ci.song.6000.json','["筠笼白雁得时双。", "一自戏回塘。", "冰魂问归何处，明月影中藏。", "苹蓼岸，镇相将。", "忍思量。", "晓昏应是，梦绕江湖，怕见鸳鸯。"]'),
('song-ci-341','浣溪沙','张鎡','宋','宋词','song-ci','浣溪沙','[]','无计长留月里花。',48,'宋词/ci.song.6000.json','["无计长留月里花。", "收英巧付火前茶。", "绿尘飞处粉芳华。", "午夜露浓天竺径，一秋香满玉川家。", "扫除残梦入云涯。"]'),
('song-ci-342','虞美人','张鎡','宋','宋词','song-ci','虞美人','[]','妆浓未试芙蓉脸。',66,'宋词/ci.song.6000.json','["妆浓未试芙蓉脸。", "却扇凉犹浅。", "粉轻红袅一生娇。", "风外细香时伴、湿云飘。", "双飞属玉来还去。", "谁识幽闲趣。", "莫教疏雨暗黄昏。", "已是不禁秋色、怕销魂。"]'),
('song-ci-343','玉团儿','张鎡','宋','宋词','song-ci','玉团儿','[]','晓来一阵金风劣。',64,'宋词/ci.song.6000.json','["晓来一阵金风劣。", "把阆海、檀霞细屑。", "依就花儿，深藏叶底，不教人折。", "初开数朵谁知得。", "却又是、金风漏泄。", "吹起清芬，露成香露，月成香月。"]'),
('song-ci-344','眼儿媚','张鎡','宋','宋词','song-ci','眼儿媚','[]','凄风吹露湿银床。',58,'宋词/ci.song.6000.json','["凄风吹露湿银床。", "凉月到西厢。", "蛩声未苦，桐阴先瘦，愁与更长。", "起来没个人偢采，枕上越思量。", "眼儿业重，假饶略睡，又且何妨。"]'),
('song-ci-345','眼儿媚','张鎡','宋','宋词','song-ci','眼儿媚','[]','山矾风味木樨魂。',58,'宋词/ci.song.6000.json','["山矾风味木樨魂。", "高树绿堆云。", "水光殿侧，月华楼畔，晴雪纷纷。", "何如且向南湖住，深映竹边门。", "月儿照著，风儿吹动，香了黄昏。"]'),
('song-ci-346','眼儿媚','张鎡','宋','宋词','song-ci','眼儿媚','[]','玄霜凉夜铸瑶丹。',58,'宋词/ci.song.6000.json','["玄霜凉夜铸瑶丹。", "飘落翠藤间。", "西风万颗，明珠巧缀，零露初漙。", "诗人那识风流品，马乳漫堆盘。", "玉纤旋摘，银罂分酿，莫负清欢。"]'),
('song-ci-347','南歌子','张鎡','宋','宋词','song-ci','南歌子','[]','种玉能延命，居山易学仙。',62,'宋词/ci.song.6000.json','["种玉能延命，居山易学仙。", "青青一亩自锄烟。", "雾孕云蒸、肌骨更凝坚。", "熟染蜂房蜜，清添石鼎泉。", "雪香酥腻老来便。", "煨芋炉深、却笑祖师禅。"]'),
('song-ci-348','鹧鸪天','张鎡','宋','宋词','song-ci','鹧鸪天','[]','阴阴一架绀云凉。',64,'宋词/ci.song.6000.json','["阴阴一架绀云凉。", "袅袅千丝翠蔓长。", "紫玉乳圆秋结穗，水晶珠莹露凝浆。", "相并熟，试新尝。", "累累轻翦粉痕香。", "小槽压就西凉酒，风月无边是醉乡。"]'),
('song-ci-349','江城子','张鎡','宋','宋词','song-ci','江城子','[]','试霜池面浅粼粼。',86,'宋词/ci.song.6000.json','["试霜池面浅粼粼。", "鹊飞晴。", "远峰明。", "蓬岛群仙，来过瑞云清。", "龙榜当年人第一，黄叔度，是前生。", "玉堂行见演丝纶。", "彩毫轻。", "思难停。", "醉里长鲸，翻浪吸东溟。", "谢女风流相称好，今母更，鬓常青。"]'),
('song-ci-350','江城子','张鎡','宋','宋词','song-ci','江城子','[]','春风旗鼓石头城。',86,'宋词/ci.song.6000.json','["春风旗鼓石头城。", "急麾兵。", "斩长鲸。", "缓带轻裘，乘胜讨蛮荆。", "蚁聚蜂屯三十万，军面缚，赴行营。", "舳舻千里大江横。", "凯歌声。", "犬羊惊。", "尊俎风流，谈笑酒徐倾。", "北望旄头今已灭，河汉淡，两台星。"]'),
('song-ci-351','卜算子','张鎡','宋','宋词','song-ci','卜算子','[]','常记十年前，共醉梅边路。',52,'宋词/ci.song.6000.json','["常记十年前，共醉梅边路。", "别后频收尺素书，依旧情相与。", "早愿却来看，玉照花深处。", "风暖还听柳际莺，休唱闲居赋。"]'),
('song-ci-352','杨柳枝','张鎡','宋','宋词','song-ci','杨柳枝','[]','绿蜡芽疏雪一包。',48,'宋词/ci.song.6000.json','["绿蜡芽疏雪一包。", "绽云梢。", "清香却暑置堂坳。", "晚风飘。", "冰雹无声栖碧叶，笑仍娇。", "相随茉莉展轻绡。", "伴凉宵。"]'),
('song-ci-353','感皇恩','张鎡','宋','宋词','song-ci','感皇恩','[]','诗眼看青天，几多虚旷。',85,'宋词/ci.song.6000.json','["诗眼看青天，几多虚旷。", "雨过凉生气萧爽。", "白云无定，吹散作、鳞鳞琼浪。", "尚馀星数点，浮空上。", "明月飞来，寒光磨荡。", "仿佛轮间桂枝长。", "倚风归去，纵长啸、一声悠扬。", "乡摇山岳影，秋悲壮。"]'),
('song-ci-354','夜游宫','张鎡','宋','宋词','song-ci','夜游宫','[]','鹊相庞儿谁有。',71,'宋词/ci.song.6000.json','["鹊相庞儿谁有。", "兀底便、笔描不就。", "小邈如何敢出手。", "细端相，甚精神、甚洗漱。", "到老长厮守。", "不吃饭、也须唧𠺕。", "你待包弹怎开口。", "暖底雪，活底花，嫩底柳。"]'),
('song-ci-355','醉高楼','张鎡','宋','宋词','song-ci','醉高楼','[]','浮云散，天似碧琉璃。',102,'宋词/ci.song.6000.json','["浮云散，天似碧琉璃。", "月正是、上弦时。", "姮娥蟾兔俱何在，广寒宫殿不应亏。", "这神功，千万世，有谁知。", "甚知解、催人须鬓老。", "更不算、将人情绪恼。", "撺掇酒，撼摇诗。", "山头望伴疏星落，庭前看照好花移。", "夜无眠，应笑我，怎如痴。"]'),
('song-ci-356','蝶恋花','张鎡','宋','宋词','song-ci','蝶恋花','[]','杨柳秋千旗斗舞。',70,'宋词/ci.song.6000.json','["杨柳秋千旗斗舞。", "漠漠轻烟，罩定黄鹂语。", "红滴海棠娇半吐。", "燕脂水似朝来雨。", "行过池边携手路。", "都把多情，变作无情绪。", "惟有东风知住处。", "凭君送取温存去。"]'),
('song-ci-357','蝶恋花','张鎡','宋','宋词','song-ci','蝶恋花','[]','门外沧洲山色近。',70,'宋词/ci.song.6000.json','["门外沧洲山色近。", "鸥鹭双双，恼乱行云影。", "翠拥高筠阴满径。", "帘垂尽日林堂静。", "明月飞来烟欲暝。", "水面天心，两个黄金镜。", "慢飐轻摇风不定。", "渔歌欸乃谁同听。"]'),
('song-ci-358','蝶恋花','张鎡','宋','宋词','song-ci','蝶恋花','[]','洒面松风凉似水。',70,'宋词/ci.song.6000.json','["洒面松风凉似水。", "下看冰泉，喷薄溪桥底。", "叠叠层峰相对起。", "家居却在深山里。", "枝上凌霄红绕翠。", "飘下红英，翠影争摇曳。", "今夜岩扉休早闭。", "月明定有飞仙至。"]'),
('song-ci-359','鹊桥仙','张鎡','宋','宋词','song-ci','鹊桥仙','[]','暑云犹在，澄空欲变，入夜俳徊庭际。',68,'宋词/ci.song.6000.json','["暑云犹在，澄空欲变，入夜俳徊庭际。", "新秋知是昨宵来，爱残月、纤纤西坠。", "芭蕉老大，流萤衰倦，静里细观天意。", "轻风未有半分凉，奈人道、今宵好睡。"]'),
('song-ci-360','鹊桥仙','张鎡','宋','宋词','song-ci','鹊桥仙','[]','连汀接渚，萦蒲带藻，万镜香浮光满。',68,'宋词/ci.song.6000.json','["连汀接渚，萦蒲带藻，万镜香浮光满。", "湿烟吹霁木栏轻，照波底、红娇翠腕。", "玉纤采处，银笼携去，一曲山长水远。", "采鸳双惯贴人飞，恨南浦、离多梦短。"]'),
('song-ci-361','鹧鸪天','张鎡','宋','宋词','song-ci','鹧鸪天','[]','闲立飞虹远兴长。',64,'宋词/ci.song.6000.json','["闲立飞虹远兴长。", "一方云锦荐疏凉。", "翻风翠盖无尘土，出水红妆有艳香。", "携靓侣，泛轻航。", "棹歌惊起野鸳鸯。", "同过清夏看新月，茉莉花园小象床。"]'),
('song-ci-362','鹧鸪天','张鎡','宋','宋词','song-ci','鹧鸪天','[]','不似琵琶不似琴。',64,'宋词/ci.song.6000.json','["不似琵琶不似琴。", "四弦陶写晋人心。", "指尖历历泉鸣涧，腹上锵锵玉振金。", "天外曲，月边音。", "为君转轴拟秋砧。", "又成雅集相依坐，清致高标记竹林。"]'),
('song-ci-363','临江仙','张鎡','宋','宋词','song-ci','临江仙','[]','七个圈儿为岁数，年年用墨糊涂。',70,'宋词/ci.song.6000.json','["七个圈儿为岁数，年年用墨糊涂。", "一圈又剩半圈馀。", "看看云蔽月，三际等空虚。", "纵使古稀真个得，后来争免呜呼。", "肯闲何必更悬车。", "非关轻利禄，自是没工夫。"]'),
('song-ci-364','御街行','张鎡','宋','宋词','song-ci','御街行','[]','良宵无意贪游玩。',94,'宋词/ci.song.6000.json','["良宵无意贪游玩。", "奈怜友、闲呼唤。", "六街非是少人行，不似旧时风范。", "笙歌零落，绮罗销减，枉了心情看。", "思量往事堪肠断。", "怕频到、帘儿畔。", "朦胧月下却归来，指望阿谁收管。", "低头注定，两汪儿泪，百计难销遣。"]'),
('song-ci-365','满庭芳','张鎡','宋','宋词','song-ci','满庭芳','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','月洗高梧，露漙幽草，宝钗楼外秋深。',118,'宋词/ci.song.6000.json','["月洗高梧，露漙幽草，宝钗楼外秋深。", "土花沿翠，萤火坠墙阴。", "静听寒声断续，微韵转、凄咽悲沈。", "争求侣，殷勤劝织，促破晓机心。", "儿时，曾记得，呼灯灌穴，敛步随音。", "任满身花影，犹自追寻。", "携向花堂戏斗，亭台小、笼巧妆金。", "今休说，从渠床下，凉夜伴孤吟。"]'),
('song-ci-366','风入松','张鎡','宋','宋词','song-ci','风入松','[]','小樊标韵称香山。',88,'宋词/ci.song.6000.json','["小樊标韵称香山。", "压尽花间。", "便须著个楼儿住，彩鸾看、飞舞妖闲。", "珠佩时因醉解，云扉常为春关。", "耳边属付话儿奸。", "休放蛮檀。", "绿窗惟怕今宵梦，莺声巧、春满阑干。", "待把衷肠教与，却愁长远都难。"]'),
('song-ci-367','浣溪沙','高观国','宋','宋词','song-ci','浣溪沙','[]','魂是湘云骨是兰。',48,'宋词/ci.song.6000.json','["魂是湘云骨是兰。", "春风冰玉注芳颜。", "谁招仙子在人间。", "溅水裙儿香雾皱，唾花衫子碧云寒。", "洞箫声绝却骖鸾。"]'),
('song-ci-368','浣溪沙','高观国','宋','宋词','song-ci','浣溪沙','[]','偷得韩香惜未烧。',48,'宋词/ci.song.6000.json','["偷得韩香惜未烧。", "吹箫人在月明桥。", "草芳似待玉骢骄。", "吹絮绣帘春澹澹，隔香罗帐夜迢迢。", "楚魂须著楚词招。"]'),
('song-ci-369','浣溪沙','高观国','宋','宋词','song-ci','浣溪沙','[]','云外峰峦翠欲埋。',48,'宋词/ci.song.6000.json','["云外峰峦翠欲埋。", "雨沾黄叶湿青鞋。", "小惊春色入寒荄。", "风月愁新空雁字，神仙梦冷忆鸾钗。", "凄凉不是好情怀。"]'),
('song-ci-370','浣溪沙','高观国','宋','宋词','song-ci','浣溪沙','[]','一色烟云澹不消。',48,'宋词/ci.song.6000.json','["一色烟云澹不消。", "两峰眉黛为谁娇。", "春寒犹占木兰桡。", "燕子似甘愁寂寞，海棠未肯醉妖娆。", "小园嫩约尚萧条。"]'),
('song-ci-371','兰陵王','高观国','宋','宋词','song-ci','兰陵王','[]','凤箫咽。',158,'宋词/ci.song.6000.json','["凤箫咽。", "花底寒轻夜月。", "兰堂静，香雾翠深，曾与瑶姬恨轻别。", "罗巾泪暗叠。", "情人歌声怨切。", "殷勤意，欲去又留，柳色和愁为重折。", "十年迥凄绝。", "念髻怯瑶簪，衣褪香雪。", "双鳞不渡烟江阔。", "自春来人见，水边花外，羞倚东风翠袖怯。", "正愁恨时节。", "南陌。", "阻金勒。", "甚望断青禽，难倩红叶。", "春愁欲解丁香结。", "整新欢罗带，旧香宫箧。", "凄凉风景，待见了，尽向说。"]'),
('song-ci-372','兰陵王','高观国','宋','宋词','song-ci','兰陵王','[]','洒虚阁。',158,'宋词/ci.song.6000.json','["洒虚阁。", "幂幂天垂似幕。", "春寒峭，吹断万丝，湿影和烟暗帘箔。", "清愁晚来觉。", "佳景愔愔过却。", "芳郊外，莺恨燕愁，不管秋千冷红索。", "行云楚台约。", "念今古凝情，朝暮如昨。", "啼红湿翠春情薄。", "谩一犁江上，半篙堤外，勾引轻阴趁暮角。", "正孤绪寂寞。", "斑驳。", "止还作。", "听点点檐声，沈沈春酌。", "只愁入夜东风恶。", "怕催教花放，趁将花落。", "冥冥烟草，梦正远，恨怎托。"]'),
('song-ci-373','水龙吟','高观国','宋','宋词','song-ci','水龙吟','[]','旧家心绪如云，乍舒乍卷初无定。',126,'宋词/ci.song.6000.json','["旧家心绪如云，乍舒乍卷初无定。", "西郊载雨，东城隔雾，还开晴景。", "爱恼花阴，喜移月地，朦胧清影。", "任无心有意，溶溶曳曳，萧散处、有谁问。", "朝暮如今难准。", "枉教他、惜春人恨。", "远峰依旧，前踪何在，有时愁凝。", "此兴飘然，不妨吹断，一川轻暝。", "待良宵，再入高唐梦里，觅巫阳信。"]'),
('song-ci-374','水龙吟','高观国','宋','宋词','song-ci','水龙吟','[]','道山玉府真仙，去年再履论思地。',126,'宋词/ci.song.6000.json','["道山玉府真仙，去年再履论思地。", "西清禁域，眷深名重，年高身退。", "玉振金声，水增川涌，德兼才贵。", "爱知章引去，安车稳驾，轩冕付、谈笑外。", "兰玉孙枝竞秀，奉亲欢、莱衣同戏。", "蓬莱东接，苎萝西顾，三山耸翠。", "赐杖清朝，命堂绿野，放怀高致。", "似太公出将，卫公入相，为苍生起。"]'),
('song-ci-375','水龙吟','高观国','宋','宋词','song-ci','水龙吟','[]','夜来曾跨青虬，海风袅袅吹襟袖。',126,'宋词/ci.song.6000.json','["夜来曾跨青虬，海风袅袅吹襟袖。", "蓬莱误入，群仙争问，刘郎安否。", "玉尘冰壶，日庭星角，孕成奇秀。", "看丹分宝鼎，箓传秘箧，闻重寄、长生酒。", "归梦惊回晓漏。", "正长庚、辉躔南斗。", "祥开华旦，菊香秋杪，枨黄霜后。", "笔扫龙蛇，句裁螭锦，俊才谁右。", "看功勋绣衮，家声再振，数千龄寿。"]'),
('song-ci-376','声声慢','高观国','宋','宋词','song-ci','声声慢','[]','壶天不夜，宝炷生香，光风荡摇金碧。',119,'宋词/ci.song.6000.json','["壶天不夜，宝炷生香，光风荡摇金碧。", "月滟冰痕，花外峭寒无力。", "歌传翠帘尽卷，误惊回、瑶台仙迹。", "禁漏促，拼千金一刻，未酬佳夕。", "卷地香尘不断，最得意、输他五陵狂客。", "楚柳吴梅，无限眼边春色。", "鲛绡暗中寄与，待重寻、行云消息。", "乍醉醒，怕南楼、吹断晓笛。"]'),
('song-ci-377','隔浦莲・隔浦莲近拍','高观国','宋','宋词','song-ci','隔浦莲・隔浦莲近拍','[]','银湾初霁暮雨。',88,'宋词/ci.song.6000.json','["银湾初霁暮雨。", "鹊赴秋期去。", "浅月窥清夜，凉生一天风露。", "纤巧云暗度。", "河桥路。", "缥缈乘鸾女。", "正容与。", "西厢旧约，玉娇谁见私语。", "柔情不尽，好似冰绡云缕。", "回首天涯又怨阻。", "无语。", "西风魂断机杼。"]'),
('song-ci-378','思佳客','高观国','宋','宋词','song-ci','思佳客','[]','入手西风意已羞。',64,'宋词/ci.song.6000.json','["入手西风意已羞。", "不须玉斧为重修。", "扑萤凉夜沈沈月，障面清歌澹澹秋。", "休弃置，且迟留。", "可怜又向箧中收。", "莫教暗损乘鸾女，汉殿凄凉万古愁。"]'),
('song-ci-379','思佳客','高观国','宋','宋词','song-ci','思佳客','[]','写出梨花雨后晴。',64,'宋词/ci.song.6000.json','["写出梨花雨后晴。", "凝脂洗尽见天真。", "春从翠髻堆边见，娇自红绡脱处生。", "天宝梦，马嵬尘。", "断魂无复到华清。", "恰如伫立东风里，犹听霓裳羯鼓声。"]'),
('song-ci-380','思佳客','高观国','宋','宋词','song-ci','思佳客','[]','有约湖山却解襟。',64,'宋词/ci.song.6000.json','["有约湖山却解襟。", "昼眠占得一庭深。", "树边风色寒滋味，愁里年华雁信音。", "惊楚梦，听瑶琴。", "黄花尚可伴孤斟。", "断云万一成疏雨，却向湖边看晚阴。"]'),
('song-ci-381','思佳客','高观国','宋','宋词','song-ci','思佳客','[]','翦翠衫儿稳四停。',64,'宋词/ci.song.6000.json','["翦翠衫儿稳四停。", "最怜一曲凤箫吟。", "同心罗帕轻藏素，合字香囊半影金。", "春思悄，昼窗深。", "谁能拘束少年心。", "莺来惊碎风流胆，踏动樱桃叶底铃。"]'),
('song-ci-382','思佳客','高观国','宋','宋词','song-ci','思佳客','[]','不肯楼边著画船。',64,'宋词/ci.song.6000.json','["不肯楼边著画船。", "载将诗酒入风烟。", "浪花溅白疑飞鹭，荷芰藏红似小莲。", "醒醉梦，唤吟仙。", "先秋一叶莫惊蝉。", "白云乡里温柔远，结得清凉世界缘。"]'),
('song-ci-383','思佳客','高观国','宋','宋词','song-ci','思佳客','[]','白玉楼台知几重。',64,'宋词/ci.song.6000.json','["白玉楼台知几重。", "夜来望断广寒宫。", "一分乍阙婵娟影，二八尤宜冰雪容。", "云鬓露，玉钗风。", "水晶帘幕正玲珑。", "殷勤再为天香醉，可惜清光付晓钟。"]'),
('song-ci-384','永遇乐','高观国','宋','宋词','song-ci','永遇乐','[]','浅晕修娥，脆痕红粉，犹记窥户。',128,'宋词/ci.song.6000.json','["浅晕修娥，脆痕红粉，犹记窥户。", "香断帘空，尘生砌冷，谁唤青鸾舞。", "春风花信，秋宵月约，历历此心曾许。", "衔芳恨、千年怨结，玉骨未应成土。", "木兰艇子，莫愁何在，谩系寒江烟树。", "事逐云沈，情随佩冷，短梦分今古。", "一杯遥夜，孤光难晓，多少碎人肠处。", "空凄黯、西风细雨，尽吹泪去。"]'),
('song-ci-385','玲珑四犯','高观国','宋','宋词','song-ci','玲珑四犯','[]','水外轻阴，做弄得飞云，吹断晴絮。',123,'宋词/ci.song.6000.json','["水外轻阴，做弄得飞云，吹断晴絮。", "驻马桥西，还系旧时芳树。", "不见翠陌寻春，每问著、小桃无语。", "恨燕莺、不识闲情，却隔乱红飞去。", "少年曾识春风意，到如今、怨怀难诉。", "魂惊冉冉江南远，烟草愁如许。", "此意待写翠笺，奈断肠、都无新句。", "问甚时、舞凤歌鸾，花里再看仙侣。"]'),
('song-ci-386','御街行','高观国','宋','宋词','song-ci','御街行','[]','香波半窣深深院。',100,'宋词/ci.song.6000.json','["香波半窣深深院。", "正日上、花阴浅。", "青丝不动玉钩闲，看翠额、轻笼葱茜。", "莺声似隔，篆醒微度，爱横影、参差满。", "那回低挂朱阑畔。", "念闲损、无人卷。", "窥春偷倚不胜情，彷佛见、如花娇面。", "纤柔缓揭，瞥然飞去，不似春风燕。"]'),
('song-ci-387','御街行','高观国','宋','宋词','song-ci','御街行','[]','藤筠巧织花纹细。',100,'宋词/ci.song.6000.json','["藤筠巧织花纹细。", "称稳步、如流水。", "踏青陌上雨初晴，嫌怕湿、文鸳双履。", "要人送上，逢花须住，才过处、香风起。", "裙儿挂在帘儿底。", "更不把、窗儿闭。", "红红白白簇花枝，恰称得、寻春芳意。", "归来时晚，纱笼引道，扶下人微醉。"]'),
('song-ci-388','霜天晓角','高观国','宋','宋词','song-ci','霜天晓角','["\u897f\u6e56"]','春云粉色。',54,'宋词/ci.song.6000.json','["春云粉色。", "春水和云湿。", "试问西湖杨柳，东风外、几丝碧。", "望极。", "连翠陌。", "兰桡双桨急。", "欲访莫愁何处，旗亭在、画桥侧。"]'),
('song-ci-389','霜天晓角','高观国','宋','宋词','song-ci','霜天晓角','[]','炉烟浥浥。',54,'宋词/ci.song.6000.json','["炉烟浥浥。", "花露蒸沈液。", "不用宝钗翻炷，闲窗下、袅轻碧。", "醉拍。", "罗袖惜。", "春风偷染得。", "占取风流声价，韩郎是、旧相识。"]'),
('song-ci-390','霜天晓角','高观国','宋','宋词','song-ci','霜天晓角','[]','霜清水碧。',54,'宋词/ci.song.6000.json','["霜清水碧。", "冷浸红云湿。", "休说季伦锦帐，山南岸、更花密。", "露滴。", "空翠幂。", "两峰开霁色。", "不为浓妆一醉，西风帽、为谁侧。"]'),
('song-ci-391','眼儿媚','高观国','宋','宋词','song-ci','眼儿媚','[]','轻云终被断云留。',58,'宋词/ci.song.6000.json','["轻云终被断云留。", "不肯放春愁。", "翠楼旧倚，粉墙重见，歌酒风流。", "今朝毕竟吟情澹，芳意未全酬。", "东风向晚，莺花有意，吹转船头。"]'),
('song-ci-392','卜算子','高观国','宋','宋词','song-ci','卜算子','[]','屈指数春来，弹指惊春去。',52,'宋词/ci.song.6000.json','["屈指数春来，弹指惊春去。", "檐外蛛丝网落花，也要留春住。", "几日喜春晴，几夜愁春雨。", "十二雕窗六曲屏，题遍伤春句。"]'),
('song-ci-393','西江月','高观国','宋','宋词','song-ci','西江月','[]','小舫半帘山色，断桥两岸秋阴。',58,'宋词/ci.song.6000.json','["小舫半帘山色，断桥两岸秋阴。", "芙蓉消息已愁深。", "红染云机翠锦。", "几度烟波共酌，半生风月关心。", "飞来鸥鹭是知音。", "一笑歌边醉醒。"]'),
('song-ci-394','点绛唇','高观国','宋','宋词','song-ci','点绛唇','[]','天外青鸾，几时常向人间住。',50,'宋词/ci.song.6000.json','["天外青鸾，几时常向人间住。", "断歌零舞。", "月上桐阴暮。", "憔悴潘郎，不解为花主。", "知何处。", "梦云愁雨。", "怕向西楼去。"]'),
('song-ci-395','点绛唇','高观国','宋','宋词','song-ci','点绛唇','[]','钓月蓬闲，载诗却向旗亭醉。',50,'宋词/ci.song.6000.json','["钓月蓬闲，载诗却向旗亭醉。", "翠蒲阴外。", "莫放双鸥起。", "水佩仙裳，酒落烟云意。", "来相试。", "玉绡新制。", "要写蓬壶记。"]'),
('song-ci-396','踏莎行','高观国','宋','宋词','song-ci','踏莎行','[]','水减堤痕，秋生屐齿。',68,'宋词/ci.song.6000.json','["水减堤痕，秋生屐齿。", "瘦筇唤起登高意。", "翠烟微冷梦凄凉，黄花香晚人憔悴。", "怀古风流，悲秋情味。", "紫萸劝入旗亭醉。", "玉人相见说新愁，可怜又湿西风泪。"]'),
('song-ci-397','踏莎行','高观国','宋','宋词','song-ci','踏莎行','[]','花染烟香，柳摇风翠。',68,'宋词/ci.song.6000.json','["花染烟香，柳摇风翠。", "春工写出清明意。", "翠湾还趁画船开，粉墙到处骄骢系。", "歌唤红裙，酒招青旆。", "吟情又许春风醉。", "何妨日日烂芳游，今宵先向西城睡。"]'),
('song-ci-398','恋绣衾','高观国','宋','宋词','song-ci','恋绣衾','[]','碧梧偷恋小窗阴。',68,'宋词/ci.song.6000.json','["碧梧偷恋小窗阴。", "恨芭蕉、不展寸心。", "暗语近、阳台远，奈秋宵、砧断漏沈。", "月明欲教吹箫去。", "隔骖鸾、空留怨音。", "从此是、天涯阻，这一场、愁梦更深。"]'),
('song-ci-399','风入松','高观国','宋','宋词','song-ci','风入松','[]','卷帘日日恨春阴。',88,'宋词/ci.song.6000.json','["卷帘日日恨春阴。", "寒食新晴。", "马蹄只向南山去，长桥爱、花柳多情。", "红外风娇日暖，翠边水秀山明。", "杜郎歌酒过平生。", "到处蓬瀛。", "醉魂不入重城晚，浓欢寄、桃叶桃根。", "绣被嫩寒清晓，莺声唤醒春酲。"]'),
('song-ci-400','风入松','高观国','宋','宋词','song-ci','风入松','[]','粉娇曾隔翠帘看。',88,'宋词/ci.song.6000.json','["粉娇曾隔翠帘看。", "横玉声寒。", "夜深不管柔荑冷，樱朱度、香喷云鬟。", "霜月摇摇吹落，梅花簌簌惊残。", "萧郎且放凤箫闲。", "何处骖鸾。", "静听三弄霓裳罢，魂飞断、愁里关山。", "三十六宫天近，念奴却在人间。"]'),
('song-ci-401','南乡子','高观国','宋','宋词','song-ci','南乡子','[]','直柱倚冰弦。',66,'宋词/ci.song.6000.json','["直柱倚冰弦。", "曾见胡儿马上弹。", "却笑琵琶风韵古，溅溅。", "想像湘妃水一帘。", "塞恨曲中传。", "两摺琴丝费玉纤。", "不似江南风月好，厌厌。", "拍手齐看舞袖边。"]'),
('song-ci-402','洞仙歌','高观国','宋','宋词','song-ci','洞仙歌','[]','轻痕浅晕。',102,'宋词/ci.song.6000.json','["轻痕浅晕。", "偷染春风面。", "恰似西施影儿现。", "拟新妆、临槛一段天真，闲态度，长恁香娇玉软。", "从今怀袖里，不暂相离，似笑如颦任舒卷。", "顾芳容不老，只似如今，娇不语、无奈情深意远。", "便雨隔云疏暂分携，也时展丹青，见伊一见。"]'),
('song-ci-403','柳梢青','高观国','宋','宋词','song-ci','柳梢青','[]','翠拂晴波，烟垂古岸，灞桥春色。',61,'宋词/ci.song.6000.json','["翠拂晴波，烟垂古岸，灞桥春色。", "斜带鸦啼，乱萦莺梦，愁丝如织。", "为怜张绪风流，正瘦损、宫腰褪碧。", "绽绾同心，留连不住，天涯行客。"]'),
('song-ci-404','少年游','高观国','宋','宋词','song-ci','少年游','[]','春风吹碧，春云映绿，晓梦入芳裀。',62,'宋词/ci.song.6000.json','["春风吹碧，春云映绿，晓梦入芳裀。", "软衬飞花，远连流水，一望隔香尘。", "萋萋多少江南恨，翻忆翠罗裙。", "冷落闲门，凄迷古道，烟雨正愁人。"]'),
('song-ci-405','诉衷情','高观国','宋','宋词','song-ci','诉衷情','[]','西楼杨柳未胜烟。',54,'宋词/ci.song.6000.json','["西楼杨柳未胜烟。", "寒峭落梅天。", "东风渡头波晚，一棹木兰船。", "花态度，酒因缘。", "只春怜。", "屏开山翠，雨怯云娇，尽付愁边。"]'),
('song-ci-406','夜行船','高观国','宋','宋词','song-ci','夜行船','[]','翦水天风吹醉醒。',68,'宋词/ci.song.6000.json','["翦水天风吹醉醒。", "高楼外、冻云愁凝。", "袖口香寒，歌喉春暖，不管雁边寒紧。", "琼屑瑶花飞碎影。", "应须待、玉田千顷。", "小约梅英，教吟柳絮，春在绣红鸳锦。"]'),
('song-ci-407','满江红','高观国','宋','宋词','song-ci','满江红','[]','击碎空明，沧浪晚、棹歌飞入。',115,'宋词/ci.song.6000.json','["击碎空明，沧浪晚、棹歌飞入。", "西山外、紫霞吹断，赤尘无迹。", "飞上冰轮凉世界，唤回天籁清肌骨。", "看骊珠、影堕冷光斜，蛟龙窟。", "长啸外，纶巾侧。", "轻露下，纤絺湿。", "听洞箫声在，卧虹阴北。", "十万江妃留醉梦，二三沙鸟惊吟魄。", "任天河、落尽玉杯空，东方白。"]'),
('song-ci-408','酹江月・念奴娇','高观国','宋','宋词','song-ci','酹江月・念奴娇','[]','万岩灵秀，拱崇台飞观，凭陵千尺。',120,'宋词/ci.song.6000.json','["万岩灵秀，拱崇台飞观，凭陵千尺。", "清磬一声帘幕冷，无复宫娃消息。", "响屉廊空，采香径古，尘土成遗迹。", "石闲松老，断云空锁愁寂。", "专宠谁比轻颦，楚腰吴艳，一笑无颜色。", "风月荒凉罗绮梦，输与扁舟归客。", "舞阕歌残，国倾人去，青草埋香骨。", "五湖波淼，远空依旧涵碧。"]'),
('song-ci-409','谒金门','高观国','宋','宋词','song-ci','谒金门','[]','烟墅暝。',53,'宋词/ci.song.6000.json','["烟墅暝。", "隔断仙源芳径。", "雨歇花梢魂未醒。", "湿红如有恨。", "别后香车谁整。", "怪得画桥春静。", "碧涨平湖三十顷。", "归云何处问。"]'),
('song-ci-410','留春令','高观国','宋','宋词','song-ci','留春令','[]','断霞低映，小桥流水，一川平远。',61,'宋词/ci.song.6000.json','["断霞低映，小桥流水，一川平远。", "柳影人家起炊烟，彷佛似、江南岸。", "马上东风吹醉面。", "问此情谁管。", "花里清歌酒边情，问何日、重相见。"]'),
('song-ci-411','留春令','高观国','宋','宋词','song-ci','留春令','[]','粉绡轻试，绿裙微褪，吴姬娇小。',61,'宋词/ci.song.6000.json','["粉绡轻试，绿裙微褪，吴姬娇小。", "一点清香著芳魂，便添起、春怀抱。", "玉脸窥人舒浅笑。", "寄此情天渺。", "酒醒罗浮角声寒，正月挂、南枝晓。"]'),
('song-ci-412','留春令','高观国','宋','宋词','song-ci','留春令','[]','玉清冰瘦，洗妆初见，春风头面。',61,'宋词/ci.song.6000.json','["玉清冰瘦，洗妆初见，春风头面。", "等得黄昏月溪寒，爱顾影、临清浅。", "历尽冰霜空羞怨。", "怨粉香消减。", "江北江南旧情多，奈笛里、关山远。"]'),
('song-ci-413','留春令','高观国','宋','宋词','song-ci','留春令','[]','玉妃春醉，夜寒吹堕，江南风月。',61,'宋词/ci.song.6000.json','["玉妃春醉，夜寒吹堕，江南风月。", "一自情留馆娃宫，在竹外、尤清绝。", "贪睡开迟风韵别。", "向杏花休说。", "角冷黄昏艳歌残，怕惊落、燕脂雪。"]'),
('song-ci-414','太常引','高观国','宋','宋词','song-ci','太常引','[]','玉肌轻衬碧霞衣。',62,'宋词/ci.song.6000.json','["玉肌轻衬碧霞衣。", "似争驾、翠鸾飞。", "羞问武陵溪，笑女伴、东风醉时。", "不飘红雨，不贪青子，冷澹却相宜。", "春晚涌金池，问一片、将愁寄谁。"]'),
('song-ci-415','浪淘沙','高观国','宋','宋词','song-ci','浪淘沙','[]','啼魄一天涯。',64,'宋词/ci.song.6000.json','["啼魄一天涯。", "怨入芳华。", "可怜零血染烟霞。", "记得西风秋露冷，曾浼司花。", "明月满窗纱。", "倦客思家。", "故宫春事与愁赊。", "冉冉断魂招不得，翠冷红斜。"]'),
('song-ci-416','意难忘','高观国','宋','宋词','song-ci','意难忘','[]','仙子奇容。',114,'宋词/ci.song.6000.json','["仙子奇容。", "是名花第一，美占春风。", "烟香笼浅翠，露靓浥芳红。", "怜舞燕，惜惊鸿。", "想独步吴宫。", "料认得、娇云媚雨，来自巫峰。", "风流正与欢浓。", "羡高楼并倚，曲影阑东。", "烛摇留醉枕，尘坠恋歌钟。", "三弄笛，五花骢。", "莫行乐匆匆。", "但看取、天长地久，笑语相逢。"]'),
('song-ci-417','雨中花・夜行船','高观国','宋','宋词','song-ci','雨中花・夜行船','["\u897f\u6e56"]','旆拂西风，客应星汉，行参玉节征鞍。',119,'宋词/ci.song.6000.json','["旆拂西风，客应星汉，行参玉节征鞍。", "缓带轻裘，争看盛世衣冠。", "吟倦西湖风月，去看北塞关山，过离宫禾黍，故垒烟尘，有泪应弹。", "文章俊伟，颖露囊锥，名动万里呼韩。", "知素有、平戎手段，小试何难。", "情寄吴梅香冷，梦随陇雁霜寒。", "立勋未晚，归来依旧，酒社诗坛。"]'),
('song-ci-418','八归','高观国','宋','宋词','song-ci','八归','[]','楚峰翠冷，吴波烟远，吹袂万里西风。',135,'宋词/ci.song.6000.json','["楚峰翠冷，吴波烟远，吹袂万里西风。", "关河迥隔新愁外，遥怜倦客音尘，未见征鸿。", "雨帽风巾归梦杳，想吟思、吹入飞蓬。", "料恨满、幽苑离宫。", "正愁黯文通。", "秋浓。", "新霜初试，重阳催近，醉红偷染江枫。", "瘦筇相伴，旧游回首，吹帽知与谁同。", "想萸囊酒盏，暂时冷落菊花丛。", "两凝伫，壮怀立尽，微云斜照中。"]'),
('song-ci-419','瑞鹤仙','高观国','宋','宋词','song-ci','瑞鹤仙','[]','一枝苍玉冷。',126,'宋词/ci.song.6000.json','["一枝苍玉冷。", "爱露节霜根，从来孤劲。", "提携远尘境。", "自清臞骨力，岁寒心性。", "登临助兴。", "甚偏与，芒鞋相称。", "笑葛洪、陂外腾飞，渺渺水闲烟迥。", "寻胜。", "拨开林影，斫破苔痕，缓支幽径。", "分云度岭。", "待随处、问梅信。", "任香挑村醑，寒拖夜月，识尽江山好景。", "扣禅关拗折，归来万缘自静。"]'),
('song-ci-420','蝶恋花','魏了翁','宋','宋词','song-ci','蝶恋花','[]','又见王正班玉瑞。',70,'宋词/ci.song.6000.json','["又见王正班玉瑞。", "霁月光风，恰与元宵际。", "横玉一声天似水。", "阳春到处皆生意。", "十载奔驰今我里。", "昔□元非，未信今皆是。", "风月惺惺人自醉。", "却将醉眼看荣悴。"]'),
('song-ci-421','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','江水自石纽，灌口怒腾辉。',114,'宋词/ci.song.6000.json','["江水自石纽，灌口怒腾辉。", "便如黑水北出，迤逦到三危。", "百尺长虹夭矫，两岸苍龙偃蹇，翠碧互因依。", "古树百夫长，修竹万竿旗。", "画堂开，风与月，巧相随。", "史君领客行乐，旌纛立披披。", "慨想二江遗迹，更起三闾忠愤，此日最为宜。", "推本美功意，禹甸六章诗。"]'),
('song-ci-422','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','轻露沦残暑，蟾影插高寒。',114,'宋词/ci.song.6000.json','["轻露沦残暑，蟾影插高寒。", "团团只似前夕，持向老莱看。", "九帙元开父算，六甲更逢儿换，梧竹拥檀栾。", "都把方寸地，散作万云烟。", "锦边城，云间戌，雪中山。", "风流老监在此，忧顾赖渠宽。", "天上玉颜合笑，堂上酡颜如酒，家国两平安。", "又恐玉川子，茗碗送飞翰。"]'),
('song-ci-423','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','风露浸秋色，烟雨媚湖弦。',114,'宋词/ci.song.6000.json','["风露浸秋色，烟雨媚湖弦。", "旌旗十里小队，拟约醮坛仙。", "身在黄旗朱邸，名在玉皇香案，底事个人传。", "正恐未免耳，惊搅日高眠。", "虎分符，龙握节，鹿御轓。", "於君本亦馀事，所乐不存焉。", "一点春风和气，无限蓝田种子，渺渺玉生烟。", "富贵谁不肯，借问此何缘。"]'),
('song-ci-424','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','万里蜀山险，难似上青天。',114,'宋词/ci.song.6000.json','["万里蜀山险，难似上青天。", "谁知间有，人心之险甚山川。", "赖得皇华星使，满载春风和气，来自鉴湖边。", "要识方寸地，四十万云烟。", "佩珑璁，冠昱炝，组蝉联。", "眼前富贵馀事，所乐不存焉。", "闻道汉家子政，博考兰台载籍，胸次著千年。", "会有太一老，同结海山缘。"]'),
('song-ci-425','念奴娇','魏了翁','宋','宋词','song-ci','念奴娇','[]','万人遮道，拨不断、争挽房湖逐客。',120,'宋词/ci.song.6000.json','["万人遮道，拨不断、争挽房湖逐客。", "臣罪既盈应九死，全荷君王矜恻。", "况是当年，曾将愚技，十字街头立。", "恩波浩荡，孤忠未报涓滴。", "世事应若穿杨，一弦不到，前发皆虚的。", "自判此生元有分，不管筮违龟食。", "靴帽丛中，渔樵席上，无入非吾得。", "倚湖一笑，夜深群动皆息。"]'),
('song-ci-426','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','九十秋光三十八，新居初度称觞。',70,'宋词/ci.song.6000.json','["九十秋光三十八，新居初度称觞。", "青衫彩服列郎娘。", "孙枝无处著，犹欠两东床。", "尽是当年亲手种，如今满院芬芳。", "只凭方寸答苍苍。", "个中无尽藏，谁弱又谁强。"]'),
('song-ci-427','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','细雨斜风驱晓瘴，绰开坦坦长途。',70,'宋词/ci.song.6000.json','["细雨斜风驱晓瘴，绰开坦坦长途。", "膏车秣马问程初。", "梅梢迎候骑，雁影度平芜。", "行己不论官小大，穷探不间精粗。", "只从厚处作规模。", "简编迂事业，屋漏拙功夫。"]'),
('song-ci-428','感皇恩','魏了翁','宋','宋词','song-ci','感皇恩','[]','三峡打头风，吹回荆步。',81,'宋词/ci.song.6000.json','["三峡打头风，吹回荆步。", "坎止流行谩随遇。", "须臾风静，重踏西来旧武。", "世间忧喜地，分明觑。", "喜事虽新，忧端依旧，徒为岷峨且欢舞。", "阴云掩映，天末扣阍无路。", "一鞭归去也，鸥为侣。"]'),
('song-ci-429','水龙吟','魏了翁','宋','宋词','song-ci','水龙吟','[]','阑风长雨连霄，昨朝晴色随轩骤。',126,'宋词/ci.song.6000.json','["阑风长雨连霄，昨朝晴色随轩骤。", "松声花气，江烟浦树，如相迎候。", "山送青来，僧随麦去，山为吾有。", "更搘筇直上，薜萝深处，云垂幄、藓成甃。", "未至相如独后。", "对山尊、劝酬多又。", "记曾犯雪，重来已是，绿肥红瘦。", "好语时闻，忧端未歇，倚风搔首。", "谩持觞自慰，冰山安在，此山如旧。"]'),
('song-ci-430','满江红','魏了翁','宋','宋词','song-ci','满江红','[]','玉质金相，长自守、间庭暗室。',112,'宋词/ci.song.6000.json','["玉质金相，长自守、间庭暗室。", "对黄昏月冷，朦胧雾浥。", "知我者希常我贵，於人不即而人即。", "彼云云、谩自怨灵均，伤兰植。", "鶗鴂乱，春芳寂。", "络纬叫，池英摘。", "惟国香耐久，素秋同德。", "既向静中观性分，偏於发处知生色。", "待到头、声臭两无时，真闻识。"]'),
('song-ci-431','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','世界要扶助，人物载耆英。',114,'宋词/ci.song.6000.json','["世界要扶助，人物载耆英。", "茫茫四海，谁识今代有宠臣。", "万顷青湖佳气，一片紫岩心事，天付与斯人。", "耸耸铁冠吏，表表白云卿。", "海沮漳，城汉郢，宅峨岷。", "规摹妙处，胸次纳纳几沧瀛。", "未说令公二纪，先看武公百岁，年与学俱新。", "星弁百僚准，天宇四时春。"]'),
('song-ci-432','南乡子','魏了翁','宋','宋词','song-ci','南乡子','[]','万里载浮名。',66,'宋词/ci.song.6000.json','["万里载浮名。", "忆昔从容下帝京。", "冉冉七年如昨梦，分明。", "赢得存存夜气清。", "谁使滥专城。", "有罪当诛尚薄刑。", "细数当时同省士，皆卿。", "落落韶阳独九龄。"]'),
('song-ci-433','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','冬至子之半，玉管罅微阳。',114,'宋词/ci.song.6000.json','["冬至子之半，玉管罅微阳。", "壶中别有天地，转觉日增长。", "一样金章紫服，一样朱颜绿发，翁季俨相望。", "翁是修何行，未已且方将。", "玉生烟，兰竞秀，彩成行。", "翁无他智，只把一念答苍苍。", "今日列城桃李，他日八荒雨露，都是乃翁庄。", "要数义方训，不说窦家郎。"]'),
('song-ci-434','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','尚忆去年称寿日，彩衣犹带天香。',70,'宋词/ci.song.6000.json','["尚忆去年称寿日，彩衣犹带天香。", "今年还见雁成行。", "两头娘子拜，笑领伯仁觞。", "知是几年培植底，如今满院芬芳。", "只凭方寸答苍苍。", "春风来不断，点缀艳阳妆。"]'),
('song-ci-435','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','曾向君王说，臣愿守嘉州。',114,'宋词/ci.song.6000.json','["曾向君王说，臣愿守嘉州。", "风流别乘初届，元在越王楼。", "湖上龟鱼何事，桥上雁犀谁使，争挽海山舟。", "便遣旧姻娅，解后作斯游。", "晚风清，初暑涨，暮云收。", "公堂高会，恍疑仙女下罗浮。", "好是中郎有女，况是史君有妇，同对藕花洲。", "拟把鹤山月，换却鉴湖秋。"]'),
('song-ci-436','临江仙','魏了翁','宋','宋词','song-ci','临江仙','[]','腰著万钉犀玉夸，肘垂斗大金章。',70,'宋词/ci.song.6000.json','["腰著万钉犀玉夸，肘垂斗大金章。", "非关性分总寻常。", "要知真乐处，彩服鬓毛苍。", "浩荡春风生玉树，蒸成满院芬芳。", "斗城无处著韶光。", "会归天上去，长捧伯仁觞。"]'),
('song-ci-437','水调歌头','魏了翁','宋','宋词','song-ci','水调歌头','[]','有匪碧岩使，满腹鉴湖秋。',114,'宋词/ci.song.6000.json','["有匪碧岩使，满腹鉴湖秋。", "不居上界官府，来作散仙游。", "长佩高冠人伟，组练锦袍官贵，清献旧风流。", "杓柄长多少，洗尽蜀民愁。", "鵕鸃冠，貂尾案，鹭鸶輈。", "时来正恐不免，留滞剑南州。", "帘卷西州风雨，庭伫百城歌鼓，桃李翠云绸。", "谁谓蜀山远，只在殿山头。"]'),
('song-ci-438','贺新郎','魏了翁','宋','宋词','song-ci','贺新郎','[]','家住峨山趾。',142,'宋词/ci.song.6000.json','["家住峨山趾。", "暑风轻、双泉漱玉，五坡攒翠。", "坡上主人归无计。", "梦泛沧波清泚。", "曾拜奏、前旒十二。", "愿上皇华将亲去，及翁儿、未老相扶曳。", "乘款段，过闾里。", "玺书未报人相谓。", "倚西风、胡尘涨野，隐忧如猬。", "就似东门贤父子，祗恐荣亲犹未。", "待洗尽、岷峨憔悴。", "便把手中长杓柄，为八荒，更作无边施。", "却上表，乞归侍。"]'),
('song-ci-439','鹧鸪天','魏了翁','宋','宋词','song-ci','鹧鸪天','[]','十载交盟可重寻。',64,'宋词/ci.song.6000.json','["十载交盟可重寻。", "剩於棠茇细论心。", "云障晚日供秋思，风递荷书作晚阴。", "纡胜引，豁尘襟。", "未须紫马去骎骎。", "玻璃无计留君住，但乞天公三日霖。"]'),
('song-ci-440','倒犯','吴文英','宋','宋词','song-ci','倒犯','[]','茂苑、共莺花醉吟，岁华如许。',128,'宋词/ci.song.6000.json','["茂苑、共莺花醉吟，岁华如许。", "江湖夜雨。", "传书问、雁多幽阻。", "清溪上，惯来往扁舟、轻如羽。", "到兴懒归来，玉冷耕云圃。", "按琼箫，赋金缕。", "回首词场，动地声名，春雷初启户。", "枕水卧漱石，数间屋，梅一坞。", "待共结、良朋侣。", "载清尊、随花追野步。", "要未若城南，分取溪隈住。", "昼长看柳舞。"]'),
('song-ci-441','花犯','吴文英','宋','宋词','song-ci','花犯','[]','翦横枝，清溪分影，修然空镜晓。',126,'宋词/ci.song.6000.json','["翦横枝，清溪分影，修然空镜晓。", "小窗春到。", "怜夜冷孀娥，相伴孤照。", "古苔泪锁霜千点，苍华人共老。", "料浅雪、黄昏驿路，飞香遗冻草。", "行云梦中认琼娘，冰肌瘦，窈窕风前纤缟。", "残醉醒，屏山外、翠禽声小。", "寒泉贮、绀壶渐暖，年事对、青灯惊换了。", "但恐舞、一帘胡蝶，玉龙吹又杳。"]'),
('song-ci-442','花犯','吴文英','宋','宋词','song-ci','花犯','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','小娉婷，清铅素靥，蜂黄暗偷晕。',126,'宋词/ci.song.6000.json','["小娉婷，清铅素靥，蜂黄暗偷晕。", "翠翘敧鬓。", "昨夜冷中庭，月下相认。", "睡浓更苦凄风紧。", "惊回心未稳。", "送晓色、一壶葱蒨，才知花梦准。", "湘娥化作此幽芳，凌波路，古岸云沙遗恨。", "临砌影，寒香乱、冻梅藏韵。", "熏炉畔、旋移傍枕，还又见、玉人垂绀鬒。", "料唤赏、清华池馆，台杯须满引。"]'),
('song-ci-443','蝶恋花','吴文英','宋','宋词','song-ci','蝶恋花','[]','北斗秋横云髻影。',70,'宋词/ci.song.6000.json','["北斗秋横云髻影。", "莺羽衣轻，腰减青丝剩。", "一曲游仙闻玉磬。", "月华深院人初定。", "十二阑干和笑凭。", "风露生寒，人在莲花顶。", "睡重不知残酒醒。", "红帘几度啼鸦暝。"]'),
('song-ci-444','蝶恋花','吴文英','宋','宋词','song-ci','蝶恋花','[]','明月枝头香满路。',70,'宋词/ci.song.6000.json','["明月枝头香满路。", "几日西风，落尽花如雨。", "倒照秦眉天镜古。", "秋明白鹭双飞处。", "自摘霜葱宜荐俎。", "可惜重阳，不把黄花与。", "帽堕笑凭纤手取。", "清歌莫送秋声去。"]'),
('song-ci-445','浣溪沙','吴文英','宋','宋词','song-ci','浣溪沙','[]','新梦游仙驾紫鸿。',48,'宋词/ci.song.6000.json','["新梦游仙驾紫鸿。", "数家灯火灞桥东。", "吹箫楼外冻云重。", "石瘦溪根船宿处，月斜梅影晓寒中。", "玉人无力倚东风。"]'),
('song-ci-446','浣溪沙','吴文英','宋','宋词','song-ci','浣溪沙','[]','冰骨清寒瘦一枝。',48,'宋词/ci.song.6000.json','["冰骨清寒瘦一枝。", "玉人初上木兰时。", "懒妆斜立澹春姿。", "月落溪穷清影在，日长春去画帘垂。", "五湖水色掩西施。"]'),
('song-ci-447','浣溪沙','吴文英','宋','宋词','song-ci','浣溪沙','[]','千盖笼花斗胜春。',48,'宋词/ci.song.6000.json','["千盖笼花斗胜春。", "东风无力扫香尘。", "尽沿高阁步红云。", "闲里暗牵经岁恨，街头多认旧年人。", "晚钟催散又黄昏。"]'),
('song-ci-448','浣溪沙','吴文英','宋','宋词','song-ci','浣溪沙','[]','蝶粉蜂黄大小乔。',48,'宋词/ci.song.6000.json','["蝶粉蜂黄大小乔。", "中庭寒尽雪微销。", "一般清瘦各无聊。", "窗下和香封远讯，墙头飞玉怨邻箫。", "夜来风雨洗春娇。"]'),
('song-ci-449','浣溪沙','吴文英','宋','宋词','song-ci','浣溪沙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','门隔花深梦旧游。',48,'宋词/ci.song.6000.json','["门隔花深梦旧游。", "夕阳无语燕归愁。", "玉纤香动小帘钩。", "落絮无声春堕泪，行云有影月含羞。", "东风临夜冷於秋。"]'),
('song-ci-450','浣溪沙','吴文英','宋','宋词','song-ci','浣溪沙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','波面铜花冷不收。',48,'宋词/ci.song.6000.json','["波面铜花冷不收。", "玉人垂钓理纤钩。", "月明池阁夜来秋。", "江燕话归成晓别，水花红减似春休。", "西风梧井叶先愁。"]'),
('song-ci-451','浣溪沙','吴文英','宋','宋词','song-ci','浣溪沙','[]','门巷深深小画楼。',48,'宋词/ci.song.6000.json','["门巷深深小画楼。", "阑干曾识凭春愁。", "新蓬遮却绣鸳游。", "桃观日斜香掩户，苹溪风起水东流。", "紫萸玉腕又逢秋。"]'),
('song-ci-452','浣溪沙','吴文英','宋','宋词','song-ci','浣溪沙','[]','曲角深帘隐洞房。',48,'宋词/ci.song.6000.json','["曲角深帘隐洞房。", "正嫌玉骨易愁黄。", "好花偏占一秋香。", "夜气清时初傍枕，晓光分处未开窗。", "可怜人似月中孀。"]'),
('song-ci-453','玉楼春','吴文英','宋','宋词','song-ci','玉楼春','[]','茸茸狸帽遮梅额。',64,'宋词/ci.song.6000.json','["茸茸狸帽遮梅额。", "金蝉罗翦胡衫窄。", "乘肩争看小腰身，倦态强随闲鼓笛。", "问称家住城东陌。", "欲买千金应不惜。", "归来困顿殢春眠，犹梦婆娑斜趁拍。"]'),
('song-ci-454','玉楼春','吴文英','宋','宋词','song-ci','玉楼春','[]','华堂夜宴连清晓。',64,'宋词/ci.song.6000.json','["华堂夜宴连清晓。", "醉里笙歌云窈袅。", "酿来千日酒初尝，过却重阳秋更好。", "阿儿早晚成名了。", "玉树阶前春满抱。", "天边金镜不须磨，长与妆楼悬晚照。"]'),
('song-ci-455','点绛唇','吴文英','宋','宋词','song-ci','点绛唇','[]','推枕南窗，拣花寒入单纱浅。',50,'宋词/ci.song.6000.json','["推枕南窗，拣花寒入单纱浅。", "雨帘不卷。", "空碍调雏燕。", "一握柔葱，香染榴巾汗。", "音尘断。", "画罗闲扇。", "山色天涯远。"]'),
('song-ci-456','点绛唇','吴文英','宋','宋词','song-ci','点绛唇','[]','时霎清明，载花不过西园路。',50,'宋词/ci.song.6000.json','["时霎清明，载花不过西园路。", "嫩阴绿树。", "正是春留处。", "燕子重来，往事东流去。", "征衫贮。", "旧寒一缕。", "泪湿风帘絮。"]'),
('song-ci-457','点绛唇','吴文英','宋','宋词','song-ci','点绛唇','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','卷尽愁云，素娥临夜新梳洗。',50,'宋词/ci.song.6000.json','["卷尽愁云，素娥临夜新梳洗。", "暗尘不起。", "酥润凌波地。", "辇路重来，仿佛灯前事。", "情如水。", "小楼熏被。", "春梦笙歌里。"]'),
('song-ci-458','秋蕊香','吴文英','宋','宋词','song-ci','秋蕊香','[]','宝月惊尘堕晓。',56,'宋词/ci.song.6000.json','["宝月惊尘堕晓。", "愁锁空枝斜照。", "古苔几点露萤小。", "销减秋光旋少。", "佩丸尚忆春酥袅。", "故人老。", "断香忍和泪痕扫。", "魂返东篱梦窅。"]'),
('song-ci-459','秋蕊香','吴文英','宋','宋词','song-ci','秋蕊香','[]','懒浴新凉睡早。',56,'宋词/ci.song.6000.json','["懒浴新凉睡早。", "雪靥酒红微笑。", "倚楼起把绣针小。", "月冷波光梦觉。", "怕闻井叶西风到。", "恨多少。", "粉河不语堕秋晓。", "云雨人间未了。"]'),
('song-ci-460','诉衷情','吴文英','宋','宋词','song-ci','诉衷情','[]','阴阴绿润暗啼鸦。',54,'宋词/ci.song.6000.json','["阴阴绿润暗啼鸦。", "陌上断香车。", "红云深处春在，飞出建章花。", "春此去，那天涯。", "几烟沙。", "忍教芳草，狼藉斜阳，人未归家。"]'),
('song-ci-461','诉衷情','吴文英','宋','宋词','song-ci','诉衷情','[]','柳腰空舞翠裙烟。',54,'宋词/ci.song.6000.json','["柳腰空舞翠裙烟。", "尽日不成眠。", "花尘浪卷清昼，渐变晚阴天。", "吴社水，系游船。", "又经年。", "东风不管，燕子初来，一夜春寒。"]'),
('song-ci-462','诉衷情','吴文英','宋','宋词','song-ci','诉衷情','[]','片云载雨过江鸥。',54,'宋词/ci.song.6000.json','["片云载雨过江鸥。", "水色澹汀洲。", "小莲玉惨红怨，翠被又经秋。", "凉意思，到南楼。", "小帘钩。", "半窗灯晕，几叶芭蕉，客梦床头。"]'),
('song-ci-463','诉衷情','吴文英','宋','宋词','song-ci','诉衷情','[]','西风吹鹤到人间。',54,'宋词/ci.song.6000.json','["西风吹鹤到人间。", "凉月满缑山。", "银河万里秋浪，重载客槎还。", "河汉女，巧云鬟。", "夜阑干。", "钗头新约，针眼娇颦，楼上秋寒。"]'),
('song-ci-464','夜游宫','吴文英','宋','宋词','song-ci','夜游宫','[]','窗外捎溪雨响。',71,'宋词/ci.song.6000.json','["窗外捎溪雨响。", "映窗里、嚼花灯冷。", "浑似潇湘系孤艇。", "见幽仙，步凌波，月边影。", "香苦欺寒劲。", "牵梦绕、沧涛千顷。", "梦觉新愁旧风景。", "绀云敧，玉搔斜，酒初醒。"]'),
('song-ci-465','夜游宫','吴文英','宋','宋词','song-ci','夜游宫','[]','春语莺迷翠柳，烟隔断、晴波远岫。',71,'宋词/ci.song.6000.json','["春语莺迷翠柳，烟隔断、晴波远岫。", "寒压重帘幔拖绣。", "袖炉香，倩东风，与吹透。", "花讯催时候。", "旧相思、偏供闲昼。", "春澹情浓半中酒。", "玉痕销，似梅花，更清瘦。"]'),
('song-ci-466','醉桃源・阮郎归','吴文英','宋','宋词','song-ci','醉桃源・阮郎归','[]','金丸一树带霜华。',56,'宋词/ci.song.6000.json','["金丸一树带霜华。", "银台摇艳霞。", "烛阴树影两交加。", "秋纱机上花。", "飞醉笔，驻吟车。", "香深小隐家。", "明朝新梦付啼鸦。", "歌阑月未斜。"]'),
('song-ci-467','醉桃源・阮郎归','吴文英','宋','宋词','song-ci','醉桃源・阮郎归','[]','沙河塘上旧游嬉。',56,'宋词/ci.song.6000.json','["沙河塘上旧游嬉。", "卢郎年少时。", "一声长笛月中吹。", "和云和雁飞。", "惊物换，叹星移。", "相看两鬓丝。", "断肠吴苑草凄凄。", "倚楼人未归。"]'),
('song-ci-468','醉桃源・阮郎归','吴文英','宋','宋词','song-ci','醉桃源・阮郎归','[]','青春花姊不同时。',56,'宋词/ci.song.6000.json','["青春花姊不同时。", "凄凉生较迟。", "艳妆临水最相宜。", "风来吹秀漪。", "惊旧事，问长眉。", "月明仙梦回。", "凭阑人但觉秋肥。", "花愁人不知。"]'),
('song-ci-469','醉桃源・阮郎归','吴文英','宋','宋词','song-ci','醉桃源・阮郎归','[]','翠阴浓合晓莺堤。',56,'宋词/ci.song.6000.json','["翠阴浓合晓莺堤。", "春如日坠西。", "画图新展远山齐。", "花深十二梯。", "风絮晚，醉魂迷。", "隔城闻马嘶。", "落红微沁绣鸳泥。", "秋千教放低。"]'),
('song-ci-470','如梦令','吴文英','宋','宋词','song-ci','如梦令','[]','春在绿窗杨柳。',40,'宋词/ci.song.6000.json','["春在绿窗杨柳。", "人与流莺俱瘦。", "眉底暮寒生，帘额时翻波皱。", "风骤。", "风骤。", "花径啼红满袖。"]'),
('song-ci-471','如梦令','吴文英','宋','宋词','song-ci','如梦令','[]','秋千争闹粉墙。',40,'宋词/ci.song.6000.json','["秋千争闹粉墙。", "闲看燕紫莺黄。", "啼到绿阴处，唤回浪子闲忙。", "春光。", "春光。", "正是拾翠寻芳。"]'),
('song-ci-472','望江南・忆江南','吴文英','宋','宋词','song-ci','望江南・忆江南','[]','衣白苎，雪面堕愁鬟。',64,'宋词/ci.song.6000.json','["衣白苎，雪面堕愁鬟。", "不识朝云行雨处，空随春梦到人间。", "留向画图看。", "慵临镜，流水洗花颜。", "自织苍烟湘泪冷，谁捞明月海波寒。", "天澹雾漫漫。"]'),
('song-ci-473','望江南・忆江南','吴文英','宋','宋词','song-ci','望江南・忆江南','[]','松风远，莺燕静幽坊。',64,'宋词/ci.song.6000.json','["松风远，莺燕静幽坊。", "妆褪宫梅人倦绣，梦回春草日初长。", "瓷碗试新汤。", "笙歌断，情与絮悠扬。", "石乳飞时离凤怨，玉纤分处露花香。", "人去月侵廊。"]'),
('song-ci-474','定风波','吴文英','宋','宋词','song-ci','定风波','[]','密约偷香□蹋青。',70,'宋词/ci.song.6000.json','["密约偷香□蹋青。", "小车随马过南屏。", "回首东风销鬓影。", "重省。", "十年心事夜船灯。", "离骨渐尘桥下水，到头难灭景中情。", "两岸落花残酒醒。", "烟冷。", "人家垂柳未清明。"]'),
('song-ci-475','月中行・月宫春','吴文英','宋','宋词','song-ci','月中行・月宫春','[]','疏桐翠井早惊秋。',59,'宋词/ci.song.6000.json','["疏桐翠井早惊秋。", "叶叶雨声愁。", "灯前倦客老貂裘。", "燕去柳边楼。", "吴宫寂寞空烟水，浑不认、旧采菱洲。", "秋花旋结小盘虬。", "蝶怨夜香留。"]'),
('song-ci-476','虞美人','吴文英','宋','宋词','song-ci','虞美人','[]','背庭缘恐花羞坠。',66,'宋词/ci.song.6000.json','["背庭缘恐花羞坠。", "心事遥山里。", "小帘愁卷月笼明。", "一寸秋怀、禁得几蛩声。", "井梧不放西风起。", "供与离人睡。", "梦和新月未圆时。", "起看檐蛛结网、又寻思。"]'),
('song-ci-477','菩萨蛮','吴文英','宋','宋词','song-ci','菩萨蛮','[]','落花夜雨辞寒食。',52,'宋词/ci.song.6000.json','["落花夜雨辞寒食。", "尘香明日城南陌。", "玉靥湿斜红。", "泪痕千万重。", "伤春头竟白。", "来去春如客。", "人瘦绿阴浓。", "日长帘影中。"]'),
('song-ci-478','菩萨蛮','吴文英','宋','宋词','song-ci','菩萨蛮','[]','绿波碧草长堤色。',52,'宋词/ci.song.6000.json','["绿波碧草长堤色。", "东风不管春狼藉。", "鱼沫细痕圆。", "燕泥花唾乾。", "无情牵怨抑。", "画舸红楼侧。", "斜日起凭阑。", "垂杨舞晓寒。"]'),
('song-ci-479','贺新郎','吴文英','宋','宋词','song-ci','贺新郎','[]','湖上芙蓉早。',142,'宋词/ci.song.6000.json','["湖上芙蓉早。", "向北山、山深雾冷，更看花好。", "流水茫茫城下梦，空指游仙路杳。", "笑萝障、云屏亲到。", "雪玉肌肤春温夜，饮湖光、山渌成花貌。", "临涧水，弄清照。", "著愁不尽宫眉小。", "听一声、相思曲里，赋情多少。", "红日阑干鸳鸯枕，那枉裙腰褪了。", "算谁识、垂杨秋袅。", "不是秦楼无缘分，点吴霜、羞带簪花帽。", "但殢酒，任天晓。"]'),
('song-ci-480','贺新郎','吴文英','宋','宋词','song-ci','贺新郎','[]','浪影龟纹皱。',142,'宋词/ci.song.6000.json','["浪影龟纹皱。", "蘸平烟、青红半湿，枕溪窗牖。", "千尺晴霞慵卧水，万叠罗屏拥绣。", "漫几度、吴船回首。", "归雁五湖应不到，问苍茫、钓雪人知否。", "樵唱杳，度深秀。", "重来趁得花时候。", "记留连、空山夜雨，短亭春酒。", "桃李新栽成蹊处，尽是行人去后。", "但东阁、官梅清瘦。", "欸乃一声山水绿，燕无言、风定垂帘昼。", "寒正悄，亸吟袖。"]'),
('song-ci-481','江城梅花引','吴文英','宋','宋词','song-ci','江城梅花引','[]','江头何处带春归。',108,'宋词/ci.song.6000.json','["江头何处带春归。", "玉川迷。", "路东西。", "一雁不飞、雪压冻云低。", "十里黄昏成晓色，竹根篱。", "分流水、过翠微。", "带书傍月自锄畦。", "苦吟诗。", "生鬓丝。", "半黄烟雨，翠禽语、似说相思。", "惆怅孤山、花尽草离离。", "半幅寒香家住远，小帘垂。", "玉人误、听马嘶。"]'),
('song-ci-482','婆罗门引','吴文英','宋','宋词','song-ci','婆罗门引','["\u6d1e\u5ead\u6e56"]','香霏泛酒，瘴花初洗玉壶冰。',93,'宋词/ci.song.6000.json','["香霏泛酒，瘴花初洗玉壶冰。", "西风乍入吴城。", "吹彻玉笙何处，曾说董双成。", "奈司空经惯，未畅高情。", "瑶台几层。", "但梦绕、曲阑行。", "空忆双蝉□翠，寂寂秋声。", "堂空露凉，倩谁唤、行云来洞庭。", "团扇月、只隔烟屏。"]'),
('song-ci-483','婆罗门引','吴文英','宋','宋词','song-ci','婆罗门引','[]','风涟乱翠，酒霏飘汗洗新妆。',93,'宋词/ci.song.6000.json','["风涟乱翠，酒霏飘汗洗新妆。", "幽情暗寄莲房。", "弄雪调冰重会，临水暮追凉。", "正碧云不破，素月微行。", "双成夜笙，断旧曲、解明珰。", "别有红娇粉润，初试霓裳。", "分莲调郎。", "又拈惹、花茸碧唾香。", "波晕切、一盼秋光。"]'),
('song-ci-484','祝英台近','吴文英','宋','宋词','song-ci','祝英台近','[]','黯春阴，收灯后，寂寞几帘户。',95,'宋词/ci.song.6000.json','["黯春阴，收灯后，寂寞几帘户。", "一片花飞，人驾彩云去。", "应是蛛网金徽，拍天寒水，恨声断、孤鸿洛浦。", "对君诉。", "团扇轻委桃花，流红为谁赋。", "□□□□，从今醉何处。", "可怜憔悴文园，曲屏春到，断肠句、落梅愁雨。"]'),
('song-ci-485','祝英台近','吴文英','宋','宋词','song-ci','祝英台近','[]','问流花，寻梦草，云暖翠微路。',95,'宋词/ci.song.6000.json','["问流花，寻梦草，云暖翠微路。", "锦雁峰前，浅约昼行处。", "不教嘶马飞春，一奁越境，那销尽、红吟绿赋。", "送人去。", "长丝初染柔黄，晴和晓烟舞。", "心事偷占，莺漏汉宫语。", "趁得罗盖天香，归来时候，共留取、玉阑春住。"]'),
('song-ci-486','祝英台近','吴文英','宋','宋词','song-ci','祝英台近','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','采幽香，巡古苑，竹冷翠微路。',95,'宋词/ci.song.6000.json','["采幽香，巡古苑，竹冷翠微路。", "斗草溪根，沙印小莲步。", "自怜两鬓清霜，一年寒食，又身在、云山深处。", "昼闲度。", "因甚天也悭春，轻阴便成雨。", "绿暗长亭，归梦趁风絮。", "有情花影阑干，莺声门径，解留我、霎时凝伫。"]'),
('song-ci-487','祝英台近','吴文英','宋','宋词','song-ci','祝英台近','[]','晚云开，朝雪霁，时节又灯市。',95,'宋词/ci.song.6000.json','["晚云开，朝雪霁，时节又灯市。", "夜约遗香，南陌少年事。", "笙箫一片红云，飞来海上，绣帘卷、缃桃春起。", "旧游地。", "素蛾城阙年年，新妆趁罗绮。", "玉练冰轮，无尘浣流水。", "晓霞红处啼鸦，良宵一梦，画堂正、日长人睡。"]'),
('song-ci-488','祝英台近','吴文英','宋','宋词','song-ci','祝英台近','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','翦红情，裁绿意，花信上钗股。',95,'宋词/ci.song.6000.json','["翦红情，裁绿意，花信上钗股。", "残日东风，不放岁华去。", "有人添烛西窗，不眠侵晓，笑声转、新年莺语。", "旧尊俎。", "玉纤曾擘黄柑，柔香系幽素。", "归梦湖边，还迷镜中路。", "可怜千点吴霜，寒销不尽，又相对、落梅如雨。"]'),
('song-ci-489','西子妆慢・西子妆','吴文英','宋','宋词','song-ci','西子妆慢・西子妆','[]','流水曲尘，艳阳醅酒，画舸游情如雾。',120,'宋词/ci.song.6000.json','["流水曲尘，艳阳醅酒，画舸游情如雾。", "笑拈芳草不知名，乍凌波、断桥西堍。", "垂杨漫舞。", "总不解、将春系住。", "燕归来，问彩绳纤手，如今何许。", "欢盟误。", "一箭流光，又趁寒食去。", "不堪衰鬓著飞花，傍绿阴、冷烟深树。", "玄都秀句。", "记前度、刘郎曾赋。", "最伤心、一片孤山细雨。"]'),
('song-ci-490','江南春・秋风清','吴文英','宋','宋词','song-ci','江南春・秋风清','[]','风响牙签，云寒古砚，芳铭犹在棠笏。',132,'宋词/ci.song.6000.json','["风响牙签，云寒古砚，芳铭犹在棠笏。", "秋床听雨，妙谢庭、春早吟笔。", "城市喧鸣辙。", "清溪上、小山秀洁。", "便向此。", "搜松访石，葺屋营花，红尘远避风月。", "瞿塘路，随汉节。", "记羽扇纶巾，气凌诸葛。", "青天万里，料漫忆、莼丝鲈雪。", "车马从休歇。", "荣华事、醉歌耳熟。", "天与此翁，芳芷嘉名，纫兰佩兮琼玦。"]'),
('song-ci-491','梦芙蓉','吴文英','宋','宋词','song-ci','梦芙蓉','["\u897f\u6e56"]','西风摇步绮。',117,'宋词/ci.song.6000.json','["西风摇步绮。", "记长堤骤过，紫骝十里。", "断桥南岸，人在晚霞外。", "锦温花共醉。", "当时曾共秋被。", "自别霓裳，应红销翠冷，霜枕正慵起。", "惨澹西湖柳底。", "摇荡秋魂，夜月归环佩。", "画图重展，惊忍旧梳洗。", "去来双翡翠。", "难传眼恨眉意。", "梦断琼娘，仙云深路杳，城影蘸流水。"]'),
('song-ci-492','高山流水','吴文英','宋','宋词','song-ci','高山流水','[]','素弦一一起秋风。',135,'宋词/ci.song.6000.json','["素弦一一起秋风。", "写柔情、都在春葱。", "徽外断肠声，霜霄暗落惊鸿。", "低颦处、翦绿裁红。", "仙郎伴、新制还赓旧曲，映月帘栊。", "似名花并蒂，日日醉春浓。", "吴中。", "空传有西子，应不解、换徵移宫。", "兰蕙满襟怀，唾碧总喷花茸。", "后堂深、想费春工。", "客愁重、时听蕉寒雨碎，泪湿琼锺。", "恁风流也称，金屋贮娇慵。"]'),
('song-ci-493','霜花腴','吴文英','宋','宋词','song-ci','霜花腴','[]','翠微路窄，醉晚风、凭谁为整敧冠。',128,'宋词/ci.song.6000.json','["翠微路窄，醉晚风、凭谁为整敧冠。", "霜饱花腴，烛消人瘦，秋光作也都难。", "病怀强宽。", "恨雁声、偏落歌前。", "记年时、旧宿凄凉，暮烟秋雨野桥寒。", "妆靥鬓英争艳，度清商一曲，暗坠金蝉。", "芳节多阴，兰情稀会，晴晖称拂吟笺。", "更移画船。", "引佩环、邀下婵娟。", "算明朝、未了重阳，紫萸应耐看。"]'),
('song-ci-494','澡兰香','吴文英','宋','宋词','song-ci','澡兰香','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','盘丝系腕，巧篆垂簪，玉隐绀纱睡觉。',126,'宋词/ci.song.6000.json','["盘丝系腕，巧篆垂簪，玉隐绀纱睡觉。", "银瓶露井，彩箑云窗，往事少年依约。", "为当时、曾写榴裙，伤心红绡褪萼。", "黍梦光阴渐老，汀洲烟箬。", "莫唱江南古调，怨抑难招，楚江沈魄。", "薰风燕乳，暗雨梅黄，午镜澡兰帘幕。", "念秦楼、也拟人归，应翦菖浦自酌。", "但怅望、一屡新蟾，随人天角。"]'),
('song-ci-495','玉京谣','吴文英','宋','宋词','song-ci','玉京谣','[]','蝶梦迷清晓，万里无家，岁晚貂裘敝。',120,'宋词/ci.song.6000.json','["蝶梦迷清晓，万里无家，岁晚貂裘敝。", "载取琴书，长安闲看桃李。", "烂绣锦、人海花场，任客燕、飘零谁记。", "春风里。", "香泥九陌，文梁孤垒。", "微吟怕有诗声翳。", "镜慵看、但小楼独依。", "金屋千娇，从他鸳暖秋被。", "蕙帐移、烟雨孤山，待对影、落梅清泚。", "终不似。", "江上翠微流水。"]'),
('song-ci-496','探芳新','吴文英','宋','宋词','song-ci','探芳新','[]','九街头，正软尘润酥，雪销残溜。',115,'宋词/ci.song.6000.json','["九街头，正软尘润酥，雪销残溜。", "禊赏祗园，花艳云阴笼昼。", "层梯峭空麝散，拥凌波、萦翠袖。", "叹年端、连环转，烂漫游人如绣。", "肠断回廊伫久。", "便写意溅波，传愁蹙岫。", "渐没飘鸿，空惹闲情春瘦。", "椒杯香乾醉醒，怕西窗、人散后。", "暮寒深，迟回处、自攀庭柳。"]'),
('song-ci-497','凤池吟','吴文英','宋','宋词','song-ci','凤池吟','[]','万丈巍台，碧罘罳外，衮衮野马游尘。',121,'宋词/ci.song.6000.json','["万丈巍台，碧罘罳外，衮衮野马游尘。", "旧文书几阁，昏朝醉暮，覆雨翻云。", "忽变清明，紫垣敕使下星辰。", "经年事静，公门如水，帝甸阳春。", "长安父老相语，几百年见此，独驾冰轮。", "又凤鸣黄幕，玉霄平溯，鹊锦新恩。", "画省中书，半红梅子荐盐新。", "归来晚，待赓吟、殿阁南薰。"]'),
('song-ci-498','暗香','吴文英','宋','宋词','song-ci','暗香','[]','县花谁葺。',120,'宋词/ci.song.6000.json','["县花谁葺。", "记满庭燕麦，朱扉斜阖。", "妙手作新，公馆青红晓云湿。", "天际疏星趁马，帘昼隙、冰弦三叠。", "尽换却、吴水吴烟，桃李靓春靥。", "风急。", "送帆叶。", "正雁水夜清，卧虹平帖。", "软红路接。", "涂粉闱深早催入。", "怀暖天香宴果，花队簇、轻轩银蜡。", "更问讯、湖上柳，两堤翠匝。"]'),
('song-ci-499','暗香疏影','吴文英','宋','宋词','song-ci','暗香疏影','[]','占春压一。',128,'宋词/ci.song.6000.json','["占春压一。", "卷峭寒万里，平沙飞雪。", "数点酥钿，凌晓东风□吹裂。", "独曳横梢瘦影，入广平、裁冰词笔。", "记五湖、清夜推篷，临水一痕月。", "何逊扬州旧事，五更梦半醒，胡调吹彻。", "若把南枝，图入凌烟，香满玉楼琼阙。", "相将初试红盐味，到烟雨、青黄时节。", "想雁空、北落冬深，澹墨晚天云阔。"]'),
('song-ci-500','念奴娇','吴文英','宋','宋词','song-ci','念奴娇','[]','思生晚眺，岸乌纱平步，春云层绿。',120,'宋词/ci.song.6000.json','["思生晚眺，岸乌纱平步，春云层绿。", "罨画屏风开四面，各样莺花结束。", "寒欲残时，香无著处，千树风前玉。", "游蜂飞过，隔墙疑是金谷。", "偏称晚色横烟，愁凝峨髻，澹生绡裙幅。", "缥缈孤山南畔路，相对花房竹屋。", "溪足沙明，岩阴石秀，梦冷吟亭宿。", "松风古涧，高调月夜清曲。"]'),
('song-ci-501','惜红衣','吴文英','宋','宋词','song-ci','惜红衣','[]','鹭老秋丝，苹愁暮雪，鬓那不白。',108,'宋词/ci.song.6000.json','["鹭老秋丝，苹愁暮雪，鬓那不白。", "倒柳移栽，如今暗溪碧。", "乌衣细语，伤绊惹、茸红曾约。", "南陌。", "前度刘郎，寻流花踪迹。", "朱楼水侧。", "雪面波光，汀莲沁颜色。", "当时醉近绣箔，夜吟寂。", "三十六矶重到，清梦冷云南北。", "买钓舟溪上，应有烟蓑相识。"]'),
('song-ci-502','江南好・忆江南','吴文英','宋','宋词','song-ci','江南好・忆江南','[]','行锦归来，画眉添妩，暗尘重拂雕栊。',117,'宋词/ci.song.6000.json','["行锦归来，画眉添妩，暗尘重拂雕栊。", "稳瓶泉暖，花隘斗春容。", "围密笼香暗霭，烦纤手、亲点团龙。", "温柔处，垂杨髻，□暗豆花红。", "行藏，多是客，莺边话别，桔下相逢。", "算江湖幽梦，频绕残钟。", "好结梅兄矾弟，莫轻侣、西燕南鸿。", "偏宜醉，寒欺酒力，帘外冻云重。"]'),
('song-ci-503','双双燕','吴文英','宋','宋词','song-ci','双双燕','[]','小桃谢后，双双燕，飞来几家庭户。',117,'宋词/ci.song.6000.json','["小桃谢后，双双燕，飞来几家庭户。", "轻烟晓暝，湘水暮云遥度。", "帘外馀寒未卷，共斜入、红楼深处。", "相将占得雕梁，似约韶光留住。", "堪举。", "翩翩翠羽。", "杨柳岸，泥香半和梅雨。", "落花风软，戏促乱红飞舞。", "多少呢喃意绪。", "尽日向、流莺分诉。", "还过短墙，谁会万千言语。"]'),
('song-ci-504','无闷','吴文英','宋','宋词','song-ci','无闷','[]','霓节飞琼，鸾驾弄玉，杳隔平云弱水。',123,'宋词/ci.song.6000.json','["霓节飞琼，鸾驾弄玉，杳隔平云弱水。", "倩皓鹤传书，卫姨呼起。", "莫待粉河凝晓，趁夜月、瑶笙飞环佩。", "正蹇驴吟影，茶烟灶冷，酒亭门闭。", "歌丽。", "泛碧蚁。", "放绣帘半钩，宝台临砌。", "要须借东君，灞陵春意。", "晓梦先迷楚蝶，早风戾、重寒侵罗被。", "还怕掩、深院梨花，又作故人清泪。"]'),
('song-ci-505','水调歌头','吴文英','宋','宋词','song-ci','水调歌头','[]','屋下半流水，屋上几青山。',114,'宋词/ci.song.6000.json','["屋下半流水，屋上几青山。", "当心千顷明镜，入座玉光寒。", "云起南峰未雨，云敛北峰初霁，健笔写青天。", "俯瞰古城堞，不碍小阑干。", "绣鞍马，软红路，乍回班。", "层梯影转亭午，信手展缃编。", "残照游船收尽，新月画帘才卷，人在翠壶间。", "天际笛声起，尘世夜漫漫。"]'),
('song-ci-506','洞仙歌','吴文英','宋','宋词','song-ci','洞仙歌','["\u897f\u6e56"]','芳辰良宴，人日春朝并。',105,'宋词/ci.song.6000.json','["芳辰良宴，人日春朝并。", "细缕青丝裹银饼。", "更玉犀金彩，沾座分簪，歌围暖，梅靥桃唇斗胜。", "露房花曲折，莺入新年，添个宜男小山枕。", "待枝上，饱东风，结子成阴，蓝桥去、还觅琼浆一饮。", "料别馆、西湖最情浓，烂画舫月明，醉宫袍锦。"]'),
('song-ci-507','秋思','吴文英','宋','宋词','song-ci','秋思','[]','堆枕香鬟侧。',152,'宋词/ci.song.6000.json','["堆枕香鬟侧。", "骤夜声、偏称画屏秋色。", "风碎串珠，润侵歌板，愁压眉窄。", "动罗箑清商，寸心低诉叙怨抑。", "映梦窗，零乱碧。", "待涨绿春深，落花香泛，料有断红流处，暗题相忆。", "欢酌。", "檐花细滴。", "送故人、粉黛重饰。", "漏侵琼瑟。", "丁东敲断，弄晴月白。", "怕一曲、霓裳未终，催去骖凤翼。", "叹谢客、犹未识。", "漫瘦却东阳，灯前无梦到得。", "路隔重云雁北。"]'),
('song-ci-508','江神子・江城子','吴文英','宋','宋词','song-ci','江神子・江城子','[]','长安门外小林丘。',86,'宋词/ci.song.6000.json','["长安门外小林丘。", "碧壶秋。", "浴轻鸥。", "不放啼红，流水通宫沟。", "时有晴空云过影，华镜里，翳鱼游。", "绮罗尘满九衢头。", "晚香楼。", "夕阳收。", "波面琴高，仙子驾黄虬。", "清磬数声人定了，池上月，照虚舟。"]'),
('song-ci-509','江神子・江城子','吴文英','宋','宋词','song-ci','江神子・江城子','[]','一声玉磬下星坛。',86,'宋词/ci.song.6000.json','["一声玉磬下星坛。", "步虚阑。", "露华寒。", "平晓阿香，油壁碾青鸾。", "应是老鳞眠不得，云炮落，雨瓢翻。", "身闲犹耿寸心丹。", "炷炉烟。", "暗祈年。", "随处蛙声，鼓吹稻花田。", "秋水一池莲叶晚，吟喜雨，拍阑干。"]'),
('song-ci-510','江神子・江城子','吴文英','宋','宋词','song-ci','江神子・江城子','[]','翠纱笼袖映红霏。',86,'宋词/ci.song.6000.json','["翠纱笼袖映红霏。", "冷香飞。", "洗凝脂。", "睡足娇多，还是夜深宜。", "翻怕回廊花有影，移烛暗，放帘垂。", "尊前不按驻云词。", "料花枝。", "妒蛾眉。", "丁属东风，莫送片红飞。", "春重锦堂人尽醉，和晓月，带花归。"]'),
('song-ci-511','渔父词・渔父','周紫芝','宋','宋词','song-ci','渔父词・渔父','[]','花姑溪上鹭鸶滩。',32,'宋词/ci.song.6000.json','["花姑溪上鹭鸶滩。", "辜负渔竿二十年。", "无可载，不抛官。", "携取全家去不难。"]'),
('song-ci-512','木兰花・玉楼春','莫将','宋','宋词','song-ci','木兰花・玉楼春','[]','一枝和露珍珠贯。',64,'宋词/ci.song.6000.json','["一枝和露珍珠贯。", "月下回来寻几遍。", "今朝忽见数枝开，未有十分如待伴。", "新妆不比徐妃面。", "雪艳冰姿寒欲颤。", "外边多少扫春人，春信莫教容易断。"]'),
('song-ci-513','木兰花・玉楼春','莫将','宋','宋词','song-ci','木兰花・玉楼春','[]','梅边晓景清无比。',64,'宋词/ci.song.6000.json','["梅边晓景清无比。", "林下诗人呵冻指。", "玉龙留住麝脐烟，银漏滴残龙脑水。", "晨光渐渐收寒气。", "昨夜遗簪犹在地。", "好生折赠镜中人，只恐绿窗慵未起。"]'),
('song-ci-514','木兰花・玉楼春','莫将','宋','宋词','song-ci','木兰花・玉楼春','[]','清姿自是生寒瘦。',64,'宋词/ci.song.6000.json','["清姿自是生寒瘦。", "更在春前并腊后。", "谁教六出巧遮藏，争似一番先透漏。", "谢娘莫把翻衣袖。", "无限琼英飘玉甃。", "开时朵朵见天真，可柰碧溪和粉溜。"]'),
('song-ci-515','木兰花・玉楼春','莫将','宋','宋词','song-ci','木兰花・玉楼春','[]','寒梢雨里愁无那。',64,'宋词/ci.song.6000.json','["寒梢雨里愁无那。", "林下开时宜数过。", "夕阳恰似过清溪，一树横斜疏影卧。", "朱唇莫比桃花破。", "鬓袅黄金花欲堕。", "剩看春雪满空来，触处是花寻那个。"]'),
('song-ci-516','木兰花・玉楼春','莫将','宋','宋词','song-ci','木兰花・玉楼春','[]','寻梅莫背东风路。',64,'宋词/ci.song.6000.json','["寻梅莫背东风路。", "路在花前知去处。", "真香破鼻蓦然闻，试问幽丛知几步。", "多情更被无寒助。", "万物枯时神物护。", "一枝和雪倚阑干，昨夜初开春信度。"]'),
('song-ci-517','木兰花・玉楼春','莫将','宋','宋词','song-ci','木兰花・玉楼春','[]','暗香浮动黄昏后。',64,'宋词/ci.song.6000.json','["暗香浮动黄昏后。", "更是月明如白昼。", "看来都坐玉壶冰，折赠徐妃丹桂手。", "赏酬风景无过酒。", "对影成三谁左右。", "劝君携取董妖娆，拱得醉翁香满袖。"]'),
('song-ci-518','木兰花・玉楼春','莫将','宋','宋词','song-ci','木兰花・玉楼春','[]','花时人道多风雨。',64,'宋词/ci.song.6000.json','["花时人道多风雨。", "梅蕊都来无几许。", "何须飘洒湿芳心，粉面琳琅如泪注。", "家童莫扫花阴土。", "留浥琼林枝上露。", "莫教燕子早衔泥，径里馀香应满户。"]'),
('song-ci-519','木兰花・玉楼春','莫将','宋','宋词','song-ci','木兰花・玉楼春','[]','眼前欲尽情何限。',64,'宋词/ci.song.6000.json','["眼前欲尽情何限。", "风外南枝无一半。", "东君何事莫教开，及至如今都不管。", "高楼三弄休吹趱。", "一片惊人肠欲断。", "杏花开后莫嫌衰，如豆青时君细看。"]'),
('song-ci-520','木兰花・玉楼春','莫将','宋','宋词','song-ci','木兰花・玉楼春','[]','前村雪里虽然早。',64,'宋词/ci.song.6000.json','["前村雪里虽然早。", "争似横斜开处好。", "直饶隔水是江南，也恐一枝春未到。", "延宾莫恨花阴小。", "见说芳林今古抱。", "集花潇洒洞天深，永夜玉山应自到。"]'),
('song-ci-521','木兰花・玉楼春','莫将','宋','宋词','song-ci','木兰花・玉楼春','[]','少陵长被花为恼。',64,'宋词/ci.song.6000.json','["少陵长被花为恼。", "况是梅花非草草。", "临歧争奈不吟诗，此度诗人宜可老。", "诗成莫惜尊罍倒。", "不醉花前花解笑。", "醒时分付两三枝，酒后忆君清梦到。"]'),
('song-ci-522','独脚令・忆王孙','莫将','宋','宋词','song-ci','独脚令・忆王孙','[]','绛唇初点粉红新。',36,'宋词/ci.song.6000.json','["绛唇初点粉红新。", "凤镜临妆已逼真。", "苒苒钗头香趁人。", "惜芳晨。", "玉骨冰姿别是春。"]'),
('song-ci-523','浣溪沙','莫将','宋','宋词','song-ci','浣溪沙','[]','宝钏香裙上玉梯。',24,'宋词/ci.song.6000.json','["宝钏香裙上玉梯。", "云重应恨翠楼低。", "愁同芳草两萋萋。"]'),
('song-ci-524','浣溪沙','莫将','宋','宋词','song-ci','浣溪沙','[]','归梦悠扬见未真。',24,'宋词/ci.song.6000.json','["归梦悠扬见未真。", "绣衾恰有暗香薰。", "五更分得楚台春。"]'),
('song-ci-525','念奴娇','邵博','宋','宋词','song-ci','念奴娇','[]','天然潇洒，尽人间、无物堪齐标格。',120,'宋词/ci.song.6000.json','["天然潇洒，尽人间、无物堪齐标格。", "只与姮娥为伴侣，方显一家颜色。", "好是多情，一年一度，首作东君客。", "竹篱茅舍，典刑别是清白。", "惆怅玉杵无凭，蓝桥人去，空锁神仙宅。", "今日天涯凭马上，忽见轻盈冰魄。", "恰似当年，温柔乡里，晓看新妆额。", "临风三嗅，挽条不忍空摘。"]'),
('song-ci-526','声声慢','赵佶','宋','宋词','song-ci','声声慢','[]','宫梅粉淡，岸柳金匀，皇州乍庆春回。',119,'宋词/ci.song.6000.json','["宫梅粉淡，岸柳金匀，皇州乍庆春回。", "凤阙端门，棚山彩建蓬莱。", "沈沈洞天向晚，宝舆还、花满钧台。", "轻烟里，算谁将金莲，陆地齐开。", "触处声歌鼎沸，香鞯趁，雕轮隐隐轻雷。", "万家帘幕，千步锦绣相挨。", "银蟾皓月如昼，共乘欢、争忍归来。", "疏钟断，听行歌、犹在禁街。"]'),
('song-ci-527','声声慢','赵佶','宋','宋词','song-ci','声声慢','[]','欺寒冲暖，占早争春，江梅已破南枝。',119,'宋词/ci.song.6000.json','["欺寒冲暖，占早争春，江梅已破南枝。", "向晚阴凝，偏宜映月临池。", "天然莹肌秀骨，笑等闲、桃李芳菲。", "劳梦想，似玉人羞懒，弄粉妆迟。", "长记行歌声断，犹堪恨，无情塞管频吹。", "寄远丁宁，折赠陇首相思。", "前村夜来雪里，殢东君、须索饶伊。", "烂漫也，算百花、犹自未知。"]'),
('song-ci-528','念奴娇','赵佶','宋','宋词','song-ci','念奴娇','[]','雅怀素态，向闲中、天与风流标格。',121,'宋词/ci.song.6000.json','["雅怀素态，向闲中、天与风流标格。", "绿锁窗前湘簟展，终日风清人寂。", "玉子声乾，纹楸色净，星点连还直。", "跳丸日月，算应局上销得。", "全似落浦斜晖，寒鸦游鹭，乱点沙汀碛。", "妙算神机，须信道，国手都无勍敌。", "玳席欢馀，芸堂香暖，赢取专良夕。", "桃园归路，烂柯应笑凡客。"]'),
('song-ci-529','醉落魄・一斛珠','赵佶','宋','宋词','song-ci','醉落魄・一斛珠','[]','无言哽噎。',67,'宋词/ci.song.6000.json','["无言哽噎。", "看灯记得年时节。", "行行指月行行说。", "愿月常圆，休要暂时缺。", "今年华市灯罗列。", "好灯争柰人心别。", "人前不敢分明说。", "不忍抬头，羞见旧时月。"]'),
('song-ci-530','探春令','赵佶','宋','宋词','song-ci','探春令','[]','帘旌微动，峭寒天气，龙池冰泮。',62,'宋词/ci.song.6000.json','["帘旌微动，峭寒天气，龙池冰泮。", "杏花笑吐香犹浅。", "又还是、春将半。", "清歌妙舞从头按。", "等芳时开宴。", "记去年、对著东风，曾许不负莺花愿。"]'),
('song-ci-531','聒龙谣','赵佶','宋','宋词','song-ci','聒龙谣','[]','紫阙苕峣，绀宇邃深，望极绛河清浅。',125,'宋词/ci.song.6000.json','["紫阙苕峣，绀宇邃深，望极绛河清浅。", "霜月流天，锁穹隆光满。", "水精宫、金锁龙盘，玳瑁帘、玉钩云卷。", "动深思，秋籁萧萧，比人世、倍清燕。", "瑶阶回。", "玉签鸣，渐秘省引水，辘轳声转。", "鸡人唱晓，促铜壶银箭。", "拂晨光、宫柳烟微，荡瑞色、御炉香散。", "从宸游，前后争趋，向金銮殿。"]'),
('song-ci-532','临江仙','赵佶','宋','宋词','song-ci','临江仙','[]','过水穿山前去也，吟诗约句千馀。',70,'宋词/ci.song.6000.json','["过水穿山前去也，吟诗约句千馀。", "淮波寒重雨疏疏。", "烟笼滩上鹭，人买就船鱼。", "古寺幽房权且住，夜深宿在僧居。", "梦魂惊起转嗟吁。", "愁牵心上虑，和泪写回书。"]'),
('song-ci-533','月上海棠','赵佶','宋','宋词','song-ci','月上海棠','[]','孟婆且与我、做些方便。',11,'宋词/ci.song.6000.json','["孟婆且与我、做些方便。"]'),
('song-ci-534','满庭芳','赵佶','宋','宋词','song-ci','满庭芳','[]','寰宇清夷，元宵游豫，为开临御端门。',118,'宋词/ci.song.6000.json','["寰宇清夷，元宵游豫，为开临御端门。", "暖风摇曳，香气霭轻氛。", "十万钩陈灿锦，钧台外、罗绮缤纷。", "欢声里，烛龙衔耀，黼藻太平春。", "灵鳌，擎采岫，冰轮远驾，初上祥云。", "照万宇嬉游，一视同仁。", "更起维垣大第，通宵宴、调燮良臣。", "从兹庆，都俞庚载，千岁乐昌辰。"]'),
('song-ci-535','眼儿媚','赵佶','宋','宋词','song-ci','眼儿媚','[]','玉京曾忆惜繁华。',58,'宋词/ci.song.6000.json','["玉京曾忆惜繁华。", "万里帝王家。", "琼林玉殿，朝喧弦管，暮列笙琶。", "花城人去今萧索，春梦绕胡沙。", "家山何处，忍听羌笛，吹彻梅花。"]'),
('song-ci-536','燕山亭','赵佶','宋','宋词','song-ci','燕山亭','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','裁翦冰绡，打叠数重，冷淡燕脂匀注。',123,'宋词/ci.song.6000.json','["裁翦冰绡，打叠数重，冷淡燕脂匀注。", "新样靓妆，艳溢香融，羞杀蕊珠宫女。", "易得凋零，更多少、无情风雨。", "愁苦。", "闲院落凄凉，几番春暮。", "凭寄离恨重重，这双燕，何曾会人言语。", "天遥地远，万水千山，知他故宫何处。", "怎不思量，除梦里、有时会去。", "无据。", "和梦也、有时不做。"]'),
('song-ci-537','失调名','赵佶','宋','宋词','song-ci','失调名','[]','卷起珠帘。',17,'宋词/ci.song.6000.json','["卷起珠帘。", "看是谁家妃子，收拾金奁。"]'),
('song-ci-538','金莲绕凤楼','赵佶','宋','宋词','song-ci','金莲绕凤楼','[]','绛烛朱笼相随映。',67,'宋词/ci.song.6000.json','["绛烛朱笼相随映。", "驰绣毂、尘清香衬。", "万金光射龙轩莹。", "绕端门、瑞雷轻振。", "元宵为开圣景。", "严敷坐、观灯锡庆。", "帝家华英乘春兴。", "搴珠帘、望尧瞻舜。"]'),
('song-ci-539','小重山','赵佶','宋','宋词','song-ci','小重山','[]','罗绮生香娇上春。',70,'宋词/ci.song.6000.json','["罗绮生香娇上春。", "金莲开陆海，艳都城。", "宝舆回望翠峰青。", "东风鼓，吹下半天星。", "万井贺升平。", "行歌花满路，月随人。", "龙楼一点玉灯明。", "箫韶远，高宴在蓬瀛。"]'),
('song-ci-540','踏莎行','侯彭老','宋','宋词','song-ci','踏莎行','[]','十二封章，三千里路。',68,'宋词/ci.song.6000.json','["十二封章，三千里路。", "当年走遍东西府。", "时人莫讶出都忙，官家送我归乡去。", "三诏出山，一言悟主。", "古人料得皆虚语。", "太平朝野总多欢，江湖幸有宽闲处。"]'),
('song-ci-541','水龙吟','李纲','宋','宋词','song-ci','水龙吟','[]','笑不知天命，明珠玉斗，漫撞令碎。',16,'宋词/ci.song.6000.json','["笑不知天命，明珠玉斗，漫撞令碎。"]'),
('song-ci-542','水龙吟','李纲','宋','宋词','song-ci','水龙吟','[]','汉家炎运中微，坐令闰位馀分据。',126,'宋词/ci.song.6000.json','["汉家炎运中微，坐令闰位馀分据。", "南阳自有，真人膺历，龙翔虎步。", "初起昆城，旋驱乌合，块然当路。", "想莽军百万，旌旗千里，应道是、探囊取。", "豁达刘郎大度。", "对勍敌、安恬无惧。", "提兵夹击，声喧天壤，雷风借助。", "虎豹哀嗥，戈鋋委地，一时休去。", "早复收旧物，扫清氛祲，作中兴主。"]'),
('song-ci-543','念奴娇','李纲','宋','宋词','song-ci','念奴娇','[]','茂陵仙客，算真是、天与雄才宏略。',120,'宋词/ci.song.6000.json','["茂陵仙客，算真是、天与雄才宏略。", "猎取天骄驰卫霍，如使鹰鸇驱雀。", "鏖战皋兰，犁庭龙碛，饮至行勋爵。", "中华疆盛，坐令夷狄衰弱。", "追想当日巡行，勒兵十万骑，横临边朔。", "亲总貔貅谈笑看，黠虏心惊胆落。", "寄语单于，两君相见，何苦逃沙漠。", "英风如在，卓然千古高著。"]'),
('song-ci-544','喜迁莺','李纲','宋','宋词','song-ci','喜迁莺','["\u957f\u6c5f"]','长江千里。',126,'宋词/ci.song.6000.json','["长江千里。", "限南北、雪浪云涛无际。", "天险难逾，人谋克壮，索虏岂能吞噬。", "阿坚百万南牧，倏忽长驱吾地。", "破强敌，在谢公处画，从容颐指。", "奇伟。", "淝水上，八千戈甲，结阵当蛇豕。", "鞭弭周旋，旌旗麾动，坐却北军风靡。", "夜闻数声鸣鹤，尽道王师将至。", "延晋祚，庇烝民，周雅何曾专美。"]'),
('song-ci-545','水龙吟','李纲','宋','宋词','song-ci','水龙吟','[]','古来夷狄难驯，射飞择肉天骄子。',126,'宋词/ci.song.6000.json','["古来夷狄难驯，射飞择肉天骄子。", "唐家建国，北边雄盛，无如颉利。", "万马崩腾，皂旗毡帐，远临清渭。", "向郊原驰突，凭陵仓卒，知战守、难为计。", "须信君王神武。", "觇虏营、只从七骑。", "长弓大箭，据鞍诘问，单于非义。", "戈甲鲜明，旌麾光彩，六军随至。", "怅敌情震骇，鱼循鼠伏，请坚盟誓。"]'),
('song-ci-546','念奴娇','李纲','宋','宋词','song-ci','念奴娇','[]','晚唐姑息，有多少方镇，飞扬跋扈。',120,'宋词/ci.song.6000.json','["晚唐姑息，有多少方镇，飞扬跋扈。", "淮蔡雄藩联四郡，千里公然旅拒。", "同恶相资，潜伤宰辅，谁敢分明语。", "媕婀群议，共云旄节应付。", "於穆天子英明，不疑不贰处，登庸裴度。", "往督全师威令使，擒贼功名归诉。", "半夜衔枚，满城深雪，忽已亡悬瓠。", "明堂坐治，中兴高映千古。"]'),
('song-ci-547','雨霖铃','李纲','宋','宋词','song-ci','雨霖铃','[]','蛾眉修绿。',126,'宋词/ci.song.6000.json','["蛾眉修绿。", "正君王恩宠，曼舞丝竹。", "华清赐浴瑶甃，五家会处，花盈山谷。", "百里遗簪堕珥，尽宝钿珠玉。", "听突骑、鼙鼓声喧，寂寞霓裳羽衣曲。", "金舆还幸匆匆速。", "奈六军不发人争目。", "明眸皓齿难恋，肠断处、绣囊犹馥。", "剑阁峥嵘，何况铃声，带雨相续。", "谩留与、千古伤神，尽入生绡幅。"]'),
('song-ci-548','喜迁莺','李纲','宋','宋词','song-ci','喜迁莺','[]','边城寒早。',126,'宋词/ci.song.6000.json','["边城寒早。", "恣骄虏、远牧甘泉丰草。", "铁马嘶风，毡裘凌雪，坐使一方云扰。", "庙堂折冲无策，欲幸坤维江表。", "叱群议，赖寇公力挽，亲行天讨。", "缥缈。", "銮辂动，霓旌龙旆，遥指澶渊道。", "日照金戈，云随黄伞，径渡大河清晓。", "六军万姓呼舞，箭发敌酋难保。", "虏情慑，誓书来，从此年年修好。"]'),
('song-ci-549','减字木兰花','李纲','宋','宋词','song-ci','减字木兰花','[]','茫茫云海。',52,'宋词/ci.song.6000.json','["茫茫云海。", "方丈蓬壶何处在。", "拟泛轻舟。", "一到金鳌背上游。", "琼楼珠室。", "千岁蟠桃初结实。", "月冷风清。", "试倩双成吸玉笙。"]'),
('song-ci-550','减字木兰花','李纲','宋','宋词','song-ci','减字木兰花','[]','龟台金母。',52,'宋词/ci.song.6000.json','["龟台金母。", "绀发芳容超敻古。", "绛节霓旌。", "青鸟传言若可凭。", "瑶池龙宴。", "零落碧桃香片片。", "八骏西巡。", "更有何人继后尘。"]'),
('song-ci-551','永遇乐','李纲','宋','宋词','song-ci','永遇乐','[]','秋色方浓，好天凉夜，风雨初霁。',128,'宋词/ci.song.6000.json','["秋色方浓，好天凉夜，风雨初霁。", "缺月如钩，微云半掩，的灿星河碎。", "爽来轩户，凉生枕簟，夜永悄然无寐。", "起徘徊，凭栏凝伫，片时万情千意。", "江湖倦客，年来衰病，坐叹岁华空逝。", "往事成尘，新愁似锁，谁是知心底。", "五陵萧瑟，中原杳杳，但有满襟清泪。", "烛兰缸，呼童取酒，且图径醉。"]'),
('song-ci-552','望江南・忆江南','李纲','宋','宋词','song-ci','望江南・忆江南','[]','归去客，迂骑过江乡。',64,'宋词/ci.song.6000.json','["归去客，迂骑过江乡。", "茅店鸡声寒逗月，板桥人迹晓凝霜。", "一望楚天长。", "春信早，山路野梅香。", "映水酒帘斜扬日，隔林渔艇静鸣榔。", "杳杳下残阳。"]'),
('song-ci-553','水调歌头','李纲','宋','宋词','song-ci','水调歌头','[]','律吕自相召，韶頀不难谐。',114,'宋词/ci.song.6000.json','["律吕自相召，韶頀不难谐。", "致君泽物，古来何世不须才。", "幸可山林高卧，袖手何妨闲处，醇酒醉朋侪。", "千里故人驾，不怕物情猜。", "秋夜永，更秉烛，且衔杯。", "五年离索，谁谓谈笑豁幽怀。", "况我早衰多病，屏迹云山深处，俗客不曾来。", "此日扫花径，蓬户为君开。"]'),
('song-ci-554','水调歌头','李纲','宋','宋词','song-ci','水调歌头','[]','如意始身退，此事古难谐。',114,'宋词/ci.song.6000.json','["如意始身退，此事古难谐。", "中年醉饮，多病闲去正当才。", "长爱兰亭公子，弋钓溪山娱适，甘旨及朋侪。", "衰疾卧江海，鸥鸟莫惊猜。", "酒初熟，招我友，共一杯。", "碧天云卷，高挂明月照人怀。", "我醉欲眠君去，醉醒君如有意，依旧抱琴来。", "尚有一壶酒，当复为君开。"]'),
('song-ci-555','水调歌头','李纲','宋','宋词','song-ci','水调歌头','[]','物我本虚幻，世事若俳谐。',114,'宋词/ci.song.6000.json','["物我本虚幻，世事若俳谐。", "功名富贵，当得须是个般才。", "幸有山林云水，造物端如有意，分付与吾侪。", "寄语旧猿鹤，不用苦相猜。", "醉中适，一杯尽，复一杯。", "坐间有客，超诣言笑可忘怀。", "况是清风明月，如会幽人高意，千里自飞来。", "共笑陶彭泽，空对菊花开。"]'),
('song-ci-556','念奴娇','李纲','宋','宋词','song-ci','念奴娇','[]','暮云四卷，淡星河、天影茫茫垂碧。',121,'宋词/ci.song.6000.json','["暮云四卷，淡星河、天影茫茫垂碧。", "皓月浮空，人尽道，端的清圆如璧。", "丹桂扶疏，银蟾依约，千古佳今夕。", "寒光委照，有人独坐秋色。", "怅念老子平生，粗令婚嫁了，超然闲适。", "误缚簪缨遭世故，空有当时胸臆。", "苒苒流年，春鸿秋燕，来往终何益。", "云山深处，这回真是休息。"]'),
('song-ci-557','感皇恩','李纲','宋','宋词','song-ci','感皇恩','[]','九日菊花迟，茱萸却早。',81,'宋词/ci.song.6000.json','["九日菊花迟，茱萸却早。", "嫩蕊浓香自妍好。", "一簪华发，只恐西风吹帽。", "细看还遍插，人忘老。", "千古此时，清欢多少。", "铁马台空但荒草。", "旅愁如海，须把金尊销了。", "暮天秋影碧，云如扫。"]'),
('song-ci-558','渔家傲','李纲','宋','宋词','song-ci','渔家傲','[]','木落霜清秋色霁。',72,'宋词/ci.song.6000.json','["木落霜清秋色霁。", "菊苞渐吐金英碎。", "佳节不随东去水。", "谁得会。", "黄花开日重阳至。", "三径旧栽烟水外。", "故园凝望空流泪。", "香色向人如有意。", "挼落蕊。", "金尊满满从教醉。"]'),
('song-ci-559','水调歌头','李纲','宋','宋词','song-ci','水调歌头','[]','秋杪暑方退，清若玉壶冰。',114,'宋词/ci.song.6000.json','["秋杪暑方退，清若玉壶冰。", "高楼对月，天上宫殿不曾扃。", "散下凄然风露，影照江山如昼，浑觉俗缘轻。", "弋者欲何慕，鸿羽正冥冥。", "世间法，唯此事，最堪凭。", "太虚心量，聊假梨枣制颓龄。", "但使心安身健，静看草根泉际，吟蚓与飞萤。", "一坐小千劫，无念契无生。"]'),
('song-ci-560','江城子','李纲','宋','宋词','song-ci','江城子','[]','老饕嗜酒若鸱夷。',86,'宋词/ci.song.6000.json','["老饕嗜酒若鸱夷。", "拣珠玑。", "自蒸炊。", "篘尽云腴，浮蚁在瑶卮。", "有客相过同一醉，无客至，独中之。", "麴生风味有谁知。", "豁心脾。", "展愁眉。", "玉颊红潮，还似少年时。", "醉倒不知天地大，浑忘却，是和非。"]'),
('song-ci-561','江城子','李纲','宋','宋词','song-ci','江城子','[]','客中重九共登高。',86,'宋词/ci.song.6000.json','["客中重九共登高。", "逼烟霄。", "见秋毫。", "云涌群山，山外海翻涛。", "回首中原何处是，天似幕，碧周遭。", "茱萸蕊绽菊方苞。", "左倾醪。", "右持螯。", "莫把闲愁，空使寸心劳。", "会取八荒皆我室，随节物，且游遨。"]'),
('song-ci-562','感皇恩','李纲','宋','宋词','song-ci','感皇恩','[]','西阁夜初寒，炉烟轻袅。',81,'宋词/ci.song.6000.json','["西阁夜初寒，炉烟轻袅。", "竹枕绸衾素屏小。", "片时清梦，又被木鱼惊觉。", "半窗残月影，天将晓。", "幻境去来，胶胶扰扰。", "追想平生发孤笑。", "壮怀消散，尽付败荷衰草。", "个中还得趣，从他老。"]'),
('song-ci-563','望江南・忆江南','李纲','宋','宋词','song-ci','望江南・忆江南','[]','新阁就，向日借清光。',64,'宋词/ci.song.6000.json','["新阁就，向日借清光。", "广厦生风非我志，小窗容膝正相当。", "聊此傲羲皇。", "狨尾拂，高挂木绳床。", "老病维摩谁问疾，散花天女为焚香。", "恰好细商量。"]'),
('song-ci-564','望江南・忆江南','李纲','宋','宋词','song-ci','望江南・忆江南','[]','新酒熟，云液满香篘。',64,'宋词/ci.song.6000.json','["新酒熟，云液满香篘。", "溜溜清声归小瓮，温温玉色照瓷瓯。", "饮兴浩难收。", "嘉客至，一酌散千忧。", "顾我老方齐物论，与君同作醉乡游。", "万事总休休。"]'),
('song-ci-565','望江南・忆江南','李纲','宋','宋词','song-ci','望江南・忆江南','[]','新雨足，一夜满南塘。',64,'宋词/ci.song.6000.json','["新雨足，一夜满南塘。", "粳稻向成初吐秀，芰荷虽败尚馀香。", "爽气入轩窗。", "澄霁后，远岫更青苍。", "两部蛙声鸣鼓吹，一天星月浸光芒。", "秋色陡凄凉。"]'),
('song-ci-566','望江南・忆江南','李纲','宋','宋词','song-ci','望江南・忆江南','[]','新月出，清影尚苍茫。',64,'宋词/ci.song.6000.json','["新月出，清影尚苍茫。", "学扇欲生青海上，如钩先挂碧霄傍。", "星斗焕文章。", "林下客，把酒挹孤光。", "斟酌嫦娥怜我老，故窥书幌照人床。", "此意自难忘。"]'),
('song-ci-567','江城子','李纲','宋','宋词','song-ci','江城子','[]','琉璃滑处玉花飞。',86,'宋词/ci.song.6000.json','["琉璃滑处玉花飞。", "溅珠玑。", "喷霏微。", "谁遣银河，一派九天垂。", "昨夜白虹来涧饮，留不去，许多时。", "幽人独坐石嵚崎。", "赏清奇。", "濯涟漪。", "不怕深沈，潭底有蛟螭。", "澒洞但闻金石奏，猿鸟乐，共忘归。"]'),
('song-ci-568','减字木兰花','李纲','宋','宋词','song-ci','减字木兰花','[]','华清赐浴。',52,'宋词/ci.song.6000.json','["华清赐浴。", "宝瓮温泉浇腻玉。", "笑靥开时。", "一骑红尘献荔枝。", "明珠乍剖。", "自擘轻红香满手。", "锦袜罗囊。", "犹瘗当年驿路旁。"]'),
('song-ci-569','减字木兰花','李纲','宋','宋词','song-ci','减字木兰花','[]','仙姝丽绝。',52,'宋词/ci.song.6000.json','["仙姝丽绝。", "被服红绡肤玉雪。", "火齐堆盘。", "常得杨妃带笑看。", "劳生重马。", "远贡长为千古话。", "林下甘芳。", "却准幽人餍饫尝。"]'),
('song-ci-570','丑奴儿・采桑子','李纲','宋','宋词','song-ci','丑奴儿・采桑子','[]','幽芳不为春光发，直待秋风。',52,'宋词/ci.song.6000.json','["幽芳不为春光发，直待秋风。", "直待秋风。", "香比馀花分外浓。", "步摇金翠人如玉，吹动珑璁。", "吹动珑璁。", "恰似瑶台月下逢。"]'),
('song-ci-571','丑奴儿・采桑子','李纲','宋','宋词','song-ci','丑奴儿・采桑子','[]','枝头万点妆金蕊，十里清香。',52,'宋词/ci.song.6000.json','["枝头万点妆金蕊，十里清香。", "十里清香。", "解引幽人雅思长。", "玉壶贮水花难老，净几明窗。", "净几明窗。", "褪下残英蔌蔌黄。"]'),
('song-ci-572','江城子','李纲','宋','宋词','song-ci','江城子','[]','去年九日在衡阳。',86,'宋词/ci.song.6000.json','["去年九日在衡阳。", "满林霜。", "俯潇湘。", "回雁峰头，依约雁南翔。", "遥想茱萸方遍插，唯少我，一枝香。", "今年佳节幸相将。", "陟层冈。", "举华觞。", "地暖风和，犹未菊开黄。", "此会明年知健否，判酩酊，醉秋光。"]'),
('song-ci-573','水调歌头','李纲','宋','宋词','song-ci','水调歌头','[]','太白乃吾祖，逸气薄青云。',114,'宋词/ci.song.6000.json','["太白乃吾祖，逸气薄青云。", "开元有道，聊复乘兴一来宾。", "天子呼来方醉，洒面清泉微醒，馀吐试龙巾。", "词翰不加点，歌阕满宫春。", "笔风雨，心锦绣，极清新。", "大儿中令，神契兼有坐忘人。", "不识将军高贵，醉里指污吾足，乃敢尚衣嗔。", "千载已仙去，图象耸风神。"]'),
('song-ci-574','水龙吟','李纲','宋','宋词','song-ci','水龙吟','[]','际天云海无涯，径从一叶舟中渡。',126,'宋词/ci.song.6000.json','["际天云海无涯，径从一叶舟中渡。", "天容海色，浪平风稳，何尝有飓。", "鳞甲千山，笙镛群籁，了无遮护。", "笑读君佳阕，追寻往事，须信道、忘来去。", "闻说钓鲸公子，为才名、鹗书交举。", "高怀澹泊，柏台兰省，留连莫住。", "万里闽山，不从海道，寄声何处。", "怅七年契阔，无因握手，与开怀语。"]'),
('song-ci-575','水龙吟','李纲','宋','宋词','song-ci','水龙吟','[]','莫春清淑之初，赏心最乐惟修禊。',126,'宋词/ci.song.6000.json','["莫春清淑之初，赏心最乐惟修禊。", "兰亭序饮，泛觞流咏，萧然适意。", "旧弼宗英，文章贤牧，肯临坰外。", "向碧山深处，寻花问柳，有佳气、随旌旆。", "寥落幽人寓止。", "惜僧园、缭云萦水。", "栽花种竹，凿池开径，渊明岂愧。", "美景良辰，玉颜方老，欲留何计。", "对残红嫩绿，开怀笑时，且须同醉。"]'),
('song-ci-576','水调歌头','李纲','宋','宋词','song-ci','水调歌头','[]','花径不曾扫，蓬户为君开。',114,'宋词/ci.song.6000.json','["花径不曾扫，蓬户为君开。", "元戎小队，清晓佳客与同来。", "我为衰迟多病，且恁浇花艺药，随分葺池台。", "多谢故人意，迂访白云隈。", "暮春月，修禊事，会兰斋。", "一觞一咏，何愧当日畅幽怀。", "况是茂林修竹，映带清流湍激，山色碧崔嵬。", "勿复叹陈迹，且为醉金杯。"]'),
('song-ci-577','江城子','李纲','宋','宋词','song-ci','江城子','[]','武夷山里一溪横。',86,'宋词/ci.song.6000.json','["武夷山里一溪横。", "晚风清。", "断霞明。", "行至晞真、馆下月华生。", "仙迹灵踪知几许，云缥缈，石峥嵘。", "羽人同载小舟轻。", "玉壶倾。", "荐芳馨。", "酣饮高歌，时作步虚声。", "一梦游仙非偶尔，回棹远，翠烟凝。"]'),
('song-ci-578','江城子','李纲','宋','宋词','song-ci','江城子','["\u592a\u6e56"]','春来江上打头风。',86,'宋词/ci.song.6000.json','["春来江上打头风。", "吼层空。", "卷飞蓬。", "多少云涛，雪浪暮江中。", "早是客情多感慨，烟漠漠，雨濛濛。", "梁溪只在太湖东。", "长儿童。", "学庞翁。", "谁信家书，三月不曾通。", "见说浙河金鼓震，何日到，羡归鸿。"]'),
('song-ci-579','江城子','李纲','宋','宋词','song-ci','江城子','[]','晓来江口转南风。',86,'宋词/ci.song.6000.json','["晓来江口转南风。", "静烟空。", "整云蓬。", "满眼高帆，隐映画图中。", "呕轧数声离岸橹，云暗淡，雪溟濛。", "扁舟归去五湖东。", "狎樵童。", "侣渔翁。", "不管人间，荣辱与穷通。", "试作五噫歌汉室，从隐遁，作梁鸿。"]'),
('song-ci-580','望江南・忆江南','李纲','宋','宋词','song-ci','望江南・忆江南','[]','征骑远，千里别沙阳。',64,'宋词/ci.song.6000.json','["征骑远，千里别沙阳。", "泛碧斋傍凝翠阁，凄云寺里印心堂。", "回首意茫茫。", "分水岭，烟雨正凄凉。", "南望瓯闽连海峤，北归吴越过江乡。", "极目暮云长。"]'),
('song-ci-581','望江南・忆江南','李纲','宋','宋词','song-ci','望江南・忆江南','[]','云岭水，南北自分流。',64,'宋词/ci.song.6000.json','["云岭水，南北自分流。", "触目澜翻飞雪浪，赴溪盘屈转琼钩。", "呜咽不胜愁。", "归去客，征骑远闽州。", "路入江南春信未，日行北陆冷光浮。", "还揽旧貂裘。"]'),
('song-ci-582','望江南・忆江南','李纲','宋','宋词','song-ci','望江南・忆江南','[]','云棹远，南浦绿波春。',64,'宋词/ci.song.6000.json','["云棹远，南浦绿波春。", "日暖风和初解冻，饵香竿袅好垂纶。", "一钓得金鳞。", "风乍起，吹皱碧渊沦。", "红脍斫来龙更美，白醪酤得旨兼醇。", "一醉武陵人。"]'),
('song-ci-583','望江南・忆江南','李纲','宋','宋词','song-ci','望江南・忆江南','[]','清昼永，幽致夏来多。',64,'宋词/ci.song.6000.json','["清昼永，幽致夏来多。", "远岸参差风扬柳，平湖清浅露翻荷。", "移棹钓烟波。", "凉一霎，飞雨洒轻蓑。", "满眼生涯千倾浪，放怀乐事一声歌。", "不醉欲如何。"]'),
('song-ci-584','望江南・忆江南','李纲','宋','宋词','song-ci','望江南・忆江南','[]','烟艇稳，浦溆正清秋。',64,'宋词/ci.song.6000.json','["烟艇稳，浦溆正清秋。", "风细波平宜进楫，月明江静好沈钩。", "横笛起汀洲。", "鲈鳜美，新酿蚁醅浮。", "休问六朝兴废事，白苹红蓼正凝愁。", "千古一渔舟。"]'),
('song-ci-585','望江南・忆江南','李纲','宋','宋词','song-ci','望江南・忆江南','[]','江上雪，独立钓渔翁。',64,'宋词/ci.song.6000.json','["江上雪，独立钓渔翁。", "箬笠但闻冰散响，蓑衣时振玉花空。", "图画若为工。", "云水暮，归去远烟中。", "茅舍竹篱依小屿，缩鳊圆鲫入轻笼。", "欢笑有儿童。"]'),
('song-ci-586','六么令','李纲','宋','宋词','song-ci','六么令','["\u957f\u6c5f"]','长江千里，烟澹水云阔。',112,'宋词/ci.song.6000.json','["长江千里，烟澹水云阔。", "歌沈玉树，古寺空有疏钟发。", "六代兴亡如梦，苒苒惊时月。", "兵戈凌灭。", "豪华销尽，几见银蟾自圆缺。", "潮落潮生波渺，江树森如发。", "谁念迁客归来，老大伤名节。", "纵使岁寒途远，此志应难夺。", "高楼谁设。", "倚阑凝望，独立渔翁满江雪。"]'),
('song-ci-587','喜迁莺','李纲','宋','宋词','song-ci','喜迁莺','[]','江天霜晓。',125,'宋词/ci.song.6000.json','["江天霜晓。", "对万顷雪浪，云涛弥渺。", "远岫参差，烟树微茫，阅尽往来人老。", "浅沙别浦极望，满目馀霞残照。", "暮云敛，放一轮明月，窥人怀抱。", "杳杳。", "千里恨，玉人一别，梦断无音耗。", "手拈江梅，枝头春信，欲寄算应难到。", "画船片帆浮碧，更值风高波浩。", "几时得向尊前，销却许多烦恼。"]'),
('song-ci-588','喜迁莺','李纲','宋','宋词','song-ci','喜迁莺','[]','边城寒早。',125,'宋词/ci.song.6000.json','["边城寒早。", "对漠漠暮秋，霜风烟草。", "战□长闲，刁斗无声，空使荷戈人老。", "陇头立马极目，万里长城古道。", "感怀处，问仲宣云乐，从军多少。", "缥缈。", "云岭外，夕烽一点，塞上传光小。", "玉帐尊罍，青油谈笑，肯把壮怀销了。", "画楼数声残角，吹彻梅花霜晓。", "愿岁岁静烟尘，羌虏常修邻好。"]'),
('song-ci-589','一翦梅','李纲','宋','宋词','song-ci','一翦梅','[]','数点梅花玉雪娇。',72,'宋词/ci.song.6000.json','["数点梅花玉雪娇。", "烟水篱边，半袅青梢。", "横斜疏影月黄昏，谁使天香，暗淡飘飘。", "半醉佳人酒未消。", "宝髻偏时，插更斜袅。", "尊前还唱早梅词，琼醑何如，□□□□。"]'),
('song-ci-590','玉蝴蝶','李纲','宋','宋词','song-ci','玉蝴蝶','[]','万古秣陵江国，舣舟烟岸，千里云林。',120,'宋词/ci.song.6000.json','["万古秣陵江国，舣舟烟岸，千里云林。", "故垒高楼，凝望远水遥岑。", "景阳钟、那闻旧响，玉树唱、空有馀音。", "感春心。", "六朝遗事，萧索难寻。", "甘泉法从弟兄芝玉，顾我情深。", "契阔相思，岂知今日共登临。", "对尊俎、休辞痛饮，伤志节、须且高吟。", "柳摇金。", "断霞轻霭，残照西沈。"]'),
('song-ci-591','水龙吟','李纲','宋','宋词','song-ci','水龙吟','[]','晚春天气融和，乍惊密雪烟空坠。',126,'宋词/ci.song.6000.json','["晚春天气融和，乍惊密雪烟空坠。", "因风飘荡，千门万户，牵情惹思。", "青眼初开，翠眉才展，小园长闭。", "又谁知化作，琼花玉屑，共榆荚、漫天起。", "深院美人慵困，乱云鬟、尽从妆缀。", "小廊回处，氍毹重叠，轻拈却碎。", "飞入楼台，舞穿帘幕，总归流水。", "怅青春又过，年年此恨，满东风泪。"]'),
('song-ci-592','满庭芳','李纲','宋','宋词','song-ci','满庭芳','[]','何时得，恩来日下，蓑笠老江湖。',15,'宋词/ci.song.6000.json','["何时得，恩来日下，蓑笠老江湖。"]'),
('song-ci-593','西江月','李纲','宋','宋词','song-ci','西江月','[]','意态何如涎涎，轻盈只恐飞飞。',58,'宋词/ci.song.6000.json','["意态何如涎涎，轻盈只恐飞飞。", "华堂偏傍主人栖。", "好与安巢稳戏。", "揽断楼中风月，且看掌上腰支。", "谪仙词赋少陵诗。", "万语千言总记。"]'),
('song-ci-594','苏武令','李纲','宋','宋词','song-ci','苏武令','[]','塞上风高，渔阳秋早。',106,'宋词/ci.song.6000.json','["塞上风高，渔阳秋早。", "惆怅翠华音杳。", "驿使空驰，征鸿归尽，不寄双龙消耗。", "念白衣、金殿除恩，归黄阁、未成图报。", "谁信我、致主丹衷，伤时多故，未作救民方召。", "调鼎为霖，登坛作将，燕然即须平扫。", "拥精兵十万，横行沙漠，奉迎天表。"]'),
('song-ci-595','感皇恩','胡舜陟','宋','宋词','song-ci','感皇恩','[]','乞得梦中身，归栖云水。',81,'宋词/ci.song.6000.json','["乞得梦中身，归栖云水。", "始觉精神自家底。", "峭帆轻棹，时与白鸥游戏。", "畏途都不管，风波起。", "光景如梭，人生浮脆。", "百岁何妨尽沈醉。", "卧龙多事，谩说三分奇计。", "算来争似我，长昏睡。"]'),
('song-ci-596','渔家傲','胡舜陟','宋','宋词','song-ci','渔家傲','[]','几日北风江海立。',72,'宋词/ci.song.6000.json','["几日北风江海立。", "千车万马鏖声急。", "短棹峭寒欺酒力。", "飞雨息。", "琼花细细穿窗隙。", "我本绿蓑青箬笠。", "浮家泛宅烟波逸。", "渚鹭沙鸥多旧识。", "行未得。", "高歌与尔相寻觅。"]'),
('song-ci-597','减字木兰花','李祁','宋','宋词','song-ci','减字木兰花','[]','梨花院宇。',52,'宋词/ci.song.6000.json','["梨花院宇。", "澹月倾云初过雨。", "一枝轻寒。", "梦入西瑶小道山。", "花深人静。", "帘锁御香清昼永。", "红药阑干。", "玉案春风窈窕间。"]'),
('song-ci-598','点绛唇','李祁','宋','宋词','song-ci','点绛唇','[]','楼下清歌，水流歌断春风暮。',50,'宋词/ci.song.6000.json','["楼下清歌，水流歌断春风暮。", "梦云烟树。", "依约江南路。", "碧水黄沙，梦到寻梅处。", "花无数。", "问花无语。", "明月随人去。"]'),
('song-ci-599','青玉案','李祁','宋','宋词','song-ci','青玉案','[]','绿琐窗纱明月透。',80,'宋词/ci.song.6000.json','["绿琐窗纱明月透。", "正清梦、莺啼柳。", "碧井银瓶鸣玉甃。", "翔鸾妆样，粲花衫绣。", "分付春风手。", "喜入秋波娇欲溜。", "脉脉青山两眉秀。", "玉枕春寒郎知否。", "归来留取，御香襟袖。", "同饮酴醿酒。"]'),
('song-ci-600','鹊桥仙','李祁','宋','宋词','song-ci','鹊桥仙','[]','春阴淡淡，春波渺渺，帘卷花稍香雾。',68,'宋词/ci.song.6000.json','["春阴淡淡，春波渺渺，帘卷花稍香雾。", "小舟谁在落梅村，正梦绕、清溪烟雨。", "碧山学士，云房娇小，须要五湖同去。", "桃花流水鳜鱼肥，恰趁得、江天佳处。"]'),
('song-ci-601','阮郎归','李祁','宋','宋词','song-ci','阮郎归','[]','校书学士小蓬山。',28,'宋词/ci.song.6000.json','["校书学士小蓬山。", "新参玉笋班。", "买花归去五湖间。", "浣花龙尾湾。"]'),
('song-ci-602','南歌子','李祁','宋','宋词','song-ci','南歌子','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','袅袅秋风起，萧萧败叶声。',62,'宋词/ci.song.6000.json','["袅袅秋风起，萧萧败叶声。", "岳阳楼上听哀筝。", "楼下凄凉江月、为谁明。", "雾雨沈云梦，烟波渺洞庭。", "可怜无处问湘灵。", "只有无情江水、绕孤城。"]'),
('song-ci-603','醉桃源・阮郎归','李祁','宋','宋词','song-ci','醉桃源・阮郎归','[]','春风碧水满郎湖。',56,'宋词/ci.song.6000.json','["春风碧水满郎湖。", "水清梅影疏。", "渡江桃叶酒家垆。", "髻鬟云样梳。", "吹玉蕊，饮琼腴。", "不须红袖扶。", "少年随意数花须。", "老来心已无。"]'),
('song-ci-604','朝中措','李祁','宋','宋词','song-ci','朝中措','[]','郎官湖上探春回。',57,'宋词/ci.song.6000.json','["郎官湖上探春回。", "初见照江梅。", "过尽竹溪流水，无人知道花开。", "佳人何处，江南梦远，殊未归来。", "唤取小丛教看，隔江烟雨楼台。"]'),
('song-ci-605','西江月','李祁','宋','宋词','song-ci','西江月','[]','拾翠亭前水满，郎官湖上春回。',58,'宋词/ci.song.6000.json','["拾翠亭前水满，郎官湖上春回。", "仪龙新碾试琼杯。", "更见春江有味。", "拄杖行穿翠篠，吹花醉绕江梅。", "故园心事老相催。", "此意陶潜能会。"]'),
('song-ci-606','西江月','李祁','宋','宋词','song-ci','西江月','[]','云观三山清露，长生万鬣青松。',58,'宋词/ci.song.6000.json','["云观三山清露，长生万鬣青松。", "琼璈珠珥下秋空。", "一笑满天鸾凤。", "雾鬓新梳绀绿，霞衣旧佩柔红。", "更邀豪俊驭南风。", "此意平生飞动。"]'),
('song-ci-607','如梦令','李祁','宋','宋词','song-ci','如梦令','[]','春水湖塘深处。',40,'宋词/ci.song.6000.json','["春水湖塘深处。", "竹暗沙洲无路。", "闲伴落花来，却信东风归去。", "且住。", "且住。", "细看两山烟雨。"]'),
('song-ci-608','如梦令','李祁','宋','宋词','song-ci','如梦令','[]','不见玉人清晓。',40,'宋词/ci.song.6000.json','["不见玉人清晓。", "长啸一声云杪。", "碧水满阑塘，竹外一枝风袅。", "奇妙。", "奇妙。", "半夜山空月皎。"]'),
('song-ci-609','水龙吟','李祁','宋','宋词','song-ci','水龙吟','[]','碧山横绕清湖，茂林秀麓波光里。',125,'宋词/ci.song.6000.json','["碧山横绕清湖，茂林秀麓波光里。", "南宫老大，西洲漂荡，危亭重倚。", "雨步云行，饵风饮雾，平生游戏。", "笑此中空洞，都无一物，有神妙、浩然气。", "扫尽云南梦北，看三江五湖秋水。", "狂歌两解，清尊一举，超然千里。", "江汉苍茫，故人何处，山川良是。", "待白苹露下，青天月上，约骑鲸起。"]'),
('song-ci-610','浪淘沙','李祁','宋','宋词','song-ci','浪淘沙','[]','拍手趁西风。',64,'宋词/ci.song.6000.json','["拍手趁西风。", "惊起乖龙。", "青山绿水古今同。", "唯有一轮山上月，长照江中。", "一点落金钟。", "浑似虚空。", "道人不住有云峰。", "但是人家清酒瓮，行处相逢。"]'),
('song-ci-611','如梦令','叶祖义','宋','宋词','song-ci','如梦令','[]','如梦。',13,'宋词/ci.song.6000.json','["如梦。", "如梦。", "和尚出门相送。"]'),
('song-ci-612','失调名','左誉','宋','宋词','song-ci','失调名','[]','无所事，盈盈秋水，淡淡春山。',14,'宋词/ci.song.6000.json','["无所事，盈盈秋水，淡淡春山。"]'),
('song-ci-613','失调名','左誉','宋','宋词','song-ci','失调名','[]','一段离愁堪画处，横风斜雨摇衰柳。',16,'宋词/ci.song.6000.json','["一段离愁堪画处，横风斜雨摇衰柳。"]'),
('song-ci-614','失调名','左誉','宋','宋词','song-ci','失调名','[]','帷云剪水，滴粉搓酥。',10,'宋词/ci.song.6000.json','["帷云剪水，滴粉搓酥。"]'),
('song-ci-615','洞仙歌','吕直夫','宋','宋词','song-ci','洞仙歌','[]','征鞍带月，浓露沾襟袖。',104,'宋词/ci.song.6000.json','["征鞍带月，浓露沾襟袖。", "马上轻衫峭寒透。", "望翠峰深浅，忆着眉儿，腰枝袅，忍看风前细柳。", "别时频嘱付，早寄书来，能趁清明到家否。", "这言语，便梦里、也在心头，重相见、不知伊瘦我瘦。", "纵百卉千花已离披，也趁锝、酴醿牡丹时候。"]'),
('song-ci-616','婆罗门引','杨景','宋','宋词','song-ci','婆罗门引','[]','帐云暮卷，漏声不到小帘栊。',93,'宋词/ci.song.6000.json','["帐云暮卷，漏声不到小帘栊。", "银汉夜洗晴空。", "皓月堂轩高挂，秋入广寒宫。", "正金波不动，桂影玲珑。", "佳人未逢。", "怅此夕、与谁同。", "对酒当歌，追念霜满愁红。", "南楼何处，愁人在、横笛一声中。", "凝望眼、立尽西风。"]'),
('song-ci-617','西江月','范智闻','宋','宋词','song-ci','西江月','[]','紫素全如玉琢，清音不假金妆。',58,'宋词/ci.song.6000.json','["紫素全如玉琢，清音不假金妆。", "海沈时许试芬芳。", "仿佛云飞仙掌。", "烟缕不愁凄断，宝钗还与商量。", "佳人特特为翻香。", "图得氤氲重上。"]'),
('song-ci-618','好事近','蒋元龙','宋','宋词','song-ci','好事近','[]','叶暗乳鸦啼，风定老红犹落。',53,'宋词/ci.song.6000.json','["叶暗乳鸦啼，风定老红犹落。", "蝴蝶不随春去，入薰风池阁。", "休歌金缕劝金卮，酒病煞如昨。", "帘卷日长人静，任杨花飘泊。"]'),
('song-ci-619','阮郎归','蒋元龙','宋','宋词','song-ci','阮郎归','[]','小池芳草绿初匀。',56,'宋词/ci.song.6000.json','["小池芳草绿初匀。", "柳寒眉尚颦。", "东风吹雨细於尘。", "一庭花脸皴。", "莺共蝶，怨还嗔。", "眼前无好春。", "这般天气煞愁人。", "人愁旋旋新。"]'),
('song-ci-620','乌夜啼','蒋元龙','宋','宋词','song-ci','乌夜啼','[]','小桃落尽残红。',45,'宋词/ci.song.6000.json','["小桃落尽残红。", "夜来风。", "又是一番春事、不从容。", "翠屏掩。", "芳信断。", "转愁浓。", "可惜日长闲暇、小帘栊。"]'),
('song-ci-621','绿头鸭・多丽','周格非','宋','宋词','song-ci','绿头鸭・多丽','[]','陇头泉，未到陇下轻分。',173,'宋词/ci.song.6000.json','["陇头泉，未到陇下轻分。", "一声声、凄凉呜咽，岂堪侧耳重闻。", "细思量、那时携手，画楼高、帘幕黄昏。", "月不长圆，云多轻散，天应偏妒有情人。", "自别后、小窗幽院，无处不消魂。", "罗衣上，残妆未减，犹带啼痕。", "自一从、瓶沈簪折，杳知欲见无因。", "也浑疑、事如春梦，又只愁、人是朝云。", "破境分来，朱弦断后，不堪独自对芳樽。", "试与问，多才谁更，匹配得文君。", "须知道，东阳瘦损，不为伤春。"]'),
('song-ci-622','西江月','程邻','宋','宋词','song-ci','西江月','[]','阶下宝鞍罗帕，门前绛蜡纱笼。',58,'宋词/ci.song.6000.json','["阶下宝鞍罗帕，门前绛蜡纱笼。", "留连佳客怅匆匆。", "赖有新团小凤。", "琼碎黄金碾里，乳浮紫玉瓯中。", "归来袭袭袖生风。", "齿颊馀甘入梦。"]'),
('song-ci-623','宴清都','何籀','宋','宋词','song-ci','宴清都','[]','细草沿阶软。',129,'宋词/ci.song.6000.json','["细草沿阶软。", "迟日薄，蕙风轻蔼微暖。", "春工靳惜，桃红尚小，柳芽犹短。", "罗帏绣幕高卷。", "又早是、歌慵笑懒。", "凭画楼，那更天远，山远，水远，人远。", "堪叹。", "傅粉疏狂，窃香俊雅，无计拘管。", "青丝绊马，红巾寄泪，甚处迷恋。", "无言泪珠零乱。", "翠袖滴、重重渍遍。", "故要知、别后思量。", "归时觑见。"]'),
('song-ci-624','烛影摇红','廖世美','宋','宋词','song-ci','烛影摇红','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','霭霭春空，画楼森耸凌云渚。',116,'宋词/ci.song.6000.json','["霭霭春空，画楼森耸凌云渚。", "紫薇登览最关情，绝妙夸能赋。", "惆怅相思迟暮。", "记当日、朱阑共语。", "塞鸿难问，岸柳何穷，别愁纷絮。", "催促年光，旧来流水知何处。", "断肠何必更残阳，极目伤平楚。", "晚霁波声带雨。", "悄无人、舟横野渡。", "数峰江上，芳草天涯，参差烟树。"]'),
('song-ci-625','好事近','廖世美','宋','宋词','song-ci','好事近','[]','落日水熔金，天淡暮烟凝碧。',53,'宋词/ci.song.6000.json','["落日水熔金，天淡暮烟凝碧。", "楼上谁家红袖，靠阑干无力。", "鸳鸯相对浴红衣，短棹弄长笛。", "惊起一双飞去，听波声拍拍。"]'),
('song-ci-626','菩萨蛮','李元卓','宋','宋词','song-ci','菩萨蛮','[]','一枝绛蜡香梅软。',52,'宋词/ci.song.6000.json','["一枝绛蜡香梅软。", "宜春小胜玲珑剪。", "拂晓上瑶钗。", "春从鬓底来。", "菱花频自照。", "粉面惊春早。", "淡拂晓山眉。", "为谁今日宜。"]'),
('song-ci-627','人娇','张方仲','宋','宋词','song-ci','人娇','[]','多少胭脂，匀成点就。',82,'宋词/ci.song.6000.json','["多少胭脂，匀成点就。", "千枝乱、攒红堆绣。", "花无长好，更光阴去骤。", "对景忆良朋，故应招手。", "曾说年时，花间把酒。", "任淋浪、春衫湿透。", "文园今病，问远能来否。", "却道有酴醿、牡丹时候。"]'),
('song-ci-628','透碧霄','查','宋','宋词','song-ci','透碧霄','[]','舣兰舟。',140,'宋词/ci.song.6000.json','["舣兰舟。", "十分端是载离愁。", "练波送远，屏山遮断，此去难留。", "相从争奈，心期久要，屡更霜秋。", "叹人生、杳似萍浮。", "又翻成轻别，都将深恨，付与东流。", "想斜阳影里，寒烟明处，双桨去悠悠。", "爱渚梅、幽香动，须采掇、倩纤柔。", "艳歌粲发，谁传馀韵，来说仙游。", "念故人、留此遐洲。", "但春风老后，秋月圆时，独倚西楼。"]'),
('song-ci-629','卜算子','李敦诗','宋','宋词','song-ci','卜算子','[]','南北利名人，常恨家居少。',52,'宋词/ci.song.6000.json','["南北利名人，常恨家居少。", "每到春时听子规，无不伤怀抱。", "好去向长安，细与公卿道。", "待得功成名遂时，不似归来早。"]'),
('song-ci-630','忆真妃・相见欢','康仲伯','宋','宋词','song-ci','忆真妃・相见欢','[]','匆匆一望关河。',45,'宋词/ci.song.6000.json','["匆匆一望关河。", "听离歌。", "艇子急催双桨、下清波。", "淋浪醉。", "阑干泪。", "奈情何。", "明日画桥西畔、暮云多。"]'),
('song-ci-631','昭君怨','程过','宋','宋词','song-ci','昭君怨','[]','试问愁来何处。',48,'宋词/ci.song.6000.json','["试问愁来何处。", "门外山无重数。", "芳草不知人。", "翠连云。", "欲看不忍重看。", "心事只堪肠断。", "肠断宿孤村。", "雨昏昏。"]'),
('song-ci-632','满江红','程过','宋','宋词','song-ci','满江红','[]','春欲来时，长是与、江梅花约。',115,'宋词/ci.song.6000.json','["春欲来时，长是与、江梅花约。", "又还向、竹林疏处，一枝开却。", "对酒渐惊身老大，看花应念人离索。", "但十分、沈醉祝东君，长如昨。", "芳草渡，孤舟泊。", "山敛黛，天垂幕。", "黯销魂、无奈暮云残角。", "便好折来和雪戴，莫教酒醒随风落。", "待殷勤、留此记相思，谁堪托。"]'),
('song-ci-633','浣溪沙','曾','宋','宋词','song-ci','浣溪沙','[]','别样清芬扑鼻来。',48,'宋词/ci.song.6000.json','["别样清芬扑鼻来。", "秋香过后却追回。", "博山轻雾锁崔嵬。", "珍重芗林三昧手，不教一日不花开。", "暗中错认是江梅。"]'),
('song-ci-634','调笑令','曾','宋','宋词','song-ci','调笑令','[]','佳友。',45,'宋词/ci.song.6000.json','["佳友。", "金英辏。", "陶令篱边常宿留。", "秋风一夜摧枯朽。", "独艳重阳时候。", "剩收芳蕊浮卮酒。", "荐酒先生眉寿。"]'),
('song-ci-635','调笑・调笑令','曾','宋','宋词','song-ci','调笑・调笑令','[]','清友。',45,'宋词/ci.song.6000.json','["清友。", "群芳右。", "万缟纷披兹独秀。", "天寒月薄黄昏后。", "缟袂亭亭招手。", "故山千树连云岫。", "借问如今安否。"]'),
('song-ci-636','调笑・调笑令','曾','宋','宋词','song-ci','调笑・调笑令','[]','净友。',45,'宋词/ci.song.6000.json','["净友。", "如妆就。", "折得清香来满手。", "一溪湛湛无尘垢。", "白羽轻摇晴昼。", "远公保社今何有。", "怅望东林搔首。"]'),
('song-ci-637','调笑・调笑令','曾','宋','宋词','song-ci','调笑・调笑令','[]','玉友。',45,'宋词/ci.song.6000.json','["玉友。", "平生旧。", "相与忘形偏耐久。", "醉乡径到无何有。", "莫问区区升斗。", "人生一笑难开口。", "为报速宜相就。"]'),
('song-ci-638','调笑・调笑令','曾','宋','宋词','song-ci','调笑・调笑令','[]','花好。',45,'宋词/ci.song.6000.json','["花好。", "被花恼。", "庭下嫣然如巧笑。", "曾教健步移根到。", "各是一般奇妙。", "赏心乐事知多少。", "乱插繁华晴昊。"]'),
('song-ci-639','调笑・调笑令','曾','宋','宋词','song-ci','调笑・调笑令','[]','酒美。',45,'宋词/ci.song.6000.json','["酒美。", "直无比。", "小瓮新醅浮玉蚁。", "空传乌氏并程氏。", "不数云安曲米。", "十花更互来相对。", "常伴先生沈醉。"]'),
('song-ci-640','临江仙','曾','宋','宋词','song-ci','临江仙','[]','子后寅前东向坐，冥心琢齿鸣鼍。',70,'宋词/ci.song.6000.json','["子后寅前东向坐，冥心琢齿鸣鼍。", "托天回顾眼光摩。", "张弓仍踏弩，升降辘轳多。", "三度朝元九度转，背摩双摆扳弩。", "虎龙交际咽元和。", "浴身挑甲罢，便可蹑烟萝。"]'),
('song-ci-641','念奴娇','张纲','宋','宋词','song-ci','念奴娇','[]','论思厌久，动莼鲈清兴，轻辞丹极。',120,'宋词/ci.song.6000.json','["论思厌久，动莼鲈清兴，轻辞丹极。", "佩玉腰金归故里，光照湖山秋色。", "八座仪刑，九重尊宠，才大今词伯。", "汉家豪俊，一时谁是勍敌。", "三径旧日家声，华堂深稳处，频开瑶席。", "春在壶中真自有，一境珠宫仙掖。", "谭程挥风，罚筹如猬，数因尊前客。", "故应元放，举杯狂醉轻掷。"]'),
('song-ci-642','念奴娇','张纲','宋','宋词','song-ci','念奴娇','[]','多情宋玉，值西风摇落，悲秋时节。',120,'宋词/ci.song.6000.json','["多情宋玉，值西风摇落，悲秋时节。", "赖有幽芳深解意，的皪枝头争发。", "欲语含羞，敛容微笑，心事如何说。", "暗香时度，卷帘留伴霜月。", "谁为赋写仙姿，挥毫落纸，有尊前词客。", "独倚阑干须信道，消得孤吟愁绝。", "补阙骚经，拾遗香传，顿许居前列。", "品题多谢，一枝当为君折。"]'),
('song-ci-643','青门饮','张纲','宋','宋词','song-ci','青门饮','[]','疏柳飘零，暮鸦寒集，都门送客，斜阳影里。',132,'宋词/ci.song.6000.json','["疏柳飘零，暮鸦寒集，都门送客，斜阳影里。", "野色沈沈，翠微隐隐，遥指故乡云外。", "聚久交情厚，对西风、争忍分袂。", "饮散宾朋，画船去也，平芜千里。", "因记。", "小轩无寐。", "观夜月凭阑，共论深契。", "绛帐清闲，杏坛优暇，当念宴游同醉。", "南北烟波远，愿无忘、音书频寄。", "未知名宦拘人，异日相逢何地。"]'),
('song-ci-644','蓦山溪','张纲','宋','宋词','song-ci','蓦山溪','[]','小窗开宴，草草杯盘具。',102,'宋词/ci.song.6000.json','["小窗开宴，草草杯盘具。", "欢喜走儿童，庆生朝、一年一度。", "风光好处，恰是小春时，香泛泛，酒醺醺，一曲歌金缕。", "吾今已醉，解作醒时语。", "千里念重亲，望家山、云天尽处。", "深深发愿，只愿早休官，居颜巷，戏莱衣，岁岁长欢聚。"]'),
('song-ci-645','临江仙','张纲','宋','宋词','song-ci','临江仙','[]','绿蚁浮觞香泛泛，黄花共荐芳辰。',70,'宋词/ci.song.6000.json','["绿蚁浮觞香泛泛，黄花共荐芳辰。", "清霜天宇净无尘。", "登高宜有赋，拈笔戏成文。", "可奈园林摇落尽，悲秋意与谁论。", "眼中相识几番新。", "龙山高会处，落帽定何人。"]'),
('song-ci-646','临江仙','张纲','宋','宋词','song-ci','临江仙','[]','追想京都全盛日，蓬弧初记生时。',70,'宋词/ci.song.6000.json','["追想京都全盛日，蓬弧初记生时。", "朝来朱绂照庭闱。", "谁知衰谢老，还有宁馨儿。", "休记蓝田生美玉，举杯听取歌词。", "年方强仕未应迟。", "高风轻借便，一鹗看横飞。"]'),
('song-ci-647','满庭芳','张纲','宋','宋词','song-ci','满庭芳','[]','十月风光，小春时候，宴堂初启朱筵。',118,'宋词/ci.song.6000.json','["十月风光，小春时候，宴堂初启朱筵。", "博山云润，风细袅晴烟。", "坐有文章公子，争吟唱、诗满花笺。", "帘帷里，时闻笑语，今日间生贤。", "郎潜。", "虽未贵，虚名自有，清议推先。", "更那堪、高堂重庆兼全。", "占取人间乐事，何必羡、玉带貂蝉。", "飞觞处，深深更祝，龟鹤永齐年。"]'),
('song-ci-648','满庭芳','张纲','宋','宋词','song-ci','满庭芳','[]','风轧云低，寒催腊近，画堂和气先春。',118,'宋词/ci.song.6000.json','["风轧云低，寒催腊近，画堂和气先春。", "玳筵处启，佳会庆生辰。", "漏转高张宝炬，重帘邃、深炷炉薰。", "欢声里，清歌闲发，一曲绕梁尘。", "慈闱，春不老，山河象服，恩被丝纶。", "占人间荣贵，兰玉诜诜。", "便好金尊尽醉，殷勤劝、须满十分。", "深深愿，斑衣拜舞，千岁奉灵椿。"]'),
('song-ci-649','万年欢','张纲','宋','宋词','song-ci','万年欢','[]','岁晚寒凝，正冥舒四叶，梅吐孤芳。',122,'宋词/ci.song.6000.json','["岁晚寒凝，正冥舒四叶，梅吐孤芳。", "庆诞佳辰，开筵盛集萱堂。", "合坐春回锦绣，卷帘处、花簇笙簧。", "除乐禁、初许闻韶，应时欢宴何妨。", "人言富贵最好，算有谁能兼，福寿康强。", "自是仙姿，天教占取恩光。", "百和重添宝炬，十分劝、频举瑶觞。", "仍教画、家庆新图，要看兰桂成行。"]'),
('song-ci-650','浣溪沙','张纲','宋','宋词','song-ci','浣溪沙','[]','罗绮争春拥画堂。',48,'宋词/ci.song.6000.json','["罗绮争春拥画堂。", "翠帷深处按笙簧。", "宝奁频炷郁沈香。", "海上蟠桃元未老，月中仙桂看馀芳。", "何须龟鹤颂年长。"]'),
('song-ci-651','浣溪沙','张纲','宋','宋词','song-ci','浣溪沙','[]','腊日银罂翠管新。',48,'宋词/ci.song.6000.json','["腊日银罂翠管新。", "潘舆迎腊庆生辰。", "卷帘花簇锦堂春。", "百和宝薰笼瑞雾，一声珠唱驻行云。", "流霞深劝莫辞频。"]'),
('song-ci-652','浣溪沙','张纲','宋','宋词','song-ci','浣溪沙','[]','象服华年两鬓青。',48,'宋词/ci.song.6000.json','["象服华年两鬓青。", "喜逢生日是嘉平。", "何妨开宴雪初晴。", "酒劝十分金凿落，舞催三叠玉娉婷。", "满堂欢笑祝椿龄。"]'),
('song-ci-653','浣溪沙','张纲','宋','宋词','song-ci','浣溪沙','[]','过隙光阴还自催。',48,'宋词/ci.song.6000.json','["过隙光阴还自催。", "生朝又送一年来。", "宴堂深处强追陪。", "眼眩岂堪花里笑，眉攒聊向酒边开。", "与君同醉莫辞杯。"]'),
('song-ci-654','点绛唇','张纲','宋','宋词','song-ci','点绛唇','[]','飞雪初晴，晓来佳气生庭户。',50,'宋词/ci.song.6000.json','["飞雪初晴，晓来佳气生庭户。", "宝薰笼雾。", "帘幕香风度。", "鹤发龟龄，堂上潘舆驻。", "花深处。", "缓歌金缕。", "莫借杯频举。"]'),
('song-ci-655','点绛唇','张纲','宋','宋词','song-ci','点绛唇','[]','罗幕重重，画堂迎腊和风转。',50,'宋词/ci.song.6000.json','["罗幕重重，画堂迎腊和风转。", "玳筵高展。", "知是群仙宴。", "银鸭香浮，红袖翻歌扇。", "金杯劝。", "深深祝愿。", "争把蟠桃献。"]'),
('song-ci-656','江城子','张纲','宋','宋词','song-ci','江城子','[]','宝津楼下柳阴重。',86,'宋词/ci.song.6000.json','["宝津楼下柳阴重。", "画桥东。", "戏鱼龙。", "闻喜当时，开宴盛仪容。", "遥想新年寻故事，扶醉帽，夕阳中。", "可怜衰鬓飒霜丛。", "借酡红。", "遣愁浓。", "梦入长安，惊起送飞鸿。", "直下青冥休避路，九万里，看抟风。"]'),
('song-ci-657','绿头鸭・多丽','张纲','宋','宋词','song-ci','绿头鸭・多丽','[]','敛晴烟。',173,'宋词/ci.song.6000.json','["敛晴烟。", "桂花如水轻寒。", "宴中秋、朋簪来会，满筵绿鬓朱颜。", "罄尊罍、兴吞海量，妙歌吹、声彻云端。", "独念衰残，强陪欢笑，恍然感旧觉悲酸。", "功名志，黄梁晓梦，老去奈何天。", "休追悔，天应教人，赢取身闲。", "想姮娥、情郎如旧，也须知我贪欢。", "奈潘鬓、霜蓬渐满，况沈腰、革带频宽。", "月有重圆，人谁长健，一回相见一回难。", "王夫子，看君风度，何不早弹冠。", "莫学我，年年对月，扶病江干。"]'),
('song-ci-658','绿头鸭・多丽','张纲','宋','宋词','song-ci','绿头鸭・多丽','[]','爱家山。',173,'宋词/ci.song.6000.json','["爱家山。", "坐来心与云闲。", "念平生、功名有志，暮年多病知难。", "眷簪缨、未容引去，奈猿鹤、久已催还。", "松菊关情，莼鲈引兴，昔人高韵照尘寰。", "细追想，山林锺鼎，从古罕兼全。", "归来好，皇恩赐可，拂袖欣然。", "望西清、犹叨法从，梦魂宁隔台躔。", "莳七松、便为小隐，开三径、且乐馀年。", "宾友相过，鸡豚为具，从容聊作饮中仙。", "君试听，阳春佳阕，今日恰新传。", "休辞酒，从教醉舞，踏碎花毡。"]'),
('song-ci-659','感皇恩','张纲','宋','宋词','song-ci','感皇恩','[]','解组盛明时，角巾东路。',81,'宋词/ci.song.6000.json','["解组盛明时，角巾东路。", "家在深村更深处。", "扫开三径，坐看一川烟雨。", "故山休笑我，来何暮。", "苦贪富贵，多忧多虑。", "百岁光阴能几许。", "醉乡日月，莫问人间寒暑。", "兴来随短棹，过南浦。"]'),
('song-ci-660','朝中措','张纲','宋','宋词','song-ci','朝中措','[]','年时生日宴高堂。',57,'宋词/ci.song.6000.json','["年时生日宴高堂。", "欢笑拥炉香。", "今日山前停棹，也须随分飞觞。", "东阳太守，携家远去，方溯桐江。", "把酒祝君长健，相随归老吾乡。"]'),
('song-ci-661','朝中措','张纲','宋','宋词','song-ci','朝中措','[]','前年初对大明宫。',57,'宋词/ci.song.6000.json','["前年初对大明宫。", "寒律转春风。", "几度相关归梦，催成两鬓霜蓬。", "山州岁晚，还逢令节，空记前踪。", "莫遣酒兵相向，愁城生怕频攻。"]'),
('song-ci-662','朝中措','张纲','宋','宋词','song-ci','朝中措','[]','休惊初腊冻全消。',57,'宋词/ci.song.6000.json','["休惊初腊冻全消。", "旬日是春朝。", "梅吐芳心半笑，柳含青眼相撩。", "风光如许，那知太守，老去无聊。", "乘兴方思把盏，归心已逐轻桡。"]'),
('song-ci-663','凤栖梧・蝶恋花','张纲','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','五日小春休屈指。',70,'宋词/ci.song.6000.json','["五日小春休屈指。", "花发西轩，早已传春意。", "应为高堂催燕喜。", "一枝得得来呈瑞。", "绮席初开云幕邃。", "兰蕙腾芳，人在蓬壶里。", "寿酒满斟那惜醉。", "锦囊行拜恩封贵。"]'),
('song-ci-664','凤栖梧・蝶恋花','张纲','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','雨洗轩庭迎晚照。',70,'宋词/ci.song.6000.json','["雨洗轩庭迎晚照。", "黄菊才芳，未觉秋光老。", "怪底烘堂添语笑。", "姮娥此夜来蓬岛。", "献寿新词谁解道。", "满眼儿孙，著语皆争巧。", "潋滟金杯休惜釂。", "追欢不怕霜天晓。"]'),
('song-ci-665','凤栖梧・蝶恋花','张纲','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','风动飞霙迎晓霁。',70,'宋词/ci.song.6000.json','["风动飞霙迎晓霁。", "银海光浮，宴启群仙会。", "骑省流芳谁可继。", "尊前看取连枝贵。", "华发衰翁羞晚岁。", "未报皇恩，尚忝专城寄。", "酒入愁肠应易醉。", "已拚一醉酬君意。"]'),
('song-ci-666','凤栖梧・蝶恋花','张纲','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','老去光阴惊掣电。',70,'宋词/ci.song.6000.json','["老去光阴惊掣电。", "生长元丰，试数今谁健。", "多谢天公怜岁晚。", "清时乞得身闲散。", "忆昔生朝叨睿眷。", "台馈颁恩，内酒当筵劝。", "今日衰残欢意鲜。", "举杯目断尧天远。"]'),
('song-ci-667','凤栖梧・蝶恋花','张纲','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','缓带垂红双侍女。',70,'宋词/ci.song.6000.json','["缓带垂红双侍女。", "彩凤衔来，秀色生庭户。", "转蕙光风香暗度。", "回眸绰约神仙侣。", "寡和清歌声激楚。", "夜饮厌厌，劝我杯频举。", "只恐酒阑催暮雨。", "凭谁约断阳台路。"]'),
('song-ci-668','好事近','张纲','宋','宋词','song-ci','好事近','[]','梅柳约东风，迎腊暗传消息。',53,'宋词/ci.song.6000.json','["梅柳约东风，迎腊暗传消息。", "粉面翠眉偷笑，似欣逢佳客。", "晚来歌管破馀寒，沈烟袅轻碧。", "老去不禁卮酒，奈尊前春色。"]'),
('song-ci-669','菩萨蛮','张纲','宋','宋词','song-ci','菩萨蛮','[]','重帘卷尽楼台日。',52,'宋词/ci.song.6000.json','["重帘卷尽楼台日。", "华灯万点欢声入。", "老病莫凭阑。", "一城星斗寒。", "艳妆翻舞雪。", "目眩红生缬。", "不是故无情。", "羞君双鬓青。"]'),
('song-ci-670','菩萨蛮','张纲','宋','宋词','song-ci','菩萨蛮','[]','南山只与溪桥隔。',52,'宋词/ci.song.6000.json','["南山只与溪桥隔。", "年来厌著寻山屐。", "卧对曲屏风。", "淡烟疏雨中。", "功成投老去。", "拚作林塘主。", "万事不关心。", "酒杯红浪生。"]'),
('song-ci-671','清平乐','张纲','宋','宋词','song-ci','清平乐','[]','红莲照晚。',54,'宋词/ci.song.6000.json','["红莲照晚。", "花底明人眼。", "无限游人谁惜倦。", "只有衰翁心懒。", "笙歌缓引更筹。", "更阑客散添愁。", "香雾半窗幽梦，烟波千里归舟。"]'),
('song-ci-672','人月圆','张纲','宋','宋词','song-ci','人月圆','[]','封人祝望尧云了，归路蔼欢声。',58,'宋词/ci.song.6000.json','["封人祝望尧云了，归路蔼欢声。", "何妨明日，开筵笑语，聊庆初生。", "官闲岁晚身犹健，兰玉更盈庭。", "持杯为寿，从教夜醉，谁怕参横。"]'),
('song-ci-673','西江月','张纲','宋','宋词','song-ci','西江月','[]','易老方惊岁晚，难禁又报生朝。',58,'宋词/ci.song.6000.json','["易老方惊岁晚，难禁又报生朝。", "从他华发转萧萧。", "且共尊前一笑。", "为具随宜饾饤，烘堂不用笙箫。", "只烦欢伯散无憀。", "醉里追回年少。"]'),
('song-ci-674','惜分飞','张纲','宋','宋词','song-ci','惜分飞','[]','年少春心花里转。',58,'宋词/ci.song.6000.json','["年少春心花里转。", "只恐飞花片片。", "沈醉归深院。", "妓衣何用令高卷。", "要看梁州初入遍。", "放出楼中舞燕。", "有眼何曾见。", "看来未足重开宴。"]'),
('song-ci-675','减字木兰花','张纲','宋','宋词','song-ci','减字木兰花','[]','思堂醇酎。',52,'宋词/ci.song.6000.json','["思堂醇酎。", "满酌金杯争献寿。", "记取年时。", "头白成双唱旧词。", "莫言秋晚。", "五日小春黄菊绽。", "折一枝来。", "纶诰金花要并开。"]'),
('song-ci-676','孤雁儿・御街行','李清照','宋','宋词','song-ci','孤雁儿・御街行','[]','藤床纸帐朝眠起。',94,'宋词/ci.song.6000.json','["藤床纸帐朝眠起。", "说不尽、无佳思。", "沈香断续玉炉寒，伴我情怀如水。", "笛里三弄，梅心惊破，多少春情意。", "小风疏雨萧萧地。", "又催下、千行泪。", "吹箫人去玉楼空，肠断与谁同倚。", "一枝折得，人间天上，没个人堪寄。"]'),
('song-ci-677','满庭霜・满庭芳','李清照','宋','宋词','song-ci','满庭霜・满庭芳','[]','小阁藏春，闲窗锁昼，画堂无限深幽。',118,'宋词/ci.song.6000.json','["小阁藏春，闲窗锁昼，画堂无限深幽。", "篆香烧尽，日影下帘钩。", "手种江梅更好，又何必、临水登楼。", "无人到，寂寥浑似，何逊在扬州。", "从来，知韵胜，难堪雨籍，不耐风柔。", "更谁家横笛，吹动浓愁。", "莫恨香消雪减，须信道、扫迹情留。", "难言处，良宵淡月，疏影尚风流。"]'),
('song-ci-678','玉楼春','李清照','宋','宋词','song-ci','玉楼春','[]','红酥肯放琼苞碎。',64,'宋词/ci.song.6000.json','["红酥肯放琼苞碎。", "探著南枝开遍未。", "不知酝藉几多香，但见包藏无限意。", "道人憔悴春窗底。", "闷损阑干愁不倚。", "要来小酌便来休，未必明朝风不起。"]'),
('song-ci-679','渔家傲','李清照','宋','宋词','song-ci','渔家傲','[]','雪里已知春信至。',72,'宋词/ci.song.6000.json','["雪里已知春信至。", "寒梅点缀琼枝腻。", "香脸半开娇旖旎。", "当庭际。", "玉人浴出新妆洗。", "造化可能偏有意。", "故教明月玲珑地。", "共赏金尊沈绿蚁。", "莫辞醉。", "此花不与群花比。"]'),
('song-ci-680','清平乐','李清照','宋','宋词','song-ci','清平乐','[]','年年雪里。',54,'宋词/ci.song.6000.json','["年年雪里。", "常插梅花醉。", "挼尽梅花无好意。", "赢得满衣清泪。", "今年海角天涯。", "萧萧两鬓生华。", "看取晚来风势，故应难看梅花。"]'),
('song-ci-681','南歌子','李清照','宋','宋词','song-ci','南歌子','[]','天上星河转，人间帘幕垂。',62,'宋词/ci.song.6000.json','["天上星河转，人间帘幕垂。", "凉生枕簟泪痕滋。", "起解罗衣、聊问夜何其。", "翠贴莲蓬小，金销藕叶稀。", "旧时天气旧时衣。", "只有情怀、不似旧家时。"]'),
('song-ci-682','转调满庭芳・满庭芳','李清照','宋','宋词','song-ci','转调满庭芳・满庭芳','[]','芳草池塘，绿阴庭院，晚晴寒透窗纱。',118,'宋词/ci.song.6000.json','["芳草池塘，绿阴庭院，晚晴寒透窗纱。", "□□金锁，管是客来唦。", "寂寞尊前席上，惟□、海角天涯。", "能留否，酴醿落尽，犹赖有□□。", "当年，曾胜赏，生香薰袖，活火分茶。", "□□□龙骄马，流水轻车。", "不怕风狂雨骤，恰才称、煮酒残花。", "如今也，不成怀抱，得似旧时那。"]'),
('song-ci-683','渔家傲','李清照','宋','宋词','song-ci','渔家傲','[]','天接云涛连晓雾。',72,'宋词/ci.song.6000.json','["天接云涛连晓雾。", "星河欲转千帆舞。", "彷佛梦魂归帝所。", "闻天语。", "殷勤问我归何处。", "我报路长嗟日暮。", "学诗谩有惊人句。", "九万里风鹏正举。", "风休住。", "蓬舟吹取三山去。"]'),
('song-ci-684','如梦令','李清照','宋','宋词','song-ci','如梦令','[]','常记溪亭日暮。',40,'宋词/ci.song.6000.json','["常记溪亭日暮。", "沈醉不知归路。", "兴尽晚回舟，误入藕花深处。", "争渡。", "争渡。", "惊起一滩鸥鹭。"]'),
('song-ci-685','如梦令','李清照','宋','宋词','song-ci','如梦令','[]','昨夜雨疏风骤。',40,'宋词/ci.song.6000.json','["昨夜雨疏风骤。", "浓睡不消残酒。", "试问卷帘人，却道海棠依旧。", "知否。", "知否。", "应是绿肥红瘦。"]'),
('song-ci-686','多丽','李清照','宋','宋词','song-ci','多丽','[]','小楼寒，夜长帘幕低垂。',173,'宋词/ci.song.6000.json','["小楼寒，夜长帘幕低垂。", "恨萧萧、无情风雨，夜来揉损琼肌。", "也不似、贵妃醉脸，也不似、孙寿愁眉。", "韩令偷香，徐娘傅粉，莫将比拟未新奇。", "细看取、屈平陶令，风韵正相宜。", "微风起，清芬酝籍，不减酴醿。", "渐秋阑、雪清玉瘦，向人无限依依。", "似愁凝、汉皋解佩，似泪洒、纨扇题诗。", "朗月清风，浓烟暗雨，天教憔悴度芳姿。", "纵爱惜、不知从此，留得几多时。", "人情好，何须更忆，泽畔东篱。"]'),
('song-ci-687','菩萨蛮','李清照','宋','宋词','song-ci','菩萨蛮','[]','风柔日薄春犹早。',52,'宋词/ci.song.6000.json','["风柔日薄春犹早。", "夹衫乍著心情好。", "睡起觉微寒。", "梅花鬓上残。", "故乡何处是。", "忘了除非醉。", "沈水卧时烧。", "香消酒未消。"]'),
('song-ci-688','菩萨蛮','李清照','宋','宋词','song-ci','菩萨蛮','[]','归鸿声断残云碧。',52,'宋词/ci.song.6000.json','["归鸿声断残云碧。", "背窗雪落炉烟直。", "烛底凤钗明。", "钗头人胜轻。", "角声催晓漏。", "曙色回牛斗。", "春意看花难。", "西风留旧寒。"]'),
('song-ci-689','浣溪沙','李清照','宋','宋词','song-ci','浣溪沙','[]','莫许杯深琥珀浓。',48,'宋词/ci.song.6000.json','["莫许杯深琥珀浓。", "未成沈醉意先融。", "□□已应晚来风。", "瑞脑香消魂梦断，辟寒金小髻鬟松。", "醒时空对烛花红。"]'),
('song-ci-690','浣溪沙','李清照','宋','宋词','song-ci','浣溪沙','[]','小院闲窗春色深。',48,'宋词/ci.song.6000.json','["小院闲窗春色深。", "重帘未卷影沈沈。", "倚楼无语理瑶琴。", "远岫出山催薄暮，细风吹雨弄轻阴。", "梨花欲谢恐难禁。"]'),
('song-ci-691','浣溪沙','李清照','宋','宋词','song-ci','浣溪沙','[]','淡荡春光寒食天。',48,'宋词/ci.song.6000.json','["淡荡春光寒食天。", "玉炉沈水袅残烟。", "梦回山枕隐花钿。", "海燕未来人斗草，江海已过柳生绵。", "黄昏疏雨湿秋千。"]'),
('song-ci-692','凤凰台上忆吹箫','李清照','宋','宋词','song-ci','凤凰台上忆吹箫','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','香冷金猊，被翻红浪，起来人未梳头。',118,'宋词/ci.song.6000.json','["香冷金猊，被翻红浪，起来人未梳头。", "任宝奁闲掩，日上帘钩。", "生怕闲愁暗恨，多少事、欲说还休。", "今年瘦，非干病酒，不是悲秋。", "明朝，这回去也，千万遍阳关，也即难留。", "念武陵春晚，云锁重楼。", "记取楼前绿水，应念我、终日凝眸。", "凝眸处，从今更数，几段新愁。"]'),
('song-ci-693','一剪梅・一翦梅','李清照','宋','宋词','song-ci','一剪梅・一翦梅','[]','红藕香残玉簟秋。',72,'宋词/ci.song.6000.json','["红藕香残玉簟秋。", "轻解罗裳，独上兰舟。", "雪中谁寄锦书来，雁字回时，月满西楼。", "花自飘零水自流。", "一种相思，两处闲愁。", "此情无计可消除，才下眉头，却上心头。"]'),
('song-ci-694','蝶恋花','李清照','宋','宋词','song-ci','蝶恋花','[]','泪湿罗衣脂粉满。',70,'宋词/ci.song.6000.json','["泪湿罗衣脂粉满。", "四叠阳关，唱到千千遍。", "人道山长山又断。", "萧萧微雨闻孤馆。", "惜别伤离方寸乱。", "忘了临行，酒盏深和浅。", "好把音书凭过雁。", "东来不似蓬莱远。"]'),
('song-ci-695','蝶恋花','李清照','宋','宋词','song-ci','蝶恋花','[]','暖日晴风初破冻。',70,'宋词/ci.song.6000.json','["暖日晴风初破冻。", "柳眼眉腮，已觉春心动。", "酒意诗情谁与共。", "泪融残粉花钿重。", "乍试夹衫金缕缝。", "山枕斜敧，枕损钗头凤。", "独抱浓愁无好梦。", "夜阑犹剪灯花弄。"]'),
('song-ci-696','鹧鸪天','李清照','宋','宋词','song-ci','鹧鸪天','[]','寒日萧萧上锁窗。',64,'宋词/ci.song.6000.json','["寒日萧萧上锁窗。", "梧桐应恨夜来霜。", "酒阑更喜团茶苦，梦断偏宜瑞脑香。", "秋已尽，日犹长。", "仲宣怀远更凄凉。", "不如随分尊前醉，莫负东篱菊蕊黄。"]'),
('song-ci-697','小重山','李清照','宋','宋词','song-ci','小重山','[]','春到长门春草青。',70,'宋词/ci.song.6000.json','["春到长门春草青。", "江梅些子破，未开匀。", "碧云笼碾玉成尘。", "留晓梦，惊破一瓯春。", "花影压重门。", "疏帘铺淡月，好黄昏。", "二年三度负东君。", "归来也，著意过今春。"]'),
('song-ci-698','怨王孙・忆王孙','李清照','宋','宋词','song-ci','怨王孙・忆王孙','[]','湖上风来波浩渺。',66,'宋词/ci.song.6000.json','["湖上风来波浩渺。", "秋已暮、红稀香少。", "水光山色与人亲，说不尽、无穷好。", "莲子已成荷叶老。", "青露洗、苹花汀草。", "眠沙鸥鹭不回头，似也恨、人归早。"]'),
('song-ci-699','临江仙','李清照','宋','宋词','song-ci','临江仙','[]','庭院深深深几许，云窗雾阁常扃。',70,'宋词/ci.song.6000.json','["庭院深深深几许，云窗雾阁常扃。", "柳梢梅萼渐分明。", "春归秣陵树，人客远安城。", "感月吟风多少事，如今老去无成。", "谁怜憔悴更凋零。", "试灯无意思，踏雪没心情。"]'),
('song-ci-700','醉花阴','李清照','宋','宋词','song-ci','醉花阴','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','薄雾浓云愁永昼。',62,'宋词/ci.song.6000.json','["薄雾浓云愁永昼。", "瑞脑消金兽。", "佳节又重阳，玉枕纱厨，半夜凉初透。", "东篱把洒黄昏后，有暗香盈袖。", "莫道不消魂，帘卷西风，人似黄花瘦。"]'),
('song-ci-701','好事近','李清照','宋','宋词','song-ci','好事近','[]','风定落花深，帘外拥红堆雪。',54,'宋词/ci.song.6000.json','["风定落花深，帘外拥红堆雪。", "长记海棠开后，正是伤春时节。", "酒阑歌罢玉尊空，青缸暗明灭。", "魂梦不堪幽怨，更一声啼鴂。"]'),
('song-ci-702','诉衷情','李清照','宋','宋词','song-ci','诉衷情','[]','夜来沈醉卸妆迟。',54,'宋词/ci.song.6000.json','["夜来沈醉卸妆迟。", "梅萼插残枝。", "酒醒熏破春睡，梦远不成归。", "人悄悄，月依依。", "翠帘垂。", "更挼残芯，更拈馀香，更得些时。"]'),
('song-ci-703','行香子','李清照','宋','宋词','song-ci','行香子','[]','草际鸣蛩。',84,'宋词/ci.song.6000.json','["草际鸣蛩。", "惊落梧桐。", "正人间、天上愁浓。", "云阶月地，关锁千重。", "纵浮槎来，浮槎去，不相逢。", "星桥鹊驾，经年才见，想离情、别恨难穷。", "牵牛织女，莫是离中。", "甚霎儿晴，霎儿雨，霎儿风。"]'),
('song-ci-704','失调名','李清照','宋','宋词','song-ci','失调名','[]','犹将歌扇向人遮。',56,'宋词/ci.song.6000.json','["犹将歌扇向人遮。", "水晶山枕象牙床。", "彩云易散月长亏。", "几多深恨断人肠。", "罗衣消尽恁时香。", "闲愁也似月明多。", "直送凄凉到画屏。"]'),
('song-ci-705','鹧鸪天','李清照','宋','宋词','song-ci','鹧鸪天','[]','暗淡轻黄体性柔。',64,'宋词/ci.song.6000.json','["暗淡轻黄体性柔。", "情疏迹远只香留。", "何须浅碧深红色，自是花中第一流。", "梅定妒，菊应羞。", "画阑开处冠中秋。", "骚人可煞无情思，何事当年不见收。"]'),
('song-ci-706','添字丑奴儿・采桑子','李清照','宋','宋词','song-ci','添字丑奴儿・采桑子','[]','窗前谁种芭蕉树，阴满中庭。',58,'宋词/ci.song.6000.json','["窗前谁种芭蕉树，阴满中庭。", "阴满中庭。", "叶叶心心，舒卷有馀情。", "伤心枕上三更雨，点滴霖霪。", "点滴霖霪。", "愁损北人，不惯起来听。"]'),
('song-ci-707','忆秦娥','李清照','宋','宋词','song-ci','忆秦娥','[]','临高阁。',56,'宋词/ci.song.6000.json','["临高阁。", "乱山平野烟光薄。", "烟光薄。", "栖鸦归后，暮天闻角。", "断香残酒情怀恶。", "西风催衬梧桐落。", "梧桐落。", "又还秋色，又还寂寞。"]'),
('song-ci-708','失调名','李清照','宋','宋词','song-ci','失调名','[]','条脱闲揎系五丝。',8,'宋词/ci.song.6000.json','["条脱闲揎系五丝。"]'),
('song-ci-709','失调名','李清照','宋','宋词','song-ci','失调名','[]','瑞脑烟残，沈香火冷。',10,'宋词/ci.song.6000.json','["瑞脑烟残，沈香火冷。"]'),
('song-ci-710','念奴娇','李清照','宋','宋词','song-ci','念奴娇','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','萧条庭院，有斜风细雨，重门须闭。',120,'宋词/ci.song.6000.json','["萧条庭院，有斜风细雨，重门须闭。", "宠柳娇花寒食近，种种恼人天气。", "险韵诗成，扶头酒醒，别是闲滋味。", "征鸿过尽，万千心事难寄。", "楼上几日春寒，帘垂四面，玉阑干慵倚。", "被冷香消新梦觉，不许愁人不起。", "清露晨流，新桐初引，多少游春意。", "日高烟敛，更看今日晴未。"]'),
('song-ci-711','永遇乐','李清照','宋','宋词','song-ci','永遇乐','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','落日熔金，暮云合璧，人在何处。',128,'宋词/ci.song.6000.json','["落日熔金，暮云合璧，人在何处。", "染柳烟浓，吹梅笛怨，春意知几许。", "元宵佳节，融和天气，次第岂无风雨。", "来相召、香车宝马，谢他酒朋诗侣。", "中州盛日，闺门多暇，记得偏重三五。", "铺翠冠儿，拈金雪柳，簇带争济楚。", "如今憔悴，风鬟霜鬓，怕见夜间出去。", "不如向、帘儿底下，听人笑语。"]'),
('song-ci-712','武陵春','李清照','宋','宋词','song-ci','武陵春','[]','风住尘香花已尽，日晚倦梳头。',58,'宋词/ci.song.6000.json','["风住尘香花已尽，日晚倦梳头。", "物是人非事事休。", "欲语泪先流。", "闻说双溪春尚好，也拟泛轻舟。", "只恐双溪舴艋舟。", "载不动、许多愁。"]'),
('song-ci-713','怨王孙・忆王孙','李清照','宋','宋词','song-ci','怨王孙・忆王孙','[]','帝里春晚。',65,'宋词/ci.song.6000.json','["帝里春晚。", "重门深院。", "草绿阶前，暮天雁断。", "楼上远信谁传。", "恨绵绵。", "多情自是多沾惹。", "难拚舍。", "又是寒食也。", "秋千巷陌，人静皎月初斜。", "浸梨花。"]'),
('song-ci-714','长寿乐','李清照','宋','宋词','song-ci','长寿乐','[]','微寒应候。',137,'宋词/ci.song.6000.json','["微寒应候。", "望日边六叶，阶蓂初秀。", "爱景欲挂扶桑，漏残银箭，杓回摇斗。", "庆高闳此际，掌上一颗明珠剖。", "有令容淑质，归逢佳偶。", "到如今，昼锦满堂贵胄。", "荣耀，文步紫禁，一一金章绿绶。", "更值棠棣连阴，虎符熊轼，夹河分守。", "况青云咫尺，朝暮重入承明后。", "看彩衣争献，兰羞玉酎。", "祝千龄，借指松椿比寿。"]'),
('song-ci-715','蝶恋花','李清照','宋','宋词','song-ci','蝶恋花','[]','永夜恹恹欢意少。',70,'宋词/ci.song.6000.json','["永夜恹恹欢意少。", "空梦长安，认取长安道。", "为报今年春色好。", "花光月影宜相照。", "随意杯盘虽草草。", "酒美梅酸，恰称人怀抱。", "醉莫插花花莫笑。", "可怜春似人将老。"]'),
('song-ci-716','声声慢','李清照','宋','宋词','song-ci','声声慢','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','寻寻觅觅，冷冷清清，凄凄惨惨戚戚。',119,'宋词/ci.song.6000.json','["寻寻觅觅，冷冷清清，凄凄惨惨戚戚。", "乍暖还寒时候，最难将息。", "三杯两盏淡酒，怎敌他、晚来风急。", "雁过也，正伤心，却是旧时相识。", "满地黄花堆积。", "憔悴损，如今有谁忺摘。", "守著窗儿，独自怎生得黑。", "梧桐更兼细雨，到黄昏、点点滴滴。", "这次第，怎一个、愁字了得。"]'),
('song-ci-717','点绛唇','李清照','宋','宋词','song-ci','点绛唇','[]','寂寞深闺，柔肠一寸愁千缕。',50,'宋词/ci.song.6000.json','["寂寞深闺，柔肠一寸愁千缕。", "惜春春去。", "几点催花雨。", "倚遍阑干，只是无情绪。", "人何处。", "连天衰草，望断归来路。"]'),
('song-ci-718','减字木兰花','李清照','宋','宋词','song-ci','减字木兰花','[]','卖花担上。',52,'宋词/ci.song.6000.json','["卖花担上。", "买得一枝春欲放。", "泪染轻匀。", "犹带彤霞晓露痕。", "怕郎猜道。", "奴面不如花面好。", "云鬓斜簪。", "徒要教郎比并看。"]'),
('song-ci-719','失调名','李清照','宋','宋词','song-ci','失调名','[]','教我甚情怀。',6,'宋词/ci.song.6000.json','["教我甚情怀。"]'),
('song-ci-720','摊破浣溪沙・山花子','李清照','宋','宋词','song-ci','摊破浣溪沙・山花子','[]','揉破黄金万点轻。',56,'宋词/ci.song.6000.json','["揉破黄金万点轻。", "剪成碧玉叶层层。", "风度精神如彦辅，大鲜明。", "梅蕊重重何俗甚，丁香千结苦粗生。", "熏透愁人千里梦，却无情。"]'),
('song-ci-721','摊破浣溪沙・山花子','李清照','宋','宋词','song-ci','摊破浣溪沙・山花子','[]','病起萧萧两鬓华。',56,'宋词/ci.song.6000.json','["病起萧萧两鬓华。", "卧看残月上窗纱。", "豆蔻连梢煎熟水，莫分茶。", "枕上诗书闲处好，门前风景雨来佳。", "终日向人多酝藉，木犀花。"]');
